```ts
import { Effect, Console } from "effect";

interface DbConn { readonly id: number; readonly close: () => void }

const connect = (): Effect.Effect<DbConn> =>
  Effect.sync(() => ({ id: Date.now(), close: () => console.log("disconnected") }));

const disconnect = (c: DbConn): Effect.Effect<void> =>
  Effect.sync(() => c.close());

// The pair: acquire + release.
const conn = Effect.acquireRelease(connect(), (c) => disconnect(c));

const query = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* conn;
    yield* Console.log(`SELECT 1 on conn ${c.id}`);
    return 1 as const;
  })
);

Effect.runPromise(query);
```

Without `Effect.scoped`, the effect still requires `Scope` in its `R` channel and cannot be executed directly. `scoped` closes the scope and runs the release regardless of outcome.

```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

type CreateSubscription = { planId: string; startDate: string; couponCode: string; seats: number };

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const planId = (s: string): E.Either<Errs, string> =>
  /^plan_[a-z0-9]+$/.test(s) ? E.right(s) : E.left([fe("planId", "must match plan_*")]);
const startDate = (s: string): E.Either<Errs, string> =>
  !Number.isNaN(Date.parse(s)) ? E.right(s) : E.left([fe("startDate", "bad date")]);
const couponCode = (s: string): E.Either<Errs, string> =>
  s === "" || /^[A-Z0-9]{4,20}$/.test(s) ? E.right(s) : E.left([fe("couponCode", "bad coupon")]);
const seats = (n: number): E.Either<Errs, number> =>
  n >= 1 && n <= 500 ? E.right(n) : E.left([fe("seats", "1..500")]);

export const validateSubscription = (
  s: CreateSubscription
): E.Either<Errs, CreateSubscription> =>
  sequenceS(V)({
    planId: planId(s.planId),
    startDate: startDate(s.startDate),
    couponCode: couponCode(s.couponCode),
    seats: seats(s.seats),
  });
```

Under the validation applicative, `sequenceS` evaluates every branch; the four field-level validators contribute their failures to a shared `ReadonlyNonEmptyArray<FieldError>`.

A `Layer<ROut, E, RIn>` describes how to produce `ROut` given `RIn`. Leaves use `Layer.succeed` (pure) or `Layer.effect` (effectful construction). You compose with `Layer.merge` (union the outputs) and `Layer.provide(inner, deps)` (satisfy `inner`'s `RIn` from `deps`'s `ROut`). The final `Effect.provide(program, AppLayer)` closes the `R` channel entirely.

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly dsn: string }
const Config = Context.GenericTag<Config>("app/Config");

interface Db { readonly ping: () => Effect.Effect<boolean> }
const Db = Context.GenericTag<Db>("app/Db");

interface Cache { readonly size: () => Effect.Effect<number> }
const Cache = Context.GenericTag<Cache>("app/Cache");

const ConfigLive = Layer.succeed(Config, { dsn: "postgres://localhost/app" });

const DbLive = Layer.effect(
  Db,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { ping: () => Effect.succeed(cfg.dsn.length > 0) };
  })
);

const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    yield* Config; // reserved for future use
    return { size: () => Effect.succeed(0) };
  })
);

// Db and Cache both need Config. Merge the two dependents, then provide Config once.
const AppLayer = Layer.provide(Layer.merge(DbLive, CacheLive), ConfigLive);

const program = Effect.gen(function* () {
  const db = yield* Db;
  const c = yield* Cache;
  const ok = yield* db.ping();
  const n = yield* c.size();
  return { ok, n };
});

export const runnable = Effect.provide(program, AppLayer);
```

```ts
import { pipe } from "effect";

const parseAll = (xs: ReadonlyArray<string>): ReadonlyArray<number> => xs.map(Number);
const keepFinite = (xs: ReadonlyArray<number>): ReadonlyArray<number> => xs.filter(Number.isFinite);
const sum = (xs: ReadonlyArray<number>): number => xs.reduce((a, b) => a + b, 0);

// Before (method chain — fine, but each step has to be a method on the carrier):
//   const out = xs.map(parse).filter(isFinite).reduce((a, b) => a + b, 0);
// After — pipe with named, testable free functions:
export const sumParsed = (xs: ReadonlyArray<string>): number =>
  pipe(xs, parseAll, keepFinite, sum);
```

The three stages are individually trivial to unit-test; the pipeline composes them without any class-bound method constraints.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Bucket { remaining: number; resetAt: number }

type BadRemaining = { _tag: "BadRemaining"; raw: string };
type BadReset = { _tag: "BadReset"; raw: string };
type ResetInPast = { _tag: "ResetInPast"; resetAt: number };

const parseIntNN = (raw: string): E.Either<BadRemaining, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0 ? E.right(n) : E.left({ _tag: "BadRemaining", raw });
};

const parseMs = (raw: string): E.Either<BadReset, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadReset", raw });
};

const future = (now: number) => (resetAt: number): E.Either<ResetInPast, number> =>
  resetAt > now ? E.right(resetAt) : E.left({ _tag: "ResetInPast", resetAt });

export const parseBucket = (remainingRaw: string, resetRaw: string, now: number): E.Either<string, Bucket> =>
  pipe(
    parseIntNN(remainingRaw),
    E.chainW((remaining) =>
      pipe(
        parseMs(resetRaw),
        E.chainW(future(now)),
        E.map((resetAt) => ({ remaining, resetAt })),
      ),
    ),
    E.mapLeft((e) => e._tag),
    E.match(
      (tag) => E.left<string, Bucket>(tag),
      (b) => E.right<string, Bucket>(b),
    ),
  );
```

The widened left `BadRemaining | BadReset | ResetInPast` is visible at the `E.mapLeft` boundary — where we project to a discriminator and rewrap for callers.

