`truncate` is curried so the final stage is a one-arg function — a common trick to keep every step in the pipeline shaped `A -> B`.

```ts
import { Effect, Fiber, Data } from "effect";

class TaskFailed extends Data.TaggedError("TaskFailed")<{ readonly task: string }> {}

declare const task1: Effect.Effect<number, TaskFailed>;
declare const task2: Effect.Effect<string, TaskFailed>;

export const both: Effect.Effect<readonly [number, string], TaskFailed> =
  Effect.gen(function* () {
    const f1 = yield* Effect.fork(task1);
    const f2 = yield* Effect.fork(task2);
    const a = yield* Fiber.join(f1);
    const b = yield* Fiber.join(f2);
    return [a, b] as const;
  });
```

Unlike `Promise.all`, if one fiber fails the parent's error propagates and structured concurrency interrupts the other forked fiber automatically — no orphaned work. The error channel is the typed union, not a widened `Error`.

```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface DomainEvent { id: string; ts: number; type: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const checkId = (id: string): E.Either<Errs, string> =>
  /^evt_[0-9a-f]{8,}$/.test(id) ? E.right(id) : E.left([fe("id", "bad event id")]);
const checkTs = (ts: number): E.Either<Errs, number> =>
  Number.isFinite(ts) && ts > 0 ? E.right(ts) : E.left([fe("ts", "must be positive finite")]);
const checkType = (t: string): E.Either<Errs, string> =>
  t.length > 0 ? E.right(t) : E.left([fe("type", "required")]);

export const validateEvent = (ev: DomainEvent): E.Either<Errs, DomainEvent> =>
  pipe(
    sequenceT(V)(checkId(ev.id), checkTs(ev.ts), checkType(ev.type)),
    E.map(([id, ts, type]) => ({ id, ts, type }))
  );
```

The `E.chain` tower stops on the first `Left`; swapping to `sequenceT(V)(...)` over the validation applicative makes all three checks contribute to a single `ReadonlyNonEmptyArray<FieldError>`.

```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface ProfilePatch { name: string; email: string; phone: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const name = (s: string): E.Either<Errs, string> =>
  s.trim().length >= 1 ? E.right(s) : E.left([fe("name", "required")]);
const email = (s: string): E.Either<Errs, string> =>
  /^[^@\s]+@[^@\s]+$/.test(s) ? E.right(s) : E.left([fe("email", "bad format")]);
const phone = (s: string): E.Either<Errs, string> =>
  /^\+?[0-9 ]{7,20}$/.test(s) ? E.right(s) : E.left([fe("phone", "bad phone")]);

export const validateProfilePatch = (
  p: ProfilePatch
): E.Either<Errs, ProfilePatch> =>
  sequenceS(V)({ name: name(p.name), email: email(p.email), phone: phone(p.phone) });
```

`sequenceS` keeps the field names in the success shape while the validation applicative funnels any failing field into the shared `ReadonlyNonEmptyArray<FieldError>` channel.

```ts
import { Effect } from "effect";

interface ImageBlob { readonly bytes: Uint8Array }

declare const transform: (path: string) => Effect.Effect<ImageBlob, Error>;

const paths: ReadonlyArray<string> = ["a.png", "b.png", "c.png", "d.png"];
const jobs = paths.map(transform);

// Sequential: default `Effect.all([...])` runs one-at-a-time.
export const serial: Effect.Effect<ReadonlyArray<ImageBlob>, Error> =
  Effect.all(jobs).pipe(Effect.map((xs) => xs));

// Bounded parallel: `{ concurrency: 3 }` caps in-flight work at 3 fibres.
export const poolOf3: Effect.Effect<ReadonlyArray<ImageBlob>, Error> =
  Effect.all(jobs, { concurrency: 3 }).pipe(Effect.map((xs) => xs));
```

The default behaviour of `Effect.all` is sequential; a numeric `concurrency` option converts it into a bounded worker pool that still preserves ordering of the returned array. The trailing `.pipe(Effect.map(...))` is a no-op here — included to show where downstream transforms naturally slot in.

```typescript
import { Effect, Data } from "effect";

class FileMissing extends Data.TaggedError("FileMissing")<{ readonly path: string }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

interface Config { readonly apiUrl: string }

const read = (path: string): Effect.Effect<string, FileMissing> =>
  path.endsWith(".json")
    ? Effect.succeed('{"apiUrl":"x"}')
    : Effect.fail(new FileMissing({ path }));

const parse = (raw: string): Effect.Effect<Config, ParseError> =>
  Effect.try({
    try: () => JSON.parse(raw) as Config,
    catch: () => new ParseError({ raw }),
  });

export const load = (path: string): Effect.Effect<Config, ParseError> =>
  Effect.gen(function* () {
    const raw = yield* read(path);
    return yield* parse(raw);
  }).pipe(
    Effect.catchTag("FileMissing", () => Effect.succeed({ apiUrl: "default" }))
  );
```

`FileMissing` is swallowed into a default value; `ParseError` stays in the channel because the caller probably wants to see malformed configs.

```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Newsletter { email: string; firstName: string; zip: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const email = (s: string): E.Either<Errs, string> =>
  /.+@.+\..+/.test(s) ? E.right(s) : E.left([fe("email", "invalid")]);
const firstName = (s: string): E.Either<Errs, string> =>
  s.length > 0 ? E.right(s) : E.left([fe("firstName", "required")]);
const zip = (s: string): E.Either<Errs, string> =>
  /^\d{5}$/.test(s) ? E.right(s) : E.left([fe("zip", "5 digits")]);

