`sequenceS` over the validation applicative is the idiomatic fp-ts answer: every field contributes its own Left when it fails, and they're merged via the `ReadonlyNonEmptyArray` semigroup.

```ts
import { pipe } from "effect";

const STOP = new Set(["the", "a", "an", "of", "to", "and", "or"]);

const lower = (s: string): string => s.toLowerCase();
const stripPunct = (s: string): string => s.replace(/[^a-z0-9\s]/g, " ");
const splitWs = (s: string): ReadonlyArray<string> => s.split(/\s+/).filter((t) => t.length > 0);
const dropStop = (xs: ReadonlyArray<string>): ReadonlyArray<string> => xs.filter((t) => !STOP.has(t));
const capN =
  (n: number) =>
  <T>(xs: ReadonlyArray<T>): ReadonlyArray<T> =>
    xs.slice(0, n);

export const tokenise = (query: string): ReadonlyArray<string> =>
  pipe(query, lower, stripPunct, splitWs, dropStop, capN(10));
```

Six stages. A nested form — `capN(10)(dropStop(splitWs(stripPunct(lower(query)))))` — works, but the intent "tokenise this query" drowns in punctuation.

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

Every `yield* eff` where `eff: Effect<A, E, R>` contributes its `E` to the outer effect's error channel as a union. As long as you never catch, the outer type accumulates all failure modes, and the compiler forces exhaustive handling when you do catch.

```ts
import { Effect, Data } from "effect";

interface Event { readonly type: string; readonly payload: string }

class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}
class ValidationError extends Data.TaggedError("ValidationError")<{ readonly field: string }> {}

const parseJson = (raw: string): Effect.Effect<unknown, ParseError> =>
  Effect.try({ try: () => JSON.parse(raw) as unknown, catch: () => new ParseError({ raw }) });

const validate = (u: unknown): Effect.Effect<Event, ValidationError> => {
  if (typeof u === "object" && u !== null && "type" in u && "payload" in u) {
    const o = u as { type: unknown; payload: unknown };
    if (typeof o.type === "string" && typeof o.payload === "string") {
      return Effect.succeed({ type: o.type, payload: o.payload });
    }
  }
  return Effect.fail(new ValidationError({ field: "root" }));
};

export const parseEvent = (raw: string): Effect.Effect<Event, ParseError | ValidationError> =>
  Effect.gen(function* () {
    const parsed = yield* parseJson(raw);
    const event = yield* validate(parsed);
    return event;
  });
```

```ts
import { Effect, Data } from "effect";

class ReadError extends Data.TaggedError("ReadError")<{}> {}
class PublishError extends Data.TaggedError("PublishError")<{ readonly id: string }> {}
class MarkError extends Data.TaggedError("MarkError")<{ readonly id: string }> {}

interface OutboxRow { readonly id: string; readonly topic: string; readonly payload: unknown }

declare const readPending: () => Effect.Effect<ReadonlyArray<OutboxRow>, ReadError>;
declare const publish: (r: OutboxRow) => Effect.Effect<void, PublishError>;
declare const markSent: (id: string) => Effect.Effect<void, MarkError>;

export const drainOutbox: Effect.Effect<number, ReadError | PublishError | MarkError> =
  Effect.gen(function* () {
    const rows = yield* readPending();
    let sent = 0;
    for (const row of rows) {
      yield* publish(row);
      yield* markSent(row.id);
      sent += 1;
    }
    return sent;
  });
```

If `publish` succeeds but `markSent` fails, the overall effect fails — the next drain retries the row, which is why publishers must be idempotent.

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly bucket: string }
const Config = Context.GenericTag<Config>("aws/Config");

interface S3 { readonly put: (k: string, v: string) => Effect.Effect<void> }
const S3 = Context.GenericTag<S3>("aws/S3");

const ConfigLive = Layer.succeed(Config, { bucket: "prod-bucket" });

// S3 depends on Config in prod
const S3Live = Layer.effect(
  S3,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return S3.of({ put: (k, v) => Effect.sync(() => console.log(`${cfg.bucket}/${k}: ${v}`)) });
  })
);

// Test double that needs no config
const S3InMemory = Layer.succeed(S3, {
  put: () => Effect.void
});

const LiveLayer = Layer.merge(ConfigLive, Layer.provide(S3Live, ConfigLive));
const TestLayer = S3InMemory;

const program = Effect.gen(function* () {
  const s3 = yield* S3;
  yield* s3.put("k", "v");
});

export const runLive = Effect.provide(program, LiveLayer);
export const runTest = Effect.provide(program, TestLayer);
```

Since both layers produce the same `S3` tag, switching them at the `Effect.provide` boundary is how you inject an alternate implementation.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

const parseF = (s: string): E.Either<string, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left(`not a number: ${s}`);
};
const toCelsius = (f: number): number => ((f - 32) * 5) / 9;
const round1 = (n: number): number => Math.round(n * 10) / 10;
const format = (c: number): string => `${c.toFixed(1)} °C`;

export const fahrenheitToCelsius = (input: string): E.Either<string, string> =>
  pipe(
    parseF(input),
    E.map(toCelsius),
    E.map(round1),
    E.map(format),
  );
```

The pipeline reads as four verbs. Every stage stays inside the `Either` monad, so a parse failure at step one cleanly skips all downstream work and falls out as a typed `Left`.

```ts
import { Effect, Clock } from "effect";

interface Row { readonly [k: string]: unknown }
declare const runSql: (sql: string) => Effect.Effect<ReadonlyArray<Row>>;
declare const recordLatency: (ms: number) => Effect.Effect<void>;

export const queryDb = (sql: string): Effect.Effect<ReadonlyArray<Row>> =>
  Effect.gen(function* () {
    const start = yield* Clock.currentTimeMillis;
    return yield* runSql(sql).pipe(
      Effect.tap(() =>
        Effect.gen(function* () {
          const end = yield* Clock.currentTimeMillis;
          yield* recordLatency(end - start);
        }),
      ),
    );
  });
```

The `tap` reads the clock again and emits the delta — the SQL result passes through untouched.

Each `Effect.catchTag("Name", handler)` returns a new effect where only the `Name` branch has been subtracted from the error union; stacking three of them peels errors off one at a time until the channel narrows to whatever is left (often `never`).

```ts
import { Effect, Data } from "effect";

class A extends Data.TaggedError("A")<{}> {}
class B extends Data.TaggedError("B")<{}> {}
class C extends Data.TaggedError("C")<{}> {}

declare const program: Effect.Effect<string, A | B | C>;

export const handled: Effect.Effect<string, C> = program.pipe(
  Effect.catchTag("A", () => Effect.succeed("a-recovered")),
  Effect.catchTag("B", () => Effect.succeed("b-recovered"))
);
```

After catching `A` then `B`, only `C` remains in `E`.

```ts
import { pipe } from "fp-ts/function";

const split = (sep: string) => (s: string): ReadonlyArray<string> => s.split(sep);
const trimAll = (xs: ReadonlyArray<string>): ReadonlyArray<string> => xs.map((x) => x.trim()).filter((x) => x.length > 0);
const lowerAll = (xs: ReadonlyArray<string>): ReadonlyArray<string> => xs.map((x) => x.toLowerCase());
const unique = (xs: ReadonlyArray<string>): ReadonlyArray<string> => Array.from(new Set(xs));

// Before — half-methods, half-free-functions; reads as a jigsaw:
//   const tags = unique(trim(split(input, ","))).map(t => t.toLowerCase());
// After — a single data-first pipe; every stage is uniform A -> B:
export const parseTags = (input: string): ReadonlyArray<string> =>
  pipe(input, split(","), trimAll, lowerAll, unique);
```

Four stages, each named, each curried into the `A -> B` shape. The pipeline can grow without growing parenthesis depth.

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly brokers: ReadonlyArray<string>; readonly groupId: string }
const Config = Context.GenericTag<Config>("kafka/Config");

interface Consumer { readonly poll: () => Effect.Effect<ReadonlyArray<string>> }
const Consumer = Context.GenericTag<Consumer>("kafka/Consumer");

const ConfigLive = Layer.succeed(Config, {
  brokers: ["localhost:9092"],
  groupId: "app"
});

// Consumer depends on Config; scoped so subscriptions close on shutdown
const ConsumerLive = Layer.scoped(
  Consumer,
  Effect.gen(function* () {
    const cfg = yield* Config;
    yield* Effect.acquireRelease(
      Effect.sync(() => console.log(`subscribe ${cfg.groupId}@${cfg.brokers.join(",")}`)),
      () => Effect.sync(() => console.log(`unsubscribe ${cfg.groupId}`))
    );
    return Consumer.of({
      poll: () => Effect.succeed([`msg@${cfg.groupId}`])
    });
  })
);

const LiveLayer = Layer.merge(ConfigLive, ConsumerLive);

const program = Effect.gen(function* () {
  const c = yield* Consumer;
  return yield* c.poll();
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.scoped` ensures the subscribe/unsubscribe pair runs exactly once per application lifetime; the tag-first argument keeps typing strict.

```ts
import { pipe } from 'fp-ts/function';

const ensureNonEmpty = (s: string): string => {
  if (s.length === 0) throw new Error('empty');
  return s;
};
const normalise = (s: string): string => s.normalize('NFC').toLowerCase();
const dropSpaces = (s: string): string => s.replace(/\s+/g, '');
const djb2 = (s: string): number => {
  let h = 5381;
  for (const ch of s) h = (h * 33) ^ ch.charCodeAt(0);
  return h >>> 0;
};

export const quickHash = (raw: string): number =>
  pipe(raw, ensureNonEmpty, normalise, dropSpaces, djb2);
```

Each step has exactly one responsibility and reads top-to-bottom — the pipeline literally documents the business rule.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type TooShort = { _tag: "TooShort"; n: number };
type NoDigit = { _tag: "NoDigit" };
type NoSymbol = { _tag: "NoSymbol" };

const min8 = (s: string): E.Either<TooShort, string> =>
  s.length >= 8 ? E.right(s) : E.left({ _tag: "TooShort", n: s.length });

const hasDigit = (s: string): E.Either<NoDigit, string> =>
  /\d/.test(s) ? E.right(s) : E.left({ _tag: "NoDigit" });

const hasSymbol = (s: string): E.Either<NoSymbol, string> =>
  /[!@#$%^&*]/.test(s) ? E.right(s) : E.left({ _tag: "NoSymbol" });

export const isStrongPassword = (pw: string): boolean =>
  pipe(
    min8(pw),
    E.chainW(hasDigit),
    E.chainW(hasSymbol),
    E.mapLeft((_e) => false as const),
    E.match((v) => v, (_ok) => true),
  );
```

The `_e` parameter shows that `E.mapLeft` sees the widened union `TooShort | NoDigit | NoSymbol` — we just discard it to produce `false`.

