```ts
import { Effect, Ref } from "effect";

interface Counters {
  readonly ok: Ref.Ref<number>;
  readonly err: Ref.Ref<number>;
}

export const withMetrics =
  <A, E, R>(counters: Counters) =>
  (eff: Effect.Effect<A, E, R>): Effect.Effect<A, E, R> =>
    eff.pipe(
      Effect.tap(() => Ref.update(counters.ok, (n) => n + 1)),
      Effect.tapError(() => Ref.update(counters.err, (n) => n + 1)),
    );

declare const fetchProfile: (id: string) => Effect.Effect<{ name: string }, Error>;

export const instrumented = (counters: Counters, id: string) =>
  fetchProfile(id).pipe(withMetrics(counters));
```

The `<A, E, R>` generics preserve the full effect signature, so `withMetrics` can wrap any effect without changing its type.

```typescript
import { Effect, Data } from "effect";

class StepAError extends Data.TaggedError("StepAError")<{ readonly msg: string }> {}
class StepBError extends Data.TaggedError("StepBError")<{ readonly code: number }> {}

const stepA: Effect.Effect<number, StepAError> = Effect.fail(new StepAError({ msg: "nope" }));
const stepB = (n: number): Effect.Effect<string, StepBError> =>
  n > 0 ? Effect.succeed(`ok-${n}`) : Effect.fail(new StepBError({ code: -1 }));

const program: Effect.Effect<string, StepAError | StepBError> = Effect.gen(function* () {
  const n = yield* stepA;
  return yield* stepB(n);
});

export const handled: Effect.Effect<string, never> = program.pipe(
  Effect.catchTag("StepAError", () => Effect.succeed("recovered-A")),
  Effect.catchTag("StepBError", () => Effect.succeed("recovered-B"))
);
```

Chaining `Effect.catchTag` calls narrows the error union tag by tag — order doesn't matter for correctness since each match is on a distinct discriminator.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const head = <A>(xs: ReadonlyArray<A>): O.Option<A> =>
  xs.length > 0 ? O.some(xs[0]) : O.none;

export const firstOr = <A, B>(
  xs: ReadonlyArray<A>,
  f: (a: A) => B,
  fallback: B,
): B =>
  pipe(
    head(xs),
    O.map(f),
    O.getOrElse<B>(() => fallback),
  );

export const firstName = (names: ReadonlyArray<string>): string =>
  firstOr(names, (s) => s.toUpperCase(), 'NONE');
```

The generic `head` keeps the domain logic honest — we cannot accidentally read `xs[0]` on an empty array since the type says `Option<A>`, not `A`.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

const nonEmpty = (s: string): E.Either<string, string> =>
  s.trim().length > 0 ? E.right(s) : E.left('email is required');

const hasAt = (s: string): E.Either<string, string> =>
  s.includes('@') ? E.right(s) : E.left("email must contain '@'");

const underMaxLen = (s: string): E.Either<string, string> =>
  s.length < 254 ? E.right(s) : E.left('email must be < 254 chars');

export const validateEmail = (s: string): E.Either<string, string> =>
  pipe(
    nonEmpty(s),
    E.chainW(hasAt),
    E.chainW(underMaxLen),
    E.mapLeft((msg) => `[email] ${msg}`),
  );
```

`E.chainW` is the widening variant — here all the error types happen to be `string`, but using `chainW` keeps the door open to different left types without a manual unification.

```ts
import { Effect, Console } from "effect";

interface FileHandle { readonly path: string; readonly fd: number }

const openFile = (path: string): Effect.Effect<FileHandle, never, never> =>
  Effect.sync(() => ({ path, fd: Math.floor(Math.random() * 1_000_000) }));

const closeFile = (h: FileHandle): Effect.Effect<void> =>
  Console.log(`[close] ${h.path} (fd=${h.fd})`);

// acquireRelease returns Effect<A, E, Scope>; Effect.scoped eliminates Scope.
const fileResource = (path: string) =>
  Effect.acquireRelease(openFile(path), (h) => closeFile(h));

const program = Effect.scoped(
  Effect.gen(function* () {
    const h = yield* fileResource("/tmp/data.txt");
    yield* Console.log(`[use] reading ${h.path}`);
    return h.path;
  })
);

Effect.runPromise(program).then((r) => console.log("done:", r));
```

`Effect.acquireRelease` registers the finalizer in the current `Scope`. `Effect.scoped` closes that scope once the inner effect finishes, so the release runs even if the read step fails.

```ts
import { Effect, Data } from "effect";

interface Profile { readonly userId: string; readonly displayName: string }
interface Enrollment { readonly userId: string; readonly plan: "free" | "pro" }

class EmailError extends Data.TaggedError("EmailError")<{ readonly userId: string }> {}
class ProfileError extends Data.TaggedError("ProfileError")<{ readonly userId: string }> {}
class EnrollError extends Data.TaggedError("EnrollError")<{ readonly userId: string }> {}

declare const sendWelcome: (userId: string) => Effect.Effect<void, EmailError>;
declare const createProfile: (userId: string, name: string) => Effect.Effect<Profile, ProfileError>;
declare const enroll: (userId: string) => Effect.Effect<Enrollment, EnrollError>;

export const onboard = (
  userId: string,
  name: string
): Effect.Effect<{ profile: Profile; enrollment: Enrollment }, EmailError | ProfileError | EnrollError> =>
  Effect.gen(function* () {
    yield* sendWelcome(userId);
    const profile = yield* createProfile(userId, name);
    const enrollment = yield* enroll(profile.userId);
    return { profile, enrollment };
  });
```

Every failure mode surfaces in the error union; downstream `catchTag` calls can peel them off one at a time without losing coverage.

```ts
import { Effect, Layer, Context } from "effect";

interface ServiceConfig { readonly svc: string }
const ServiceConfig = Context.GenericTag<ServiceConfig>("app/ServiceConfig");

interface Metrics { readonly count: (n: string) => Effect.Effect<void> }
const Metrics = Context.GenericTag<Metrics>("app/Metrics");

interface Tracer { readonly span: (n: string) => Effect.Effect<void> }
const Tracer = Context.GenericTag<Tracer>("app/Tracer");

interface Logger { readonly log: (m: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

const ServiceConfigLive = Layer.succeed(ServiceConfig, { svc: "api" });

// All three observability services depend on ServiceConfig
const MetricsLive = Layer.effect(
  Metrics,
  Effect.gen(function* () {
    const c = yield* ServiceConfig;
    return Metrics.of({ count: (n) => Effect.sync(() => console.log(`${c.svc}:${n}`)) });
  })
);
const TracerLive = Layer.effect(
  Tracer,
  Effect.gen(function* () {
    const c = yield* ServiceConfig;
    return Tracer.of({ span: (n) => Effect.sync(() => console.log(`${c.svc}/span:${n}`)) });
  })
);
const LoggerLive = Layer.effect(
  Logger,
  Effect.gen(function* () {
    const c = yield* ServiceConfig;
    return Logger.of({ log: (m) => Effect.sync(() => console.log(`${c.svc} ${m}`)) });
  })
);

const LiveLayer = Layer.mergeAll(ServiceConfigLive, MetricsLive, TracerLive, LoggerLive);

const program = Effect.gen(function* () {
  const m = yield* Metrics;
  const t = yield* Tracer;
  const l = yield* Logger;
  yield* m.count("hit");
  yield* t.span("route");
  yield* l.log("ok");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.mergeAll` is the natural choice when you have N peer services that all depend on a common base — the argument list reads like a manifest.

```ts
import { Effect, Option, Data } from "effect";

interface User { readonly id: string; readonly name: string }

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}

declare const cacheGet: (id: string) => Effect.Effect<Option.Option<User>>;
declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound>;
declare const cachePut: (u: User) => Effect.Effect<void>;

export const getUser = (id: string): Effect.Effect<User, UserNotFound> =>
  Effect.gen(function* () {
    const cached = yield* cacheGet(id);
    if (Option.isSome(cached)) return cached.value;
    const u = yield* fetchUser(id);
    yield* cachePut(u);
    return u;
  });
```

The cache path returns inside the generator without calling `fetchUser`, so the miss-path remains the only place the `UserNotFound` error can surface.

```python
from dataclasses import dataclass
import re
from typing import Any

_EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")

@dataclass
class Customer:
    id: int
    name: str
    email: str

    def __post_init__(self) -> None:
        if not _EMAIL_RE.match(self.email):
            raise ValueError(f"invalid email: {self.email!r}")

    @classmethod
    def from_dict(cls, d: dict[str, Any]) -> "Customer":
        return cls(id=int(d["id"]), name=str(d["name"]), email=str(d["email"]))
```

`__post_init__` runs after the generated `__init__` and is the canonical spot for validation. `from_dict` coerces types explicitly so a JSON payload with numeric strings doesn't smuggle through the type hints.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Empty = { _tag: "Empty" };
type TooLong = { _tag: "TooLong"; n: number };

const nonEmpty = (s: string | undefined | null): E.Either<Empty, string> =>
  s != null && s.length > 0 ? E.right(s) : E.left({ _tag: "Empty" });

const maxLen80 = (s: string): E.Either<TooLong, string> =>
  s.length <= 80 ? E.right(s) : E.left({ _tag: "TooLong", n: s.length });

export const process = (input: string | undefined | null): E.Either<string, string> =>
  pipe(
    nonEmpty(input),
    E.chainW(maxLen80),
    E.map((s) => s.trim()),
    E.mapLeft((e) => e._tag.toLowerCase()),
    E.match(
      (tag) => E.left<string, string>(tag),
      (s) => E.right<string, string>(s),
    ),
  );
```

The `(err, ok)` callback dichotomy maps onto `Either` natively: the left holds the error, the right holds the success value. `E.match` here rewraps into the simpler `Either<string, string>` interface callers want.

```ts
import { Effect, Layer, Context } from "effect";

interface Env { readonly get: (key: string) => string | undefined }
const Env = Context.GenericTag<Env>("app/Env");

interface FeatureFlags { readonly enabled: (flag: string) => Effect.Effect<boolean> }
const FeatureFlags = Context.GenericTag<FeatureFlags>("app/FeatureFlags");

const EnvLive = Layer.succeed(Env, {
  get: (k) => ({ NEW_CHECKOUT: "true", DARK_MODE: "false" } as Record<string, string>)[k]
});

// FeatureFlags depends on Env (reads flag values by name)
const FeatureFlagsLive = Layer.effect(
  FeatureFlags,
  Effect.gen(function* () {
    const env = yield* Env;
    return FeatureFlags.of({
      enabled: (flag) => Effect.sync(() => env.get(flag) === "true")
    });
  })
);

const LiveLayer = Layer.merge(EnvLive, FeatureFlagsLive);

const program: Effect.Effect<boolean, never, FeatureFlags> = Effect.gen(function* () {
  const ff = yield* FeatureFlags;
  return yield* ff.enabled("NEW_CHECKOUT");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`FeatureFlags` is keyed by its `Context.GenericTag`; the `Env` tag survives only inside the layer graph and is eliminated once `Layer.merge` bundles `EnvLive`.

```ts
import { Effect } from "effect";

const a: Effect.Effect<number, never> = Effect.succeed(1);
const b: Effect.Effect<number, never> = Effect.succeed(2);
const c: Effect.Effect<number, never> = Effect.succeed(3);

// No options → sequential. Effects run in order, each awaiting the previous.
