```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseDate = (s: string): O.Option<Date> => {
  const d = new Date(s);
  return Number.isNaN(d.getTime()) ? O.none : O.some(d);
};

