`Effect.catchTag` is the typed analogue of `TE.orElse` filtered to one error tag; the resulting error channel is the union of the remaining tags and the fallback's errors.

```ts
import { Effect, Data, Duration } from "effect";

class TimeoutErr extends Data.TaggedError("TimeoutErr")<{ readonly ms: number }> {}

const fetchPrimary: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("200 millis");
  return "primary-ok";
});

const timeoutAfter = (ms: number): Effect.Effect<never, TimeoutErr> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new TimeoutErr({ ms }));
  });

const program: Effect.Effect<string, TimeoutErr> = Effect.race(fetchPrimary, timeoutAfter(150));

Effect.runPromise(Effect.either(program)).then(console.log);
```

Unlike `Promise.race`, the loser is *actually* cancelled — not just ignored — because fibres are interruptible.

```typescript
import { Effect, Data } from "effect";

class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}
class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

const find = (id: string): Effect.Effect<string, NotFoundError | DbError> =>
  id === "" ? Effect.fail(new NotFoundError({ id })) : Effect.succeed("row");

export const program: Effect.Effect<string | null, DbError> = find("").pipe(
  Effect.catchTag("NotFoundError", () => Effect.succeed(null))
