```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface ProfileUpdate { displayName: string; bio: string; avatarUrl: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const checkDisplay = (s: string): E.Either<Errs, string> =>
  s.trim().length >= 2 ? E.right(s) : E.left([fe("displayName", "too short")]);
const checkBio = (s: string): E.Either<Errs, string> =>
  s.length <= 280 ? E.right(s) : E.left([fe("bio", "over 280 chars")]);
const checkAvatar = (s: string): E.Either<Errs, string> =>
  s.startsWith("https://") ? E.right(s) : E.left([fe("avatarUrl", "must be https")]);

// `E.chain` short-circuits on the first left. `sequenceT` over the validation
// applicative instead *accumulates* all lefts into a ReadonlyNonEmptyArray.
export const validateProfile = (p: ProfileUpdate): E.Either<Errs, ProfileUpdate> =>
  pipe(
    sequenceT(V)(checkDisplay(p.displayName), checkBio(p.bio), checkAvatar(p.avatarUrl)),
    E.map(([displayName, bio, avatarUrl]) => ({ displayName, bio, avatarUrl }))
  );
```

The shift is from `pipe(x, E.chain(f), E.chain(g), ...)` — which stops at the first `E.left` — to `sequenceT(V)(fx, gx, hx)` with the validation applicative, which evaluates every branch and concatenates their errors.

```ts
import { Effect, Context, Layer } from "effect";

interface L1 { readonly tag: "L1" }
interface L2 { readonly tag: "L2" }
interface Main { readonly tag: "Main" }

const L1 = Context.GenericTag<L1>("app/L1");
const L2 = Context.GenericTag<L2>("app/L2");
const Main = Context.GenericTag<Main>("app/Main");

const L1Live = Layer.succeed(L1, { tag: "L1" });
const L2Live = Layer.succeed(L2, { tag: "L2" });
const MainLive = Layer.effect(Main, Effect.succeed({ tag: "Main" as const }));

const program = Effect.gen(function* () {
  const m = yield* Main;
  return m.tag;
});

// Flatten the two nested Layer.provide calls: merge the deps, provide once.
const Deps = Layer.merge(L1Live, L2Live);
export const runnable = Effect.provide(program, Layer.provide(MainLive, Deps));
```

Merging `L1Live` and `L2Live` into `Deps` collapses the nesting and makes the dependency direction obvious: `Main -> { L1, L2 }`.

```ts
import { Effect, Console } from "effect";

interface Channel { readonly topic: string }

const openCh = (topic: string): Effect.Effect<Channel> => Effect.succeed({ topic });
const closeCh = (c: Channel) => Console.log(`close ${c.topic}`);

// Refactored: acquireRelease + scoped makes the pairing explicit and survives interruption.
const channel = (topic: string) =>
  Effect.acquireRelease(openCh(topic), (c) => closeCh(c));

const program = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* channel("events");
    yield* Console.log(`using ${c.topic}`);
    return c.topic;
  })
);

Effect.runPromise(program);
```

`Effect.ensuring` runs an action at the end but isn't tied to an acquired value; `acquireRelease` binds the release to the exact handle it owns, which is safer.

