import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Kyc { ssn: string; dob: string; idImage: string }

const ssn = (s: string): Effect.Effect<string, FieldError> =>
  /^\d{3}-\d{2}-\d{4}$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("ssn", "bad ssn"));
const dob = (s: string): Effect.Effect<string, FieldError> =>
  !Number.isNaN(Date.parse(s)) ? Effect.succeed(s) : Effect.fail(fe("dob", "bad date"));
const idImage = (s: string): Effect.Effect<string, FieldError> =>
  s.startsWith("data:image/") ? Effect.succeed(s) : Effect.fail(fe("idImage", "need data uri"));

export const validateKyc = (
  k: Kyc
): Effect.Effect<Kyc, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [s, d, i] = yield* Effect.all([
      Effect.either(ssn(k.ssn)),
      Effect.either(dob(k.dob)),
      Effect.either(idImage(k.idImage)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(s)) errs.push(s.left);
    if (Either.isLeft(d)) errs.push(d.left);
    if (Either.isLeft(i)) errs.push(i.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return k;
  });
```

Wrapping each check in `Effect.either` turns failures into data so `Effect.all` doesn't short-circuit; we then hoist every `Left` into the `ReadonlyArray<FieldError>` error channel.

