```ts
import { Effect, Ref, Clock, Duration } from "effect";

interface Bucket { readonly tokens: number; readonly lastRefillMs: number }

export const makeTokenBucket = (capacity: number, refillPerSec: number) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Bucket>({ tokens: capacity, lastRefillMs: 0 });
    const acquire = (): Effect.Effect<void> =>
      Effect.gen(function* () {
        while (true) {
          const now = yield* Clock.currentTimeMillis;
          const got = yield* Ref.modify(ref, (b) => {
            const add = Math.floor(((now - b.lastRefillMs) / 1000) * refillPerSec);
            const tokens = Math.min(capacity, b.tokens + Math.max(0, add));
            if (tokens <= 0) return [false, { tokens, lastRefillMs: now }];
            return [true, { tokens: tokens - 1, lastRefillMs: now }];
          });
          if (got) return;
          yield* Effect.sleep(Duration.millis(50));
        }
      });
    return { acquire } as const;
  });
