import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type HandlerError =
  | { readonly _tag: 'MissingHeader' }
  | { readonly _tag: 'BadHeader'; readonly reason: string };

interface Request { readonly headers: Readonly<Record<string, string | undefined>> }

const getHeader = (req: Request): E.Either<HandlerError, string> => {
  const h = req.headers['x-token'];
  return h === undefined ? E.left({ _tag: 'MissingHeader' }) : E.right(h);
};

const parseToken = (raw: string): E.Either<HandlerError, { sub: string }> => {
  const parts = raw.split('.');
  return parts.length === 2
    ? E.right({ sub: parts[0] })
    : E.left({ _tag: 'BadHeader', reason: 'format' });
};

const requireSub = (t: { sub: string }): E.Either<HandlerError, string> =>
  t.sub.length > 0 ? E.right(t.sub) : E.left({ _tag: 'BadHeader', reason: 'no-sub' });

export const handle = (req: Request): E.Either<HandlerError, string> =>
  pipe(getHeader(req), E.chain(parseToken), E.chain(requireSub));
```

Each stage returns an Either with the same error type, so `E.chain` stitches them into a single short-circuiting pipeline.

