const firmware = (s: string): E.Either<Errs, string> =>
  /^\d+\.\d+\.\d+$/.test(s) ? E.right(s) : E.left([fe("firmwareVersion", "semver required")]);
const region = (s: string): E.Either<Errs, string> =>
  ["us-east", "us-west", "eu-central", "ap-south"].includes(s)
    ? E.right(s)
    : E.left([fe("region", "unknown region")]);

