import { Effect } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Order { totalCents: number; country: string; itemCount: number }

type Rule = { field: string; ok: (o: Order) => boolean; message: string };

const rules: ReadonlyArray<Rule> = [
  { field: "totalCents", ok: (o) => o.totalCents >= 500, message: "min $5" },
  { field: "country", ok: (o) => ["US", "CA"].includes(o.country), message: "US|CA only" },
  { field: "itemCount", ok: (o) => o.itemCount <= 50, message: "<= 50 items" },
];

export const checkOrder = (
  o: Order
): Effect.Effect<Order, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [errs] = yield* Effect.partition(rules, (r) =>
      r.ok(o) ? Effect.succeed(r.field) : Effect.fail(fe(r.field, r.message))
    );
    if (errs.length > 0) return yield* Effect.fail(errs);
    return o;
  });
```

`Effect.partition(rules, fn)` runs every rule and returns `[errors, successes]` without short-circuiting. We lift the errors arm into the failure channel so the caller sees every broken rule as a single `ReadonlyArray<FieldError>`.

```ts
import { Effect, Context, Layer, Data } from "effect";

class CacheError extends Data.TaggedError("CacheError")<{ readonly key: string }> {}

interface Cache {
  readonly warm: (k: string) => Effect.Effect<void, CacheError>;
  readonly read: (k: string) => Effect.Effect<string, CacheError>;
}
const Cache = Context.GenericTag<Cache>("app/Cache");

export const program: Effect.Effect<string, CacheError, Cache> =
  Effect.gen(function* () {
    const cache = yield* Cache;
    // Parallel warm-up.
    yield* Effect.all(
      [cache.warm("a"), cache.warm("b"), cache.warm("c")] as const,
      { concurrency: "unbounded", discard: true }
    );
    // Sequential read after the warm-up resolves.
    return yield* cache.read("a");
  });

export const CacheLive = Layer.succeed(Cache, {
  warm: () => Effect.void,
  read: () => Effect.succeed("hit"),
});
```

The parallel `Effect.all` finishes before the surrounding generator continues; the trailing `cache.read` is a plain sequential yield inside `Effect.gen`.

