class ApiError extends Data.TaggedError("ApiError")<{ readonly code: number }> {}
class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly ms: number }> {}

declare const slowApi: Effect.Effect<string, ApiError>;

