import { Effect, Data, Console } from "effect";

class LoadError extends Data.TaggedError("LoadError")<{ readonly key: string }> {}

interface Config { readonly url: string }
interface Client { readonly cfg: Config; readonly id: number }

const loadConfig: Effect.Effect<Config, LoadError> = Effect.succeed({ url: "https://api.example.com" });
const openClient = (cfg: Config): Effect.Effect<Client> =>
  Effect.sync(() => ({ cfg, id: Date.now() }));

const config = Effect.acquireRelease(loadConfig, () => Console.log("[cfg] unloaded"));
const client = (cfg: Config) =>
  Effect.acquireRelease(openClient(cfg), (c) => Console.log(`[client ${c.id}] closed`));

const program: Effect.Effect<number, LoadError, never> = Effect.scoped(
  Effect.gen(function* () {
    const cfg = yield* config;
    const c = yield* client(cfg);
    return c.id;
  })
);

Effect.runPromise(program).then(console.log);
```

Scope runs finalizers in LIFO order — the client closes first, then the config unloads.

