import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface CouponForm { code: string; discountPct: number; expiresAt: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const code = (s: string): E.Either<Errs, string> =>
  /^[A-Z0-9]{4,12}$/.test(s) ? E.right(s) : E.left([fe("code", "4-12 upper/digits")]);
const discount = (n: number): E.Either<Errs, number> =>
  n > 0 && n < 100 ? E.right(n) : E.left([fe("discountPct", "0 < n < 100")]);
const expires = (s: string): E.Either<Errs, string> =>
  !Number.isNaN(Date.parse(s)) && Date.parse(s) > Date.now()
    ? E.right(s)
    : E.left([fe("expiresAt", "must be future ISO date")]);

export const validateCoupon = (c: CouponForm): E.Either<Errs, CouponForm> =>
  sequenceS(V)({ code: code(c.code), discountPct: discount(c.discountPct), expiresAt: expires(c.expiresAt) });
```

`sequenceS` over the validation applicative is the record-shaped accumulator: every bad field raises its own `Left` into the shared `ReadonlyNonEmptyArray<FieldError>`.

