import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadNum = { _tag: "BadNum"; raw: string };
type BelowAbsZero = { _tag: "BelowAbsZero"; c: number };

const parseNum = (s: string): E.Either<BadNum, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadNum", raw: s });
};

const atLeastAbsZero = (c: number): E.Either<BelowAbsZero, number> =>
  c >= -273.15 ? E.right(c) : E.left({ _tag: "BelowAbsZero", c });

const toF = (c: number): number => Math.round((c * 9 / 5 + 32) * 10) / 10;

export const convert = (raw: string): string =>
  pipe(
    parseNum(raw),
    E.chainW(atLeastAbsZero),
    E.map(toF),
    E.mapLeft((e) => e._tag === "BadNum" ? `not a number: ${e.raw}` : `below absolute zero: ${e.c}`),
    E.match((err) => `ERR: ${err}`, (f) => `${f}F`),
  );
```

`E.map(toF)` applies the pure transform without touching the left; `E.mapLeft` exhaustively handles the widened `BadNum | BelowAbsZero` union.

