import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type ApiError =
  | { readonly _tag: 'NetworkError'; readonly message: string }
  | { readonly _tag: 'ServerError'; readonly status: number };

interface ErrorWithStatus { readonly status: number }

const hasStatus = (u: unknown): u is ErrorWithStatus =>
  typeof u === 'object' &&
  u !== null &&
  typeof (u as ErrorWithStatus).status === 'number';

declare const api: () => Promise<{ ok: true }>;

export const call = (): TE.TaskEither<ApiError, { ok: true }> =>
  TE.tryCatch(
    () => api(),
    (u): ApiError =>
      hasStatus(u)
        ? { _tag: 'ServerError', status: u.status }
        : { _tag: 'NetworkError', message: u instanceof Error ? u.message : 'unknown' }
  );

export const isOk = (): TE.TaskEither<ApiError, boolean> =>
  pipe(call(), TE.map((r) => r.ok));
