import { Effect, Layer, Context } from "effect";

interface SearchConfig { readonly indexPath: string }
const SearchConfig = Context.GenericTag<SearchConfig>("search/Config");

interface IndexReader { readonly lookup: (term: string) => Effect.Effect<ReadonlyArray<string>> }
const IndexReader = Context.GenericTag<IndexReader>("search/IndexReader");

interface QueryParser { readonly parse: (q: string) => Effect.Effect<ReadonlyArray<string>> }
const QueryParser = Context.GenericTag<QueryParser>("search/QueryParser");

interface SearchService { readonly search: (q: string) => Effect.Effect<ReadonlyArray<string>> }
const SearchService = Context.GenericTag<SearchService>("search/SearchService");

const SearchConfigLive = Layer.succeed(SearchConfig, { indexPath: "/var/idx" });
const QueryParserLive = Layer.succeed(QueryParser, {
  parse: (q) => Effect.succeed(q.split(/\s+/))
});

// IndexReader depends on SearchConfig
const IndexReaderLive = Layer.effect(
  IndexReader,
  Effect.gen(function* () {
    const cfg = yield* SearchConfig;
    return IndexReader.of({
      lookup: (term) => Effect.succeed([`${cfg.indexPath}:hit-${term}`])
    });
  })
);

// SearchService depends on IndexReader + QueryParser
const SearchServiceLive = Layer.effect(
  SearchService,
  Effect.gen(function* () {
    const reader = yield* IndexReader;
    const parser = yield* QueryParser;
    return SearchService.of({
      search: (q) => Effect.gen(function* () {
        const terms = yield* parser.parse(q);
        const hits: Array<string> = [];
        for (const term of terms) hits.push(...(yield* reader.lookup(term)));
        return hits;
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(SearchConfigLive, QueryParserLive, IndexReaderLive, SearchServiceLive);

const program = Effect.gen(function* () {
  const s = yield* SearchService;
  return yield* s.search("effect layer");
});

export const runnable = Effect.provide(program, LiveLayer);
```

Four tags, three dependencies, one `Effect.provide`: `Layer.mergeAll` resolves the graph once at provide time.

```ts
import { Effect, Context, Layer } from "effect";

interface A { readonly tag: "A" }
interface B { readonly tag: "B" }
interface C { readonly tag: "C" }
interface D { readonly tag: "D" }

const A = Context.GenericTag<A>("app/A");
const B = Context.GenericTag<B>("app/B");
const C = Context.GenericTag<C>("app/C");
const D = Context.GenericTag<D>("app/D");

const ALive = Layer.succeed(A, { tag: "A" });
const BLive = Layer.succeed(B, { tag: "B" });
const CLive = Layer.effect(C, Effect.succeed({ tag: "C" as const }));
const DLive = Layer.effect(D, Effect.succeed({ tag: "D" as const }));

