```ts
import { Effect, Fiber, Data } from "effect";

class PrepareRejected extends Data.TaggedError("PrepareRejected")<{ readonly replica: string }> {}
class Aborted extends Data.TaggedError("Aborted")<{ readonly reason: string }> {}

interface Vote { readonly replica: string; readonly ok: true }

declare const prepare: (replica: string) => Effect.Effect<Vote, PrepareRejected>;

export const twoPhaseCommit = (
  a: string,
  b: string
): Effect.Effect<readonly [Vote, Vote], Aborted> =>
  Effect.gen(function* () {
    const fa = yield* Effect.fork(prepare(a));
    const fb = yield* Effect.fork(prepare(b));
    const va = yield* Fiber.join(fa).pipe(
      Effect.catchTag("PrepareRejected", (e) =>
        Fiber.interrupt(fb).pipe(
          Effect.flatMap(() => Effect.fail(new Aborted({ reason: e.replica })))
        )
      )
    );
    const vb = yield* Fiber.join(fb).pipe(
      Effect.catchTag("PrepareRejected", (e) =>
        Effect.fail(new Aborted({ reason: e.replica }))
      )
    );
    return [va, vb] as const;
  });
```

The first rejection triggers `Fiber.interrupt` on the peer so its prepare work is torn down before the coordinator returns `Aborted`. On mutual success both joins succeed.

