import { Effect, Data, Console } from "effect";

class RegisterError extends Data.TaggedError("RegisterError")<{ readonly reason: string }> {}

interface ScheduledTask { readonly id: string; readonly cancel: () => void }

const register = (name: string): Effect.Effect<ScheduledTask, RegisterError> =>
  name === "" ? Effect.fail(new RegisterError({ reason: "empty name" }))
              : Effect.succeed({ id: `${name}-${Date.now()}`, cancel: () => {} });

const scheduled = (name: string) =>
  Effect.acquireRelease(
    register(name),
    (t) => Effect.sync(() => { t.cancel(); console.log(`cancelled ${t.id}`); })
  );

const program: Effect.Effect<string, RegisterError, never> = Effect.scoped(
  Effect.gen(function* () {
    const t = yield* scheduled("heartbeat");
    yield* Console.log(`[tick] ${t.id}`);
    return t.id;
  })
);

Effect.runPromise(program).then(console.log);
