Layers build services from their dependencies. `Layer.succeed` injects a ready-made value, `Layer.effect` constructs one inside an `Effect` (can `yield*` other services), and `Layer.merge` / `Layer.mergeAll` combine independent layers. `Effect.provide` finally feeds a program the composed `Layer`, erasing service tags from the R channel.

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly logTarget: "console" | "file" }
const Config = Context.GenericTag<Config>("app/Config");

interface Logger { readonly log: (msg: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

const ConfigLive = Layer.succeed(Config, { logTarget: "console" });

// Logger depends on Config (chooses backend)
const LoggerLive = Layer.effect(
  Logger,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return Logger.of({
      log: (msg) => cfg.logTarget === "console"
        ? Effect.sync(() => console.log(msg))
        : Effect.sync(() => { /* append to file */ })
    });
  })
);

const LiveLayer = Layer.merge(ConfigLive, LoggerLive);

const program = Effect.gen(function* () {
  const log = yield* Logger;
  yield* log.log("hello");
});

export const runnable = Effect.provide(program, LiveLayer);
```

The tag-first argument to `Layer.effect` keeps the compiler from drifting to stringly-typed keys.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadShape = { _tag: "BadShape"; parts: number };
type BadOctet = { _tag: "BadOctet"; raw: string };

const fourParts = (s: string): E.Either<BadShape, ReadonlyArray<string>> => {
  const ps = s.split(".");
  return ps.length === 4 ? E.right(ps) : E.left({ _tag: "BadShape", parts: ps.length });
};

const toOctets = (parts: ReadonlyArray<string>): E.Either<BadOctet, ReadonlyArray<number>> => {
  const out: number[] = [];
  for (const p of parts) {
    const n = Number.parseInt(p, 10);
    if (!Number.isFinite(n) || n < 0 || n > 255) return E.left({ _tag: "BadOctet", raw: p });
    out.push(n);
  }
  return E.right(out);
};

const pack = (octets: ReadonlyArray<number>): number =>
  ((octets[0] << 24) | (octets[1] << 16) | (octets[2] << 8) | octets[3]) >>> 0;

export const ipv4ToUint = (raw: string): string =>
  pipe(
    fourParts(raw),
    E.chainW(toOctets),
    E.map(pack),
    E.mapLeft((e) => `invalid ipv4 (${e._tag})`),
    E.fold((err) => err, (n) => n.toString(16).padStart(8, "0")),
  );
```

The widened left `BadShape | BadOctet` survives intact through `E.map` (which only touches the right); `E.mapLeft` formats it just before `E.fold`.

