```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Err1 = { _tag: "Err1" };
type Err2 = { _tag: "Err2" };

declare const cond1: <T>(x: T) => boolean;
declare const cond2: <T>(x: T) => boolean;

const check1 = <T>(x: T): E.Either<Err1, T> =>
  cond1(x) ? E.right(x) : E.left({ _tag: "Err1" });

const check2 = <T>(x: T): E.Either<Err2, T> =>
  cond2(x) ? E.right(x) : E.left({ _tag: "Err2" });

export const validate = <T>(x: T): E.Either<string, T> =>
  pipe(
    check1(x),
    E.chainW(check2),
    E.mapLeft((e) => e._tag),
    E.match((tag) => E.left<string, T>(tag), (v) => E.right<string, T>(v)),
  );
```

The nested ternary becomes a flat pipeline. `E.chainW` widens `Err1` to `Err1 | Err2`; `E.mapLeft` collapses the union to a discriminator string.

```ts
import { Effect, Fiber, Duration, Data } from "effect";

class HeartbeatError extends Data.TaggedError("HeartbeatError")<{ readonly reason: string }> {}

declare const sendPing: Effect.Effect<void, HeartbeatError>;
declare const doWork: Effect.Effect<string>;

const heartbeat: Effect.Effect<never, HeartbeatError> = Effect.gen(function* () {
  while (true) {
    yield* sendPing;
    yield* Effect.sleep(Duration.seconds(1));
  }
});

export const withHeartbeat: Effect.Effect<string, HeartbeatError> =
  Effect.gen(function* () {
    const hb = yield* Effect.fork(heartbeat);
    const result = yield* doWork;
    yield* Fiber.interrupt(hb);
    return result;
  });
```

The heartbeat runs concurrently with `doWork`; the sleep between pings gives the fiber a natural interruption point. `Fiber.interrupt` stops it cleanly — any pending sleep is cancelled and the fiber terminates without leaking a timer.

```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Payroll { salary: number; hours: number; department: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const salary = (n: number): E.Either<Errs, number> =>
  n > 0 && n < 1_000_000 ? E.right(n) : E.left([fe("salary", "out of range")]);
const hours = (n: number): E.Either<Errs, number> =>
  n >= 0 && n <= 80 ? E.right(n) : E.left([fe("hours", "must be 0..80")]);
const dept = (s: string): E.Either<Errs, string> =>
  ["eng", "sales", "ops", "hr"].includes(s) ? E.right(s) : E.left([fe("department", "unknown dept")]);

export const validatePayroll = (p: Payroll): E.Either<Errs, Payroll> =>
  pipe(
    sequenceT(V)(salary(p.salary), hours(p.hours), dept(p.department)),
    E.map(([s, h, d]) => ({ salary: s, hours: h, department: d }))
  );
```

Swapping the `E.chain` tower for `sequenceT(V)` under the validation applicative means a simultaneously-bad salary and department both land in the resulting `ReadonlyNonEmptyArray<FieldError>`.

