```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NotNumber = { _tag: "NotNumber"; raw: string };
type Negative = { _tag: "Negative"; n: number };

const parseFloatE = (s: string): E.Either<NotNumber, number> => {
  const n = Number.parseFloat(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotNumber", raw: s });
};

const nonNegative = (n: number): E.Either<Negative, number> =>
  n >= 0 ? E.right(n) : E.left({ _tag: "Negative", n });

const withTax = (n: number): number => n * 1.2;

export const priceOf = (raw: string): number =>
  pipe(
    parseFloatE(raw),
    E.chainW(nonNegative),
    E.map(withTax),
    E.mapLeft((e) => {
      console.warn(`priceOf: ${e._tag}`);
      return 0;
    }),
    E.fold((fallback) => fallback, (price) => Math.round(price * 100) / 100),
  );
```

Throwing becomes `E.left(tagged)`. `E.chainW` widens `NotNumber` to `NotNumber | Negative`; `E.map` applies tax without touching the error channel; `E.fold` collapses both sides to `number`.

