class LockFailed extends Data.TaggedError("LockFailed")<{ readonly node: string }> {}

interface Lease { readonly node: string; readonly expiresAt: number }

declare const tryAcquire: (node: string) => Effect.Effect<Lease, LockFailed>;

export const electLeader = (
  candidates: readonly [string, string, ...string[]]
): Effect.Effect<Lease, LockFailed> =>
  Effect.gen(function* () {
    const attempts = candidates.map(tryAcquire);
    return yield* Effect.raceAll(attempts);
  });
```

`Effect.raceAll` runs all candidate acquisitions concurrently. The first `Lease` success ends the race and interrupts the other fibers, so losing candidates never hold a partial lock. If every candidate fails, the last `LockFailed` propagates.

