```ts
export function memoize<T extends (...args: any[]) => any>(fn: T): T {
  const cache = new Map<string, ReturnType<T>>();
  const memoized = (...args: Parameters<T>): ReturnType<T> => {
    const key = JSON.stringify(args);
    let hit = cache.get(key);
    if (hit === undefined && !cache.has(key)) {
      hit = fn(...args);
      cache.set(key, hit as ReturnType<T>);
    }
    return hit as ReturnType<T>;
  };
  return memoized as T;
}
```

Notes: uses `Parameters<T>` / `ReturnType<T>` to preserve the exact tuple shape and return type. `JSON.stringify` is a reasonable default key for serializable args; swap in a structural hash if you need to cache on objects-with-cycles or functions. The `has` check distinguishes a cached `undefined` from a miss.

