class StreamError extends Data.TaggedError("StreamError")<{ readonly cause: string }> {}
class NeverMatched extends Data.TaggedError("NeverMatched")<{}> {}
class Deadline extends Data.TaggedError("Deadline")<{ readonly ms: number }> {}

declare const waitForMatch: Effect.Effect<string, StreamError>;
declare const waitForFallback: Effect.Effect<string, StreamError>;

