import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface LoanApp { income: number; debtRatio: number; employmentYears: number }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const income = (n: number): E.Either<Errs, number> =>
  n >= 20000 ? E.right(n) : E.left([fe("income", "below minimum $20k")]);
const debtRatio = (n: number): E.Either<Errs, number> =>
  n <= 0.4 ? E.right(n) : E.left([fe("debtRatio", "exceeds 0.4 cap")]);
const emp = (n: number): E.Either<Errs, number> =>
  n >= 2 ? E.right(n) : E.left([fe("employmentYears", "need >= 2 years")]);

export const validateLoan = (l: LoanApp): E.Either<Errs, LoanApp> =>
  pipe(
    sequenceT(V)(income(l.income), debtRatio(l.debtRatio), emp(l.employmentYears)),
    E.map(([inc, dr, ey]) => ({ income: inc, debtRatio: dr, employmentYears: ey }))
  );
