```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";
import { getSemigroup } from "fp-ts/ReadonlyNonEmptyArray";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const err = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface SignupInput { email: string; password: string; username: string }

const validateEmail = (e: string): E.Either<RNEA.ReadonlyNonEmptyArray<FieldError>, string> =>
  /.+@.+\..+/.test(e) ? E.right(e) : E.left([err("email", "invalid format")]);

const validatePassword = (p: string): E.Either<RNEA.ReadonlyNonEmptyArray<FieldError>, string> =>
  p.length >= 8 ? E.right(p) : E.left([err("password", "must be >= 8 chars")]);

const validateUsername = (u: string): E.Either<RNEA.ReadonlyNonEmptyArray<FieldError>, string> =>
  /^[a-z0-9_]{3,20}$/.test(u) ? E.right(u) : E.left([err("username", "3-20 lowercase/digits/_")]);

const Applicative = E.getApplicativeValidation(getSemigroup<FieldError>());

export const validateSignup = (
  input: SignupInput
): E.Either<RNEA.ReadonlyNonEmptyArray<FieldError>, SignupInput> =>
  pipe(
    sequenceT(Applicative)(
      validateEmail(input.email),
      validatePassword(input.password),
      validateUsername(input.username)
    ),
    E.map(([email, password, username]) => ({ email, password, username }))
  );
```

`E.getApplicativeValidation(getSemigroup<FieldError>())` swaps the default short-circuiting Either applicative for one that concatenates failures into a `ReadonlyNonEmptyArray<FieldError>`, so every failed validator contributes its error instead of only the first.

```ts
import { Effect, Data } from "effect";

class AuthError extends Data.TaggedError("AuthError")<{}> {}
class FetchError extends Data.TaggedError("FetchError")<{ readonly id: string }> {}

declare const login: () => Effect.Effect<string, AuthError>;
declare const fetchItem: (token: string, id: string) => Effect.Effect<string, FetchError>;

export const loginAndFetch = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, AuthError | FetchError> =>
  Effect.gen(function* () {
    const token = yield* login(); // sequential step
    return yield* Effect.all(ids.map((id) => fetchItem(token, id)), {
      concurrency: 6,
    });
