```ts
import { Effect } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Checkout { cardNumber: string; cvv: string; zip: string }

type Rule = { field: string; check: (c: Checkout) => boolean; message: string };

const rules: ReadonlyArray<Rule> = [
  { field: "cardNumber", check: (c) => /^\d{16}$/.test(c.cardNumber), message: "need 16 digits" },
  { field: "cvv", check: (c) => /^\d{3,4}$/.test(c.cvv), message: "3-4 digits" },
  { field: "zip", check: (c) => /^\d{5}$/.test(c.zip), message: "5 digits" },
];

export const partitionCheckout = (
  c: Checkout
): Effect.Effect<readonly [ReadonlyArray<FieldError>, ReadonlyArray<string>]> =>
  Effect.partition(rules, (r) =>
    r.check(c) ? Effect.succeed(r.field) : Effect.fail(fe(r.field, r.message))
  );
```

`Effect.partition(items, fn)` runs `fn` on every item and returns `[failures, successes]` — it never fails the outer effect, so the caller can render every bad field in one pass instead of ping-ponging on each mistake.

```ts
