```ts
import { Effect, Duration, Data } from "effect";

interface WebHit { readonly url: string }
interface ImageHit { readonly url: string }
interface VideoHit { readonly url: string }

class WebError extends Data.TaggedError("WebError")<{}> {}
class ImageError extends Data.TaggedError("ImageError")<{}> {}
class VideoError extends Data.TaggedError("VideoError")<{}> {}

declare const webSearch: (q: string) => Effect.Effect<ReadonlyArray<WebHit>, WebError>;
declare const imageSearch: (q: string) => Effect.Effect<ReadonlyArray<ImageHit>, ImageError>;
declare const videoSearch: (q: string) => Effect.Effect<ReadonlyArray<VideoHit>, VideoError>;

