```ts
import { pipe } from 'fp-ts/function';
import * as A from 'fp-ts/ReadonlyArray';

const isEven = (n: number): boolean => n % 2 === 0;
const times10 = (n: number): number => n * 10;
const sum = (xs: ReadonlyArray<number>): number => xs.reduce((a, b) => a + b, 0);

export const out: number = pipe(
  [1, 2, 3, 4] as ReadonlyArray<number>,
  A.filter(isEven),
  A.map(times10),
  sum
);
```

The `fp-ts` array combinators are data-last, so `pipe` is how you feed the array through them. Native `Array.prototype` is fine for quick work, but `pipe` + `ReadonlyArray` gives you immutability and consistent ordering with the rest of an fp-ts codebase.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type DateErr = { _tag: 'InvalidDate' };
type FutureErr = { _tag: 'Future'; iso: string };

const parseIso = (iso: string): E.Either<DateErr, Date> => {
  const d = new Date(iso);
  return Number.isNaN(d.getTime()) ? E.left({ _tag: 'InvalidDate' }) : E.right(d);
};

const notFuture = (now: Date) =>
  (d: Date): E.Either<FutureErr, Date> =>
    d.getTime() <= now.getTime()
      ? E.right(d)
      : E.left({ _tag: 'Future', iso: d.toISOString() });

export const daysAgo = (
  iso: string,
  now: Date,
): E.Either<DateErr | FutureErr, number> =>
  pipe(
    parseIso(iso),
    E.chainW(notFuture(now)),
    E.map((d) => Math.floor((now.getTime() - d.getTime()) / 86_400_000)),
  );
```

Method chaining requires every intermediate to be a prototype method on the carrier type — you can't inject your own `trim` unless `String.prototype.trim` already exists. `pipe(a, f, g, h)` is data-first function application: any function that takes the previous step's output works, even ad-hoc ones you define inline.

