```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadNumber = { _tag: "BadNumber"; field: string; raw: string };
type OverLimit = { _tag: "OverLimit"; requested: number; approved: number };

const toNum = (field: string) => (s: string): E.Either<BadNumber, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadNumber", field, raw: s });
};

const withinLimit = (approved: number) => (requested: number): E.Either<OverLimit, number> =>
  requested <= approved ? E.right(approved - requested) : E.left({ _tag: "OverLimit", requested, approved });

export const headroom = (requested: string, approved: string): string =>
  pipe(
    toNum("approved")(approved),
    E.chainW((a) =>
      pipe(
        toNum("requested")(requested),
        E.chainW(withinLimit(a)),
      ),
    ),
    E.mapLeft((e) => e._tag === "BadNumber" ? `parse fail: ${e.field}` : `denied: ${e.requested}>${e.approved}`),
    E.fold((err) => err, (rem) => `remaining: ${rem}`),
  );
```

The inner `pipe` keeps the widened `BadNumber | OverLimit` union flowing while computing the dependent validation.

