```ts
import { Effect, Layer, Context } from "effect";

interface RedisConfig { readonly url: string }
const RedisConfig = Context.GenericTag<RedisConfig>("redis/Config");

interface Redis { readonly get: (k: string) => Effect.Effect<string | null>; readonly set: (k: string, v: string) => Effect.Effect<void> }
const Redis = Context.GenericTag<Redis>("redis/Redis");

interface SessionStore { readonly load: (uid: string) => Effect.Effect<string | null>; readonly save: (uid: string, data: string) => Effect.Effect<void> }
const SessionStore = Context.GenericTag<SessionStore>("app/SessionStore");

const RedisConfigLive = Layer.succeed(RedisConfig, { url: "redis://localhost:6379" });

// Redis depends on RedisConfig; scoped resource
const RedisLive = Layer.scoped(
  Redis,
  Effect.gen(function* () {
    const cfg = yield* RedisConfig;
    const conn = yield* Effect.acquireRelease(
      Effect.sync(() => ({ store: new Map<string, string>(), url: cfg.url })),
      (c) => Effect.sync(() => console.log(`close ${c.url}`))
    );
    return Redis.of({
      get: (k) => Effect.sync(() => conn.store.get(k) ?? null),
      set: (k, v) => Effect.sync(() => { conn.store.set(k, v); })
    });
  })
);

// SessionStore depends on Redis
const SessionStoreLive = Layer.effect(
  SessionStore,
  Effect.gen(function* () {
    const r = yield* Redis;
    return SessionStore.of({
      load: (uid) => r.get(`sess:${uid}`),
      save: (uid, data) => r.set(`sess:${uid}`, data)
    });
  })
);

const LiveLayer = Layer.mergeAll(RedisConfigLive, RedisLive, SessionStoreLive);

const program = Effect.gen(function* () {
  const sess = yield* SessionStore;
  yield* sess.save("u1", "{}");
  return yield* sess.load("u1");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`RedisLive` owns the scoped connection, `SessionStoreLive` wraps it; `Layer.mergeAll` pulls everything together for a single `Effect.provide`.

```ts
import { Effect, Data } from "effect";

class DlqError extends Data.TaggedError("DlqError")<{ readonly reason: string }> {}

export const withDlq =
  <A, E>(dlq: (err: E) => Effect.Effect<void, DlqError>) =>
  (eff: Effect.Effect<A, E>): Effect.Effect<A, E | DlqError> =>
    Effect.gen(function* () {
      const out = yield* Effect.either(eff);
      if (out._tag === "Right") return out.right;
      yield* dlq(out.left);
      return yield* Effect.fail(out.left);
    });

declare const saveRecord: (r: unknown) => Effect.Effect<void, Error>;
declare const publishDead: (e: Error) => Effect.Effect<void, DlqError>;

export const trySave = (r: unknown) => saveRecord(r).pipe(withDlq(publishDead));
```

The DLQ publish happens before re-failing, so observability is preserved without swallowing the error.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = { kind: 'parse' };
type NormErr = { kind: 'norm' };

const parse = (s: string): E.Either<ParseErr, string> =>
  s.trim().length > 0 ? E.right(s.trim()) : E.left({ kind: 'parse' });

const normalise = (s: string): E.Either<NormErr, string> =>
  /^[a-z0-9-]+$/.test(s) ? E.right(s) : E.left({ kind: 'norm' });

export const run = (input: string): string =>
  pipe(
    parse(input),
    E.chainW(normalise),
    E.match(
      (e) => `error:${e.kind}`,
      (ok) => `ok:${ok}`,
    ),
  );
```

`E.match` is `E.fold` by another name — both collapse `Either<E, A>` to a single `B` by handling both sides.

