```ts
import { Effect, Data, Ref, Clock } from "effect";

class RefreshError extends Data.TaggedError("RefreshError")<{ readonly cause: string }> {}

interface Token { readonly value: string; readonly expiresAtMs: number }

declare const refresh: () => Effect.Effect<Token, RefreshError>;

export const makeTokenSource = (initial: Token) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Token>(initial);
    const getValid = (): Effect.Effect<Token, RefreshError> =>
      Effect.gen(function* () {
        const now = yield* Clock.currentTimeMillis;
        const cur = yield* Ref.get(ref);
        if (cur.expiresAtMs > now + 30_000) return cur;
        const fresh = yield* refresh();
        yield* Ref.set(ref, fresh);
        return fresh;
      });
    return { getValid } as const;
  });
```

The 30-second skew prevents races where a token expires between "check" and "use".

`Layer.mergeAll(a, b, c)` is the variadic form of `Layer.merge(Layer.merge(a, b), c)` — semantically the same, but it reads cleanly for 3+ layers and the compiler infers a flatter requirement set.

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly url: string }
const Config = Context.GenericTag<Config>("app/Config");

interface Cache { readonly get: (k: string) => Effect.Effect<string | null> }
const Cache = Context.GenericTag<Cache>("app/Cache");

interface Db { readonly get: (k: string) => Effect.Effect<string> }
const Db = Context.GenericTag<Db>("app/Db");

const ConfigLive = Layer.succeed(Config, { url: "postgres://x" });

// Cache depends on Config
const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    yield* Config;
    const m = new Map<string, string>();
    return Cache.of({ get: (k) => Effect.sync(() => m.get(k) ?? null) });
  })
);

// Db depends on Config
const DbLive = Layer.effect(
  Db,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return Db.of({ get: (k) => Effect.succeed(`${cfg.url}:${k}`) });
  })
);

const LiveLayer = Layer.mergeAll(ConfigLive, CacheLive, DbLive);

const program = Effect.gen(function* () {
  const cache = yield* Cache;
  const db = yield* Db;
  const hit = yield* cache.get("a");
  return hit ?? (yield* db.get("a"));
});

export const runnable = Effect.provide(program, LiveLayer);
```

Use `mergeAll` whenever you have 3+ peers — it scales linearly in readability, not nested parentheses.

```ts
import { pipe } from "effect";

interface Product { readonly id: string; readonly price: number; readonly inStock: boolean }

// Method-chain form — fine for built-ins, but every stage must be a method on the array:
export const expensiveInStockIdsA = (ps: ReadonlyArray<Product>): ReadonlyArray<string> =>
  ps.filter((p) => p.inStock).filter((p) => p.price > 100).map((p) => p.id);

// pipe form — the stages can be ANY free function, not just methods on the carrier:
const inStock = <P extends { inStock: boolean }>(xs: ReadonlyArray<P>): ReadonlyArray<P> =>
  xs.filter((p) => p.inStock);
const expensive = <P extends { price: number }>(xs: ReadonlyArray<P>): ReadonlyArray<P> =>
  xs.filter((p) => p.price > 100);
const ids = (xs: ReadonlyArray<Product>): ReadonlyArray<string> => xs.map((p) => p.id);

export const expensiveInStockIdsB = (ps: ReadonlyArray<Product>): ReadonlyArray<string> =>
  pipe(ps, inStock, expensive, ids);
```

`pipe` generalises method chaining to any free function. The second form lets each stage live as a named, reusable, unit-testable function — the first locks you into whatever methods `Array` happens to expose.

