import { Effect, Fiber, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly page: number }> {}

interface Page { readonly n: number; readonly items: ReadonlyArray<string> }

declare const loadPage: (n: number) => Effect.Effect<Page, FetchError>;
declare const renderPage: (p: Page) => Effect.Effect<void>;

export const showWithPrefetch = (n: number): Effect.Effect<readonly [Page, Page], FetchError> =>
  Effect.gen(function* () {
    const prefetch = yield* Effect.fork(loadPage(n + 1));
    const current = yield* loadPage(n);
    yield* renderPage(current);
    const next = yield* Fiber.join(prefetch);
    return [current, next] as const;
  });
```

