```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

interface User { email?: string | null }

export const emailOf = (u: User | null | undefined): O.Option<string> =>
  pipe(
    O.fromNullable(u),
    O.chain((x) => O.fromNullable(x.email)),
  );
```

Swap `O.map` for `O.chain` whenever the step function itself returns an `Option`. `O.map` is for plain `A -> B`; `O.chain` flattens `A -> Option<B>` to avoid the nested wrapper.

Convert this throwing async function to fp-ts v2 TaskEither with proper error narrowing and a downstream `pipe` that extracts the name:
```ts
async function loadUser(id: string): Promise<User> {
  const res = await fetch(`/users/${id}`);
  if (!res.ok) throw new Error(`status ${res.status}`);
  return res.json();
}
```

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

interface User { readonly id: string; readonly name: string }

export interface LoadUserError {
  readonly _tag: 'LoadUserError';
  readonly message: string;
}

export const loadUser = (id: string): TE.TaskEither<LoadUserError, User> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(`/users/${id}`);
      if (!res.ok) throw new Error(`status ${res.status}`);
      return (await res.json()) as User;
    },
    (u): LoadUserError => ({
      _tag: 'LoadUserError',
      message: u instanceof Error ? u.message : String(u),
    })
  );

export const loadUserName = (id: string): TE.TaskEither<LoadUserError, string> =>
  pipe(loadUser(id), TE.map((u) => u.name));
```

The body of the thunk is unchanged — we just move the throw/catch responsibility to `TE.tryCatch` and narrow `unknown` into a typed domain error. The outer `pipe` proves the error channel survives composition.

```ts
import { Effect, Data, Console } from "effect";

class LogError extends Data.TaggedError("LogError")<{ readonly sink: string }> {}

declare const writeLine: (sink: string, line: string) => Effect.Effect<number, LogError>;

export const broadcast = (
  line: string,
  sinks: ReadonlyArray<string>
): Effect.Effect<void, LogError> =>
  Effect.all(
    sinks.map((s) => writeLine(s, line)),
    { concurrency: "unbounded", discard: true }
  ).pipe(Effect.tap(() => Console.log(`fanout done (${sinks.length})`)));
```

`discard: true` drops the per-fibre `number` results so the effect's success type collapses to `void`; the `LogError` channel is preserved untouched, and `Effect.tap` lets you observe completion without affecting the value.

`pipe(x, f, g, h)` is the smallest possible primitive that expresses sequential data-first composition. Every other fp-ts combinator — `map`, `chain`, `filter`, `ap` — is designed to slot into a pipe, because pipe-friendly APIs compose trivially without naming intermediate values. That consistency is why fp-ts calls `pipe` canonical.

```ts
import { pipe } from 'fp-ts/function';

const stripTags = (s: string): string => s.replace(/<[^>]*>/g, '');
const squashSpace = (s: string): string => s.replace(/\s+/g, ' ');
const trim = (s: string): string => s.trim();

export const sanitise = (raw: string): string =>
  pipe(raw, stripTags, squashSpace, trim);
```

```ts
import { Effect, Duration } from "effect";

type Status = { readonly state: "pending" | "ready"; readonly result?: string };

declare const fetchStatus: (jobId: string) => Effect.Effect<Status>;

export const pollUntilReady = (jobId: string): Effect.Effect<string> =>
  Effect.gen(function* () {
    while (true) {
      const s = yield* fetchStatus(jobId);
      if (s.state === "ready" && s.result !== undefined) return s.result;
      yield* Effect.sleep(Duration.seconds(1));
    }
  });
```

`while (true)` inside `Effect.gen` is safe — each iteration's `yield* Effect.sleep(...)` suspends the fiber, so nothing is busy-looping.

```ts
import { Effect, Data } from "effect";

interface Profile { readonly id: string; readonly name: string }
interface Preferences { readonly theme: string }
interface Order { readonly id: string; readonly total: number }

class ProfileMissing extends Data.TaggedError("ProfileMissing")<{ readonly id: string }> {}
class PrefsUnavailable extends Data.TaggedError("PrefsUnavailable")<{ readonly id: string }> {}
class OrdersUnavailable extends Data.TaggedError("OrdersUnavailable")<{ readonly id: string }> {}

declare const fetchProfile: (id: string) => Effect.Effect<Profile, ProfileMissing>;
declare const fetchPrefs: (id: string) => Effect.Effect<Preferences, PrefsUnavailable>;
declare const fetchOrders: (id: string) => Effect.Effect<ReadonlyArray<Order>, OrdersUnavailable>;

export const enrich = (
  id: string
): Effect.Effect<[Profile, Preferences, ReadonlyArray<Order>], ProfileMissing | PrefsUnavailable | OrdersUnavailable> =>
  Effect.gen(function* () {
    return yield* Effect.all(
      [fetchProfile(id), fetchPrefs(id), fetchOrders(id)] as const,
      { concurrency: "unbounded" }
    );
  });
```

Passing a tuple to `Effect.all` preserves per-position types in the success channel; `{ concurrency: "unbounded" }` runs all three in parallel, and any branch's failure cancels the rest while merging into the union `E` channel. The `Effect.gen` wrapper makes the parallel fan-out easy to extend with post-processing steps.

```ts
import { Effect, Data } from "effect";

interface Booking { readonly seat: string; readonly confirmed: boolean }

class SeatTaken extends Data.TaggedError("SeatTaken")<{ readonly seat: string }> {}
class CardExpired extends Data.TaggedError("CardExpired")<{ readonly last4: string }> {}
class GatewayTimeout extends Data.TaggedError("GatewayTimeout")<{ readonly ms: number }> {}

declare const reserveSeat: (seat: string) => Effect.Effect<void, SeatTaken>;
declare const confirm: (seat: string) => Effect.Effect<Booking, CardExpired | GatewayTimeout>;

export const book = (seat: string): Effect.Effect<Booking, SeatTaken> =>
  Effect.gen(function* () {
    yield* reserveSeat(seat);
    const booking = yield* confirm(seat).pipe(
      Effect.catchTags({
        CardExpired: () => Effect.succeed<Booking>({ seat, confirmed: false }),
        GatewayTimeout: () => Effect.succeed<Booking>({ seat, confirmed: false }),
      })
    );
    return booking;
  });
```

`Effect.catchTags` handles both payment tags at once; the outer effect retains only `SeatTaken` in its error channel because the payment failures are fully resolved.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Op = "add" | "sub" | "mul" | "div";
type Symbol = "+" | "-" | "*" | "/";

type BadOp = { _tag: "BadOp"; got: string };
type DivByZero = { _tag: "DivByZero" };

const parseOp = (s: string): E.Either<BadOp, Op> =>
  s === "add" || s === "sub" || s === "mul" || s === "div"
    ? E.right(s)
    : E.left({ _tag: "BadOp", got: s });

const toSymbol = (op: Op): Symbol =>
  op === "add" ? "+" : op === "sub" ? "-" : op === "mul" ? "*" : "/";

const guardDiv = (op: Op, rhs: number): E.Either<DivByZero, Op> =>
  op === "div" && rhs === 0 ? E.left({ _tag: "DivByZero" }) : E.right(op);

export const apply = (opStr: string, lhs: number, rhs: number): string =>
  pipe(
    parseOp(opStr),
    E.chainW((op) => guardDiv(op, rhs)),
    E.map((op) => {
      const s = toSymbol(op);
      const result = op === "add" ? lhs + rhs : op === "sub" ? lhs - rhs : op === "mul" ? lhs * rhs : lhs / rhs;
      return `${lhs}${s}${rhs}=${result}`;
    }),
    E.mapLeft((e) => `err:${e._tag}`),
    E.fold((err) => err, (expr) => expr),
  );
```

`E.chainW` widens `BadOp` to `BadOp | DivByZero`; both are flattened to a single `err:<tag>` string by `E.mapLeft`.

```ts
import { Effect, Data } from "effect";

class IndexError extends Data.TaggedError("IndexError")<{ readonly id: string }> {}

interface Doc { readonly id: string; readonly body: string }

declare const tokenize: (d: Doc) => Effect.Effect<ReadonlyArray<string>, IndexError>;
declare const embed: (toks: ReadonlyArray<string>) => Effect.Effect<Float32Array, IndexError>;
declare const write: (id: string, v: Float32Array) => Effect.Effect<void, IndexError>;

const indexOne = (d: Doc): Effect.Effect<void, IndexError> =>
  Effect.gen(function* () {
    const toks = yield* tokenize(d);
    const vec = yield* embed(toks);
    yield* write(d.id, vec);
  });

export const indexAll = (
  docs: ReadonlyArray<Doc>
): Effect.Effect<void, IndexError> =>
  Effect.all(docs.map(indexOne), {
    concurrency: "inherit",
    discard: true,
  });

// Caller selects the pool size for the whole region.
export const run = (docs: ReadonlyArray<Doc>) =>
  indexAll(docs).pipe(Effect.withConcurrency(8));
```

`concurrency: "inherit"` defers to whichever value `Effect.withConcurrency` has pushed onto the current region — the library never hard-codes a pool size.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

interface AuthError { readonly _tag: 'AuthError'; readonly reason: string }
interface ProfileError { readonly _tag: 'ProfileError'; readonly userId: string }
interface PrefsError { readonly _tag: 'PrefsError'; readonly userId: string }

type ApiError = AuthError | ProfileError | PrefsError;

declare const authenticate: () => TE.TaskEither<AuthError, string>;
declare const getProfile: (token: string) => TE.TaskEither<ProfileError, { id: string }>;
declare const getPrefs: (userId: string) => TE.TaskEither<PrefsError, { theme: string }>;

export const boot = (): TE.TaskEither<ApiError, { theme: string }> =>
  pipe(
    authenticate() as TE.TaskEither<ApiError, string>,
    TE.chainW((token) => getProfile(token)),
    TE.chainW((profile) => getPrefs(profile.id))
  );
