```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NotString = { _tag: "NotString"; got: string };
type Empty = { _tag: "Empty" };

const asString = (u: unknown): E.Either<NotString, string> =>
  typeof u === "string" ? E.right(u) : E.left({ _tag: "NotString", got: typeof u });

const nonEmpty = (s: string): E.Either<Empty, string> => {
  const t = s.trim();
  return t.length > 0 ? E.right(t) : E.left({ _tag: "Empty" });
};

export const normalise = (u: unknown): string =>
  pipe(
    asString(u),
    E.chainW(nonEmpty),
    E.map((s) => s.toLowerCase()),
    E.mapLeft((e) => `bad:${e._tag}`),
    E.fold((msg) => msg, (s) => s),
  );
```

`E.chainW` widens `NotString` to `NotString | Empty`. `E.map` handles the pure transform without touching the left.

```ts
import { Effect, Exit } from "effect";

interface SagaStep<E> {
  readonly name: string;
  readonly action: Effect.Effect<void, E>;
  readonly compensate: Effect.Effect<void>;
}

export const runSaga = <E>(
  steps: ReadonlyArray<SagaStep<E>>,
): Effect.Effect<void, E> =>
  Effect.gen(function* () {
    const done: SagaStep<E>[] = [];
    const exit = yield* Effect.exit(
      Effect.gen(function* () {
        for (const step of steps) {
          yield* step.action;
          done.push(step);
        }
      }),
    );
    if (Exit.isSuccess(exit)) return;
    for (const s of done.reverse()) {
      yield* Effect.orDie(s.compensate);
    }
    return yield* Effect.failCause(exit.cause);
  });
```

The inner `Effect.exit` isolates partial progress; compensations run on the reversed `done` list.

