```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type IdbError =
  | { readonly _tag: 'BlockedError'; readonly name: string }
  | { readonly _tag: 'OpenFailed'; readonly cause: unknown };

const BLOCKED = Symbol('idb-blocked');

const openDb = (name: string, version: number): Promise<IDBDatabase> =>
  new Promise((resolve, reject) => {
    const req = indexedDB.open(name, version);
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error ?? new Error('open failed'));
    req.onblocked = () => reject(BLOCKED);
  });

export const openSafe = (name: string, version: number): TE.TaskEither<IdbError, IDBDatabase> =>
  TE.tryCatch(
    () => openDb(name, version),
    (u): IdbError =>
      u === BLOCKED ? { _tag: 'BlockedError', name } : { _tag: 'OpenFailed', cause: u }
  );

export const openedVersion = (name: string, version: number): TE.TaskEither<IdbError, number> =>
  pipe(openSafe(name, version), TE.map((db) => db.version));
```

Promisifying the request API into a single promise makes `TE.tryCatch` straightforward — the narrower then only has to distinguish the blocked sentinel from generic failures.

