```ts
import { Effect, Fiber } from "effect";

declare const prefetchCatalog: Effect.Effect<ReadonlyArray<string>>;
declare const renderShell: Effect.Effect<void>;

export const boot: Effect.Effect<ReadonlyArray<string>> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(prefetchCatalog);
  yield* renderShell;
  const catalog = yield* Fiber.join(fiber);
  return catalog;
});
