```ts
import { pipe } from "fp-ts/function";

type AnyRec = Readonly<Record<string, unknown>>;

const rename =
  (map: Readonly<Record<string, string>>) =>
  (rec: AnyRec): AnyRec => {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(rec)) out[map[k] ?? k] = v;
    return out;
  };

const dropNulls = (rec: AnyRec): AnyRec => {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(rec)) if (v !== null && v !== undefined) out[k] = v;
  return out;
};

const freeze = <T extends object>(o: T): Readonly<T> => Object.freeze({ ...o });

export const cleanRecord = (rec: AnyRec): AnyRec =>
  pipe(rec, rename({ user_id: "userId", created_at: "createdAt" }), dropNulls, freeze);
```

Three stages. Currying `rename` keeps the pipeline's uniform shape — every stage goes `AnyRec -> AnyRec`, so they slot together without adapter functions.

```ts
import { Effect, Option } from "effect";
import { pipe } from "effect";

interface Config { readonly host: string; readonly port: number; readonly db: string; readonly region: string; readonly ttl: number }

class CfgError { readonly _tag = "CfgError" as const; constructor(readonly field: keyof Config, readonly msg: string) {} }

const str = (f: keyof Config, s: string): Effect.Effect<string, CfgError> =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(new CfgError(f, "required"));
const port = (n: number): Effect.Effect<number, CfgError> =>
  Number.isInteger(n) && n >= 1 && n <= 65535 ? Effect.succeed(n) : Effect.fail(new CfgError("port", "out of range"));
const ttl = (n: number): Effect.Effect<number, CfgError> =>
  Number.isFinite(n) && n > 0 ? Effect.succeed(n) : Effect.fail(new CfgError("ttl", "must be positive"));

export const validate = (c: Config): Effect.Effect<Config, ReadonlyArray<CfgError>> =>
  pipe(
    Effect.all(
      {
        host: str("host", c.host),
        port: port(c.port),
