import { Effect, Console, Fiber } from "effect";

interface Socket { readonly port: number }

const openSocket = Effect.sync((): Socket => ({ port: 9000 }));
const closeSocket = (s: Socket) => Console.log(`shutdown ${s.port}`);

const socket = Effect.acquireRelease(openSocket, (s) => closeSocket(s));

const serve = Effect.scoped(
  Effect.gen(function* () {
    const s = yield* socket;
    yield* Console.log(`listening on ${s.port}`);
    yield* Effect.never;
  })
);

const runWithInterrupt = Effect.gen(function* () {
  const fiber = yield* Effect.fork(serve);
  yield* Effect.sleep("20 millis");
  yield* Fiber.interrupt(fiber);
});

Effect.runPromise(runWithInterrupt);
```

`Effect.scoped` treats interruption like any other exit — the finalizer runs. That is why acquireRelease is safer than manual try/finally.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type ApiError =
  | { readonly _tag: 'NetworkError'; readonly cause: unknown }
  | { readonly _tag: 'ValidationError'; readonly field: string };

interface Widget { readonly id: string; readonly size: number }

const validate = (raw: unknown): TE.TaskEither<ApiError, Widget> => {
  if (typeof raw !== 'object' || raw === null) {
    return TE.left({ _tag: 'ValidationError', field: 'root' });
  }
  const r = raw as { id?: unknown; size?: unknown };
  if (typeof r.id !== 'string') return TE.left({ _tag: 'ValidationError', field: 'id' });
  if (typeof r.size !== 'number') return TE.left({ _tag: 'ValidationError', field: 'size' });
  return TE.right({ id: r.id, size: r.size });
};

export const loadWidget = (url: string): TE.TaskEither<ApiError, Widget> =>
  pipe(
    TE.tryCatch<ApiError, unknown>(
      async () => (await fetch(url)).json() as Promise<unknown>,
      (u) => ({ _tag: 'NetworkError', cause: u })
    ),
    TE.chain(validate)
  );
```

Parsing sits in its own `TE.chain` step so each failure mode maps to a distinct tag — the narrower above only deals with network-shaped errors.

