```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Questionnaire { answer: string; consent: boolean; submissionToken: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const answer = (s: string): E.Either<Errs, string> =>
  s.trim().length >= 10 ? E.right(s) : E.left([fe("answer", "need >= 10 chars")]);
const consent = (b: boolean): E.Either<Errs, boolean> =>
  b ? E.right(b) : E.left([fe("consent", "must consent")]);
const token = (s: string): E.Either<Errs, string> =>
  /^tok_[a-z0-9]{16,}$/.test(s) ? E.right(s) : E.left([fe("submissionToken", "bad token")]);

export const validateQuestionnaire = (
  q: Questionnaire
): E.Either<Errs, Questionnaire> =>
  pipe(
    sequenceT(V)(answer(q.answer), consent(q.consent), token(q.submissionToken)),
    E.map(([a, c, t]) => ({ answer: a, consent: c, submissionToken: t }))
  );
```

`sequenceT(V)` over the validation applicative is the minimum-surface change that turns three independent `Either<Errs, _>` checks into one `Either<Errs, [string, boolean, string]>` with concatenated errors.

