```ts
import { Effect, Data, Duration, Schedule } from "effect";

class RateLimit extends Data.TaggedError("RateLimit")<{ readonly retryMs: number }> {}
class AuthFailed extends Data.TaggedError("AuthFailed")<{}> {}

declare const call: () => Effect.Effect<string, RateLimit | AuthFailed>;

export const callWithBackoff: Effect.Effect<string, AuthFailed> = call().pipe(
  Effect.retry({
    schedule: Schedule.spaced(Duration.seconds(1)).pipe(Schedule.intersect(Schedule.recurs(3))),
    while: (e) => e._tag === "RateLimit",
  }),
  Effect.catchTag("RateLimit", () => Effect.succeed(""))
);
