import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Addr { country: string; postal: string; city: string }

type BadCountry = { _tag: "BadCountry"; got: string };
type MissingPostal = { _tag: "MissingPostal" };
type MissingCity = { _tag: "MissingCity" };

const COUNTRIES = new Set(["US", "CA", "DE", "FR", "JP", "UK"]);

const knownCountry = (a: Addr): E.Either<BadCountry, Addr> =>
  COUNTRIES.has(a.country) ? E.right(a) : E.left({ _tag: "BadCountry", got: a.country });

const hasPostal = (a: Addr): E.Either<MissingPostal, Addr> =>
  a.postal.trim().length > 0 ? E.right(a) : E.left({ _tag: "MissingPostal" });

const hasCity = (a: Addr): E.Either<MissingCity, Addr> =>
  a.city.trim().length > 0 ? E.right(a) : E.left({ _tag: "MissingCity" });

export const validateAddr = (a: Addr): string =>
  pipe(
    knownCountry(a),
    E.chainW(hasPostal),
    E.chainW(hasCity),
    E.mapLeft((e) => e._tag),
    E.match((tag) => `reject:${tag}`, (_ok) => "ship-ready"),
  );
```

Because `E.chainW` short-circuits on the first `E.left`, only the first failure propagates — the other validators are not run.

