import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type LoadErr = { _tag: 'LoadErr' };
type DecodeErr = { _tag: 'DecodeErr' };
type UseErr = { _tag: 'UseErr' };

const load = (key: string): E.Either<LoadErr, string> =>
  key.length > 0 ? E.right(`raw:${key}`) : E.left({ _tag: 'LoadErr' });

const decode = (raw: string): E.Either<DecodeErr, number> => {
  const n = Number.parseInt(raw.replace(/\D/g, ''), 10);
  return Number.isNaN(n) ? E.left({ _tag: 'DecodeErr' }) : E.right(n);
};

const use = (n: number): E.Either<UseErr, number> =>
  n > 0 ? E.right(n * 2) : E.left({ _tag: 'UseErr' });

export const run = (key: string): number =>
  pipe(
    load(key),
    E.chainW(decode),
    E.chainW(use),
    E.fold(
      () => -1,
      (n) => n,
    ),
  );
