import { Effect, Console } from "effect";

interface Reader { readonly path: string; readonly lines: readonly string[] }

const openReader = (path: string): Effect.Effect<Reader> =>
  Effect.sync(() => ({ path, lines: ["alpha", "beta", "gamma"] }));

const closeReader = (r: Reader) => Console.log(`closed ${r.path}`);

const reader = (path: string) =>
  Effect.acquireRelease(openReader(path), (r) => closeReader(r));

const readAll = (path: string) =>
  Effect.scoped(
    Effect.gen(function* () {
      const r = yield* reader(path);
      return r.lines.join("\n");
    })
  );

Effect.runPromise(readAll("/tmp/log.txt")).then(console.log);
