```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface OrderBody {
  customerId: string;
  items: ReadonlyArray<{ sku: string; qty: number }>;
  shippingAddress: string;
}

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const checkCustomer = (id: string): E.Either<Errs, string> =>
  /^cus_[a-z0-9]+$/.test(id) ? E.right(id) : E.left([fe("customerId", "must match cus_*")]);
const checkItems = (xs: ReadonlyArray<{ sku: string; qty: number }>): E.Either<Errs, typeof xs> =>
  xs.length > 0 ? E.right(xs) : E.left([fe("items", "must be non-empty")]);
const checkShipping = (s: string): E.Either<Errs, string> =>
  s.trim().length > 0 ? E.right(s) : E.left([fe("shippingAddress", "required")]);

export const validateOrderBody = (body: OrderBody): E.Either<Errs, OrderBody> =>
  sequenceS(V)({
    customerId: checkCustomer(body.customerId),
    items: checkItems(body.items),
    shippingAddress: checkShipping(body.shippingAddress),
  });
```

Every check is independent and returns its own `Left` when it fails; `sequenceS` over the validation applicative merges all failures into a `ReadonlyNonEmptyArray<FieldError>` so a partially-bad body still reports every problem in one response.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { sequenceT } from "fp-ts/Apply";

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;
const bad = (m: Err): V<never> => E.left([m] as RNEA.ReadonlyNonEmptyArray<Err>);

const longEnough = (s: string): V<string> => s.length >= 12 ? E.right(s) : bad("must be >= 12 chars");
const hasDigit = (s: string): V<string> => /\d/.test(s) ? E.right(s) : bad("must contain a digit");
const hasUpper = (s: string): V<string> => /[A-Z]/.test(s) ? E.right(s) : bad("must contain uppercase");
const hasSpecial = (s: string): V<string> => /[!@#$%^&*]/.test(s) ? E.right(s) : bad("must contain a special char");

const appVal = E.getApplicativeValidation(RNEA.getSemigroup<Err>());

export const validatePassword = (s: string): V<string> =>
  pipe(
    sequenceT(appVal)(longEnough(s), hasDigit(s), hasUpper(s), hasSpecial(s)),
    E.map(() => s),
  );

// validatePassword("abc") returns Left of four distinct errors.
```

