The middle `safe` shows what `catchTag` leaves typed (`Fatal`); the final `catchAll` collapses everything, but `safe` is the interesting intermediate — callers can still handle `Fatal` specifically if they prefer.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface Form { id: string; email: string; age: number }

type Err = { tag: 'id' } | { tag: 'email' } | { tag: 'age' };

const checkId = (f: Form): E.Either<Err, Form> =>
  f.id.length > 0 ? E.right(f) : E.left({ tag: 'id' });

const checkEmail = (f: Form): E.Either<Err, Form> =>
  f.email.includes('@') ? E.right(f) : E.left({ tag: 'email' });

const checkAge = (f: Form): E.Either<Err, Form> =>
  f.age >= 13 ? E.right(f) : E.left({ tag: 'age' });

export const summarise = (f: Form): string =>
  pipe(
    checkId(f),
    E.chain(checkEmail),
    E.chain(checkAge),
    E.match(
      (e) => `first-failure:${e.tag}`,
      () => 'all-valid',
    ),
  );
```

Short-circuit semantics mean only the first failing validator's tag surfaces. For all-errors accumulation, swap to `getApplicativeValidation`.

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly host: string }
interface Metrics { readonly inc: (key: string) => Effect.Effect<void> }

const Config = Context.GenericTag<Config>("app/Config");
const Metrics = Context.GenericTag<Metrics>("app/Metrics");

const ConfigLive = Layer.succeed(Config, { host: "localhost" });
const MetricsLive = Layer.effect(
  Metrics,
  Effect.succeed({ inc: (_: string) => Effect.void })
);

// Merge then provide once.
const AppLayer = Layer.merge(ConfigLive, MetricsLive);

const program = Effect.gen(function* () {
  const cfg = yield* Config;
  const m = yield* Metrics;
  yield* m.inc("start");
  return cfg.host;
});

export const runnable = Effect.provide(program, AppLayer);
```

One `Effect.provide` at the edge consumes both services in `R`; the inner program stays pure and polymorphic over layer choice.

Nested calls (`h(g(f(x)))`) force the reader to parse right-to-left: the data source is the innermost token and the final shape is the outermost. Past two levels, this inverts working memory — you have to hold the intermediate types upside-down. `pipe(x, f, g, h)` puts the seed first and every subsequent transform in data-flow order, so the reader can scan the pipeline like prose.

```ts
import { pipe } from "fp-ts/function";

interface DbUser { readonly id: number; readonly first_name: string; readonly last_name: string; readonly email: string | null }
interface Display { readonly id: number; readonly displayName: string; readonly contact: string }

const combineNames = (u: DbUser): DbUser & { full: string } => ({ ...u, full: `${u.first_name} ${u.last_name}`.trim() });
const resolveContact = <U extends DbUser>(u: U): U & { contact: string } => ({ ...u, contact: u.email ?? "(no email on file)" });
const toDisplay = (u: DbUser & { full: string; contact: string }): Display => ({ id: u.id, displayName: u.full, contact: u.contact });

export const toDisplayModel = (row: DbUser): Display =>
  pipe(row, combineNames, resolveContact, toDisplay);
```

Three stages, each additive, each named. A nested form — `toDisplay(resolveContact(combineNames(row)))` — works fine at three but becomes a traversal exercise at six.

```ts
import { Effect } from "effect";

declare const loadCount: () => Effect.Effect<number>;
declare const loadName: () => Effect.Effect<string>;
declare const loadFlag: () => Effect.Effect<boolean>;

export const combined: Effect.Effect<[number, string, boolean]> =
  Effect.gen(function* () {
    return yield* Effect.all(
      [loadCount(), loadName(), loadFlag()] as const,
      { concurrency: "unbounded" }
    );
  });

// Sequential equivalent — same success type, different scheduling.
