  if (i.bytes > 10_000_000) return Effect.fail(new TooLarge({ bytes: i.bytes }));
  if (!i.mime.startsWith("image/")) return Effect.fail(new BadType({ mime: i.mime }));
  return Effect.succeed(i);
};

const send = (_i: UploadInput): Effect.Effect<string, UploadFailed> =>
  Effect.succeed("uploaded");

export const upload = (i: UploadInput): Effect.Effect<string, TooLarge | BadType | UploadFailed> =>
  validate(i).pipe(Effect.flatMap(send));

export const handled: Effect.Effect<string, UploadFailed> = upload({ bytes: 99, mime: "image/png" }).pipe(
  Effect.catchTag("TooLarge", (e) => Effect.succeed(`reject:${e.bytes}`)),
  Effect.catchTag("BadType", (e) => Effect.succeed(`reject:${e.mime}`))
);
