```ts
import { Effect, Duration, Data } from "effect";

export class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly ms: number }> {}

export const withTimeout = <A, E, R>(
  effect: Effect.Effect<A, E, R>,
  ms: number
): Effect.Effect<A, E | TimeoutError, R> =>
  Effect.race(
