```ts
import { Effect, Data } from "effect";

class IngestError extends Data.TaggedError("IngestError")<{ readonly id: string }> {}

declare const ingest: (id: string) => Effect.Effect<void, IngestError>;

// Parallel variant — every id ingested at once.
export const ingestAll = (
  ids: ReadonlyArray<string>
): Effect.Effect<void, IngestError> =>
  Effect.gen(function* () {
    yield* Effect.all(ids.map(ingest), { concurrency: "unbounded", discard: true });
  });

// Kept around as a safer fallback.
export const ingestAllSerial = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<void>, IngestError> =>
  Effect.all(ids.map(ingest));
```

Downside of `"unbounded"`: if the downstream service is rate-limited or the list is very large, you can flood it and all fibres fail simultaneously. A numeric `concurrency` such as `{ concurrency: 8 }` is usually the safer production default.

`Brand.nominal<T>()` is a zero-runtime-cost identity function — it trusts the caller that the value already satisfies whatever invariant the name implies. `Brand.refined<T>(pred, onErr)` runs `pred` at construction and emits a `Brand.BrandErrors` on failure.

Use `nominal` when the invariant is enforced elsewhere (parser, DB constraint, prior validation). Use `refined` when this call site is the first place the invariant is checked.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type SessionId = string & Brand.Brand<"SessionId">;
export const SessionId = Brand.nominal<SessionId>();

export type Email = string & Brand.Brand<"Email">;
export const Email = Brand.refined<Email>(
  (s) => s.includes("@") && s.length <= 254,
  (s) => Brand.error(`Bad email: ${s}`),
);

export const parseEmail = (raw: string): Effect.Effect<Email, Brand.Brand.BrandErrors> =>
  pipe(
    Email.either(raw),
    (r) => r._tag === "Right" ? Effect.succeed(r.right) : Effect.fail(r.left),
  );
```

