```typescript
import { Effect, Data } from "effect";

class EmptyField extends Data.TaggedError("EmptyField")<{ readonly field: string }> {}
class BadEmail extends Data.TaggedError("BadEmail")<{ readonly value: string }> {}

interface Signup { readonly name: string; readonly email: string }

const nonEmpty = (field: string, value: string): Effect.Effect<string, EmptyField> =>
  value.trim().length > 0 ? Effect.succeed(value) : Effect.fail(new EmptyField({ field }));

const validEmail = (value: string): Effect.Effect<string, BadEmail> =>
  value.includes("@") ? Effect.succeed(value) : Effect.fail(new BadEmail({ value }));

export const validate = (raw: Signup): Effect.Effect<Signup, EmptyField | BadEmail> =>
  Effect.gen(function* () {
    const name = yield* nonEmpty("name", raw.name);
    const email = yield* nonEmpty("email", raw.email);
    const okEmail = yield* validEmail(email);
    return { name, email: okEmail };
  });
```

Each validator returns an `Effect<A, TaggedError>`; composing them in `Effect.gen` unions the error channel to `EmptyField | BadEmail`, which `catchTag` can later discriminate.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type SdkError =
  | { readonly _tag: 'RateLimited'; readonly retryAfterMs: number }
  | { readonly _tag: 'SdkFailure'; readonly cause: unknown };

interface RawSdkError { readonly code?: string; readonly retryAfter?: number }

const isRateLimited = (u: unknown): u is RawSdkError =>
  typeof u === 'object' && u !== null && (u as RawSdkError).code === 'RATE_LIMITED';

declare const sdk: { call: <A>(op: string) => Promise<A> };

export const callSdk = <A>(op: string): TE.TaskEither<SdkError, A> =>
  TE.tryCatch(
    () => sdk.call<A>(op),
    (u): SdkError =>
      isRateLimited(u)
        ? { _tag: 'RateLimited', retryAfterMs: (u.retryAfter ?? 1) * 1000 }
        : { _tag: 'SdkFailure', cause: u }
  );

export const listUsers = (): TE.TaskEither<SdkError, ReadonlyArray<string>> =>
  pipe(
    callSdk<ReadonlyArray<{ name: string }>>('listUsers'),
    TE.map((xs) => xs.map((x) => x.name))
  );
```

A type guard keeps the narrowing logic reusable — callers never touch raw SDK error shapes.

```ts
import { Effect, Data } from "effect";

interface Order { readonly id: string; readonly total: number }
interface Shipment { readonly trackingId: string }

class OutOfStock extends Data.TaggedError("OutOfStock")<{ readonly sku: string }> {}
class PaymentDeclined extends Data.TaggedError("PaymentDeclined")<{ readonly card: string }> {}
class ShippingUnavailable extends Data.TaggedError("ShippingUnavailable")<{ readonly zip: string }> {}

declare const reserve: (sku: string) => Effect.Effect<Order, OutOfStock>;
declare const charge: (o: Order, card: string) => Effect.Effect<void, PaymentDeclined>;
declare const ship: (o: Order, zip: string) => Effect.Effect<Shipment, ShippingUnavailable>;

const altCard = "alt-4242";

export const checkout = (
  sku: string,
  card: string,
  zip: string
): Effect.Effect<Shipment, OutOfStock | ShippingUnavailable> =>
  Effect.gen(function* () {
    const order = yield* reserve(sku);
    yield* charge(order, card).pipe(
      Effect.catchTag("PaymentDeclined", () => charge(order, altCard)),
      Effect.catchTag("PaymentDeclined", () => Effect.void)
    );
    const shipment = yield* ship(order, zip);
    return shipment;
  });
```

The inner `catchTag` retries on an alt card; a second pass erases any remaining `PaymentDeclined` so only `OutOfStock | ShippingUnavailable` survives to the outer signature.

```ts
import { Effect, Context, Layer } from "effect";

interface Inner { readonly kind: "inner" }
interface Outer { readonly kind: "outer" }

const Inner = Context.GenericTag<Inner>("app/Inner");
const Outer = Context.GenericTag<Outer>("app/Outer");

const InnerLive = Layer.succeed(Inner, { kind: "inner" });
const OuterLive = Layer.succeed(Outer, { kind: "outer" });

// v3: Layer.provide takes (inner, deps) positionally.
const WiredOuter = Layer.provide(OuterLive, InnerLive);

const program = Effect.gen(function* () {
  const o = yield* Outer;
  return o.kind;
});

// v3: Effect.provide, not Effect.provideLayer.
export const runnable = Effect.provide(program, WiredOuter);
```

Both `Layer.provide` and `Effect.provide` take their arguments positionally in v3; the `provideLayer` name is gone.

```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface FlagConfig { name: string; rolloutPct: number; enabled: boolean }

const name = (s: string): Effect.Effect<string, FieldError> =>
  /^[a-z][a-z0-9_]*$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("name", "snake_case only"));
const rollout = (n: number): Effect.Effect<number, FieldError> =>
  n >= 0 && n <= 100 ? Effect.succeed(n) : Effect.fail(fe("rolloutPct", "0..100"));
const enabled = (b: boolean): Effect.Effect<boolean, FieldError> =>
  typeof b === "boolean" ? Effect.succeed(b) : Effect.fail(fe("enabled", "bool required"));

export const validateFlag = (
  c: FlagConfig
): Effect.Effect<FlagConfig, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [n, r, e] = yield* Effect.all([
      Effect.either(name(c.name)),
      Effect.either(rollout(c.rolloutPct)),
      Effect.either(enabled(c.enabled)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(n)) errs.push(n.left);
    if (Either.isLeft(r)) errs.push(r.left);
    if (Either.isLeft(e)) errs.push(e.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return c;
  });
```

No schema library required: `Effect.either` reifies each field failure as an `Either`, `Effect.all` runs them all without short-circuiting, and we collect every `Left` into the `ReadonlyArray<FieldError>` error channel.

```ts
import { pipe } from "effect";

interface Config { readonly host: string; readonly port: number; readonly debug: boolean }

const DEFAULTS: Config = { host: "localhost", port: 8080, debug: false };

const applyEnv = (env: Readonly<Record<string, string | undefined>>) => (cfg: Config): Config => ({
  ...cfg,
  host: env.APP_HOST ?? cfg.host,
  port: env.APP_PORT !== undefined ? Number(env.APP_PORT) : cfg.port,
  debug: env.APP_DEBUG !== undefined ? env.APP_DEBUG === "1" : cfg.debug,
});

const applyFlags = (flags: Partial<Config>) => (cfg: Config): Config => ({
  ...cfg,
  ...flags,
});

const freeze = (cfg: Config): Readonly<Config> => Object.freeze({ ...cfg });

export const loadConfig = (
  env: Readonly<Record<string, string | undefined>>,
  flags: Partial<Config>,
): Readonly<Config> =>
  pipe(DEFAULTS, applyEnv(env), applyFlags(flags), freeze);
```

The overlay order is visible on the page: defaults first, then env, then flags. Layering with nested calls — `freeze(applyFlags(flags)(applyEnv(env)(DEFAULTS)))` — would obscure which source wins.

```ts
import { Effect, Duration, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly url: string }> {}

interface Body { readonly text: string }

declare const get: (url: string) => Effect.Effect<Body, HttpError>;

export const hedged = (
  url: string,
  hedgeAfter = 50
): Effect.Effect<Body, HttpError> =>
  Effect.race(
    get(url),
    Effect.sleep(Duration.millis(hedgeAfter)).pipe(
      Effect.flatMap(() => get(url))
    )
  );
```

The first request starts immediately; the second is delayed by `hedgeAfter` ms so we don't double the load on fast responses. Whichever finishes first wins and the runtime interrupts the slower fiber — on a slow first request the hedge wins and the original is cancelled.

```ts
import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: () => number }
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Counter { readonly tick: () => Effect.Effect<number> }
const Counter = Context.GenericTag<Counter>("app/Counter");

// Pure value — Layer.succeed.
const ClockLive = Layer.succeed(Clock, { now: () => Date.now() });

// Effectful construction (allocate a closure over a mutable ref) — Layer.effect.
const CounterLive = Layer.effect(
  Counter,
  Effect.sync(() => {
    let n = 0;
    return { tick: () => Effect.sync(() => ++n) };
  })
);

export const BaseLayer = Layer.merge(ClockLive, CounterLive);
```

`Layer.succeed` takes a ready value; `Layer.effect` takes an `Effect` that produces the service — use it when construction needs I/O, allocation, or other effects.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const notEmpty = (s: string): O.Option<string> =>
  s.length > 0 ? O.some(s) : O.none;

export const resolveId = (id: string | null | undefined): string =>
  pipe(
    O.fromNullable(id),
    O.map((x) => x.trim()),
    O.chain(notEmpty),
    O.getOrElse<string>(() => {
      console.warn('[resolveId] falling back to guest');
      return 'guest';
    }),
  );
```

The logging lives inside the `getOrElse` thunk — it only fires on the `None` branch, and the pipeline's return type stays `string`.

```ts
import { Effect, Duration, Data } from "effect";

class ConnectError extends Data.TaggedError("ConnectError")<{ readonly host: string }> {}
class AuthError extends Data.TaggedError("AuthError")<{ readonly user: string }> {}
class PhaseTimeout extends Data.TaggedError("PhaseTimeout")<{ readonly phase: string; readonly ms: number }> {}

interface Session { readonly id: string }

declare const connect: (host: string) => Effect.Effect<{ readonly sock: string }, ConnectError>;
declare const authenticate: (sock: string, user: string) => Effect.Effect<Session, AuthError>;

const phaseTimeout = (phase: string, ms: number): Effect.Effect<never, PhaseTimeout> =>
  Effect.sleep(Duration.millis(ms)).pipe(
    Effect.flatMap(() => Effect.fail(new PhaseTimeout({ phase, ms })))
  );

export const login = (
  host: string,
  user: string
): Effect.Effect<Session, ConnectError | AuthError | PhaseTimeout> =>
  Effect.gen(function* () {
    const { sock } = yield* Effect.race(connect(host), phaseTimeout("connect", 1000));
    const session = yield* Effect.race(authenticate(sock, user), phaseTimeout("auth", 500));
    return session;
  });
```

Each phase has an independent deadline; if the connect timeout fires, the `authenticate` step is never reached. Losers in each race are interrupted, so an in-flight socket handshake or auth request is cancelled before the typed `PhaseTimeout` surfaces.

When an effect is interrupted (timeout, race loser, manual `Fiber.interrupt`), Effect runs each registered finalizer on the way out. `Effect.scoped` guarantees the finalizer runs regardless of exit reason — success, typed failure, defect, or interruption.

```ts
import { Effect, Console, Fiber } from "effect";

interface Session { readonly id: string }

const open = Effect.sync((): Session => ({ id: `s-${Date.now()}` }));
const close = (s: Session) => Console.log(`[closed] ${s.id}`);

const session = Effect.acquireRelease(open, (s) => close(s));

const run = Effect.gen(function* () {
  const fiber = yield* Effect.fork(
    Effect.scoped(
      Effect.gen(function* () {
        const s = yield* session;
        yield* Console.log(`[use] ${s.id}`);
        yield* Effect.never;
      })
    )
  );
  yield* Effect.sleep("15 millis");
  yield* Fiber.interrupt(fiber);
});

Effect.runPromise(run);
```

```ts
import { Effect, Layer, Context } from "effect";

interface Config { readonly gatewayUrl: string; readonly fraudThreshold: number }
const Config = Context.GenericTag<Config>("pay/Config");

interface CardGateway { readonly charge: (amount: number) => Effect.Effect<string> }
const CardGateway = Context.GenericTag<CardGateway>("pay/CardGateway");

interface FraudCheck { readonly score: (amount: number) => Effect.Effect<number> }
const FraudCheck = Context.GenericTag<FraudCheck>("pay/FraudCheck");

interface Payments { readonly process: (amount: number) => Effect.Effect<string> }
const Payments = Context.GenericTag<Payments>("pay/Payments");

const ConfigLive = Layer.succeed(Config, { gatewayUrl: "https://gw", fraudThreshold: 0.9 });

// CardGateway depends on Config
const CardGatewayLive = Layer.effect(
  CardGateway,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return CardGateway.of({ charge: (n) => Effect.succeed(`${cfg.gatewayUrl}:${n}`) });
  })
);

// FraudCheck depends on Config
const FraudCheckLive = Layer.effect(
  FraudCheck,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return FraudCheck.of({ score: (n) => Effect.succeed(Math.min(n / 1000, cfg.fraudThreshold)) });
  })
);

// Payments depends on CardGateway and FraudCheck
const PaymentsLive = Layer.effect(
  Payments,
  Effect.gen(function* () {
    const gw = yield* CardGateway;
    const fc = yield* FraudCheck;
    return Payments.of({
      process: (amount) => Effect.gen(function* () {
        const s = yield* fc.score(amount);
        if (s >= 0.9) return "blocked";
        return yield* gw.charge(amount);
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(ConfigLive, CardGatewayLive, FraudCheckLive, PaymentsLive);

const program = Effect.gen(function* () {
  const pay = yield* Payments;
  return yield* pay.process(50);
});

export const runnable = Effect.provide(program, LiveLayer);
```

Each consumer lists its dependencies via `yield*`; `Layer.mergeAll` collapses them because `Config` is resolved by `ConfigLive` present in the bundle.

