```ts
import { Effect, Duration, Data } from "effect";

class ComputeError extends Data.TaggedError("ComputeError")<{ readonly stage: string }> {}

declare const exactResult: Effect.Effect<number, ComputeError>;
declare const approxResult: Effect.Effect<number, ComputeError>;

export const anytime = (
  graceMs: number
): Effect.Effect<number, ComputeError> =>
  Effect.race(
    exactResult,
    Effect.sleep(Duration.millis(graceMs)).pipe(
      Effect.flatMap(() => approxResult)
    )
  );
```

The exact computation starts immediately; after `graceMs` the approximation is launched. Whichever finishes first wins and the loser is interrupted — so if the exact answer completes within the grace period it wins without ever starting the approximation.

```ts
import { Effect } from "effect";

interface User { readonly id: string }
interface Order { readonly total: number }
interface Prefs { readonly theme: "light" | "dark" }

const fetchUser = (id: string): Effect.Effect<User, Error> =>
  Effect.succeed({ id });
const fetchOrders = (id: string): Effect.Effect<ReadonlyArray<Order>, Error> =>
  Effect.succeed([{ total: 10 }]);
const fetchPrefs = (id: string): Effect.Effect<Prefs, Error> =>
  Effect.succeed({ theme: "dark" });

export const loadAll = (id: string): Effect.Effect<
  readonly [User, ReadonlyArray<Order>, Prefs],
  Error
> =>
  Effect.all(
    [fetchUser(id), fetchOrders(id), fetchPrefs(id)],
    { concurrency: "unbounded" },
  );
```

`E.chain` / `E.chainW` is bind for `Either`: on `Right(a)` it runs your function `a -> Either<E', B>` and returns its result; on `Left(e)` it short-circuits. `E.chainW` is the widening form that lets each step have its own error type and unions them in the result.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = 'parse';
type DivZero = 'divzero';

const num = (s: string): E.Either<ParseErr, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left('parse') : E.right(n);
};

const safeDiv = (a: number, b: number): E.Either<DivZero, number> =>
  b === 0 ? E.left('divzero') : E.right(a / b);

export const divide = (
  a: string,
  b: string,
): E.Either<ParseErr | DivZero, number> =>
  pipe(
    num(a),
    E.chainW((x) => pipe(num(b), E.chainW((y) => safeDiv(x, y)))),
  );
```

