```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Form { username: string; email: string; age: number; terms: boolean }
interface Registration { username: string; email: string; age: number }

type BadUsername = { _tag: "BadUsername" };
type BadEmail = { _tag: "BadEmail" };
type Underage = { _tag: "Underage"; age: number };
type TermsNotAccepted = { _tag: "TermsNotAccepted" };

const okUsername = (f: Form): E.Either<BadUsername, Form> =>
  /^[A-Za-z0-9_]{3,20}$/.test(f.username) ? E.right(f) : E.left({ _tag: "BadUsername" });

const okEmail = (f: Form): E.Either<BadEmail, Form> =>
  /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(f.email) ? E.right(f) : E.left({ _tag: "BadEmail" });

const adult = (f: Form): E.Either<Underage, Form> =>
  f.age >= 18 ? E.right(f) : E.left({ _tag: "Underage", age: f.age });

const accepted = (f: Form): E.Either<TermsNotAccepted, Form> =>
  f.terms ? E.right(f) : E.left({ _tag: "TermsNotAccepted" });

export const register = (form: Form): E.Either<string, Registration> =>
  pipe(
    okUsername(form),
    E.chainW(okEmail),
    E.chainW(adult),
    E.chainW(accepted),
    E.map((f) => ({ username: f.username, email: f.email, age: f.age })),
    E.mapLeft((e) => e._tag),
    E.match(
      (tag) => E.left<string, Registration>(tag),
      (r) => E.right<string, Registration>(r),
    ),
  );
```

Four `E.chainW` steps build a widened `BadUsername | BadEmail | Underage | TermsNotAccepted`; `E.mapLeft` projects the discriminator, then `E.match` rewraps for the caller.

