```ts
import { Effect, Data, Exit } from "effect";

class NoDelivery extends Data.TaggedError("NoDelivery")<{ readonly failures: ReadonlyArray<string> }> {}

interface Subscriber { readonly id: string }

declare const deliver: (s: Subscriber, msg: string) => Effect.Effect<void, Error>;

export const broadcast = (
  subs: ReadonlyArray<Subscriber>,
  msg: string,
): Effect.Effect<number, NoDelivery> =>
  Effect.gen(function* () {
    let ok = 0;
    const failed: string[] = [];
    for (const s of subs) {
      const exit = yield* Effect.exit(deliver(s, msg));
      if (Exit.isSuccess(exit)) ok += 1;
      else failed.push(s.id);
    }
    if (ok === 0) return yield* Effect.fail(new NoDelivery({ failures: failed }));
    return ok;
  });
```

```ts
import { pipe } from "effect";

interface PreparedRequest { readonly url: string; readonly method: "GET" }

const forceHttps = (url: string): string =>
  url.startsWith("http://") ? "https://" + url.slice(7) : url.startsWith("https://") ? url : "https://" + url;

const appendParams =
  (params: Record<string, string>) =>
  (url: string): string => {
    const qs = new URLSearchParams(params).toString();
    return qs.length === 0 ? url : url + (url.includes("?") ? "&" : "?") + qs;
  };

const toRequest = (url: string): PreparedRequest => ({ url, method: "GET" });

export const buildRequest = (raw: string, params: Record<string, string>): PreparedRequest =>
  pipe(raw, forceHttps, appendParams(params), toRequest);
```

Currying `appendParams` lets it fit the uniform `A -> B` shape pipe expects. Three stages, each reading as a single verb of intent.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface SignUp { email: string; password: string }

const checkEmail = (s: SignUp): E.Either<string, SignUp> =>
  s.email.includes('@') ? E.right(s) : E.left('bad email');

const checkPassword = (s: SignUp): E.Either<string, SignUp> =>
  s.password.length >= 8 ? E.right(s) : E.left('short password');

const checkDistinct = (s: SignUp): E.Either<string, SignUp> =>
  s.email !== s.password ? E.right(s) : E.left('email=password');

export const describe = (s: SignUp): string =>
  pipe(
    checkEmail(s),
    E.chain(checkPassword),
    E.chain(checkDistinct),
    E.fold(
      (err) => `rejected: ${err}`,
      () => 'accepted',
    ),
  );
```

All the validators share `string` as their error type here, so plain `E.chain` is enough — use `E.chainW` only when the error types differ.

```ts
import { Effect, Fiber, Console } from "effect";

const heartbeat = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("♥");
    yield* Effect.sleep("40 millis");
  })
);

const mainTask: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("130 millis");
  return "main done";
});

const program = Effect.gen(function* () {
  const hb = yield* Effect.fork(heartbeat);
  const result = yield* mainTask;
  yield* Fiber.interrupt(hb);
  return result;
});

Effect.runPromise(program).then(console.log);
```

The heartbeat fibre is explicitly interrupted; even if we forgot, the supervised fork would be cleaned up when the program exits.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadNum = { _tag: "BadNum"; field: string; raw: string };
type BadRate = { _tag: "BadRate"; rate: number };

const parseNum = (field: string) => (s: string): E.Either<BadNum, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadNum", field, raw: s });
};

const rateInRange = (n: number): E.Either<BadRate, number> =>
  n >= 0 && n <= 1 ? E.right(n) : E.left({ _tag: "BadRate", rate: n });

export const totalWithTax = (subRaw: string, rateRaw: string): string =>
  pipe(
    parseNum("sub")(subRaw),
    E.chainW((sub) =>
      pipe(
        parseNum("rate")(rateRaw),
        E.chainW(rateInRange),
        E.map((rate) => sub * (1 + rate)),
      ),
    ),
    E.map((t) => Math.round(t * 100) / 100),
    E.mapLeft((e) => e._tag === "BadNum" ? `bad ${e.field}` : `rate ${e.rate}`),
    E.fold((err) => `ERR: ${err}`, (total) => `$${total.toFixed(2)}`),
  );
```

The inner `pipe` keeps validations on `rate` local; the outer `E.chainW` then joins them to `sub` with the widened `BadNum | BadRate` union.

