import { Effect, Layer, Context } from "effect";

interface Config { readonly taxRate: number }
const Config = Context.GenericTag<Config>("shop/Config");

interface CartStore { readonly items: (id: string) => Effect.Effect<ReadonlyArray<string>> }
const CartStore = Context.GenericTag<CartStore>("shop/CartStore");

interface Inventory { readonly reserve: (items: ReadonlyArray<string>) => Effect.Effect<boolean> }
const Inventory = Context.GenericTag<Inventory>("shop/Inventory");

interface PricingEngine { readonly total: (items: ReadonlyArray<string>) => Effect.Effect<number> }
const PricingEngine = Context.GenericTag<PricingEngine>("shop/PricingEngine");

interface CheckoutService { readonly checkout: (cartId: string) => Effect.Effect<{ reserved: boolean; total: number }> }
const CheckoutService = Context.GenericTag<CheckoutService>("shop/CheckoutService");

const ConfigLive = Layer.succeed(Config, { taxRate: 0.08 });
const CartStoreLive = Layer.succeed(CartStore, {
  items: (id) => Effect.succeed([`sku-${id}-a`, `sku-${id}-b`])
});

// Inventory depends on CartStore and Config
const InventoryLive = Layer.effect(
  Inventory,
  Effect.gen(function* () {
    yield* CartStore;
    yield* Config;
    return Inventory.of({ reserve: (items) => Effect.succeed(items.length > 0) });
  })
);

// PricingEngine depends on Config
const PricingEngineLive = Layer.effect(
  PricingEngine,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return PricingEngine.of({
      total: (items) => Effect.succeed(items.length * 10 * (1 + cfg.taxRate))
    });
  })
);

// CheckoutService depends on Inventory + PricingEngine
const CheckoutServiceLive = Layer.effect(
  CheckoutService,
  Effect.gen(function* () {
    const inv = yield* Inventory;
    const price = yield* PricingEngine;
    const cart = yield* CartStore;
    return CheckoutService.of({
      checkout: (cartId) => Effect.gen(function* () {
        const items = yield* cart.items(cartId);
        const reserved = yield* inv.reserve(items);
        const total = yield* price.total(items);
        return { reserved, total };
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(
  ConfigLive,
  CartStoreLive,
  InventoryLive,
  PricingEngineLive,
  CheckoutServiceLive
);

const program = Effect.gen(function* () {
  const co = yield* CheckoutService;
  return yield* co.checkout("c1");
});

export const runnable = Effect.provide(program, LiveLayer);
```

The diamond dependency (Inventory and PricingEngine both need Config) resolves via `Layer.mergeAll` — Effect caches the single `ConfigLive` for all consumers.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface Raw { name?: unknown; age?: unknown }
interface Person { name: string; age: number }

const decode = (u: unknown): E.Either<{ code: 'decode' }, Raw> =>
  typeof u === 'object' && u !== null
    ? E.right(u as Raw)
    : E.left({ code: 'decode' });

const validate = (r: Raw): E.Either<{ code: 'validate'; field: string }, Person> => {
  if (typeof r.name !== 'string') return E.left({ code: 'validate', field: 'name' });
  if (typeof r.age !== 'number') return E.left({ code: 'validate', field: 'age' });
  return E.right({ name: r.name, age: r.age });
};

const persist = (p: Person): E.Either<{ code: 'persist' }, Person> =>
  p.age >= 0 ? E.right(p) : E.left({ code: 'persist' });

export const save = (input: unknown): E.Either<string, Person> =>
  pipe(
    decode(input),
    E.chainW(validate),
    E.chainW(persist),
    E.mapLeft((e) => `failed:${e.code}`),
  );
```

`E.chainW` lets each step keep its own tagged error; `E.mapLeft` collapses the union to a single string at the edge.

