```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type PostError =
  | { readonly _tag: 'NetworkError'; readonly cause: unknown }
  | { readonly _tag: 'ParseError'; readonly body: string };

interface RawResponse { readonly raw: string; readonly ok: boolean }

const send = (url: string, payload: unknown): TE.TaskEither<PostError, RawResponse> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(url, {
        method: 'POST',
        body: JSON.stringify(payload),
        headers: { 'content-type': 'application/json' },
      });
      return { raw: await res.text(), ok: res.ok };
    },
    (u): PostError => ({ _tag: 'NetworkError', cause: u })
  );

const parse = (r: RawResponse): TE.TaskEither<PostError, unknown> =>
  TE.tryCatch(
    async () => JSON.parse(r.raw) as unknown,
    (): PostError => ({ _tag: 'ParseError', body: r.raw })
  );

export const postJson = (url: string, payload: unknown): TE.TaskEither<PostError, unknown> =>
  pipe(send(url, payload), TE.chain(parse));
```

Two `TE.tryCatch` blocks — one per distinct failure class — keeps each narrower small and focused on a single error tag.

