import { Effect, Console, Duration } from "effect";

interface Reader { readonly path: string }

const openR = (p: string) => Effect.sync((): Reader => ({ path: p }));
const closeR = (r: Reader) => Console.log(`[reader] closed ${r.path}`);

const reader = (p: string) =>
  Effect.acquireRelease(openR(p), (r) => closeR(r));

const slowRead = (r: Reader) =>
  Effect.gen(function* () {
    yield* Effect.sleep("500 millis");
    return `data from ${r.path}`;
  });

const guarded = Effect.timeout(
  Effect.scoped(
    Effect.gen(function* () {
      const r = yield* reader("/tmp/slow.txt");
      return yield* slowRead(r);
    })
  ),
  Duration.millis(100)
);

Effect.runPromise(Effect.either(guarded)).then(console.log);
```

When the timeout fires, the scoped block is interrupted — Scope still runs the reader's close.

