interface Profile { readonly id: string; readonly name: string }
interface Prefs { readonly theme: "light" | "dark" }

class ProfileError { readonly _tag = "ProfileError" as const; constructor(readonly id: string) {} }
class PrefsError { readonly _tag = "PrefsError" as const; constructor(readonly id: string) {} }

declare const fetchProfile: (id: string) => Effect.Effect<Profile, ProfileError>;
declare const fetchPrefs: (id: string) => Effect.Effect<Prefs, PrefsError>;

