  id: string
): Effect.Effect<{ profile: Profile; prefs: Prefs }, ProfileError> =>
  Effect.all(
    [
      fetchProfile(id),
      fetchPrefs(id).pipe(Effect.catchTag("PrefsError", () => Effect.succeed(defaults))),
    ],
    { concurrency: "unbounded" }
  ).pipe(Effect.map(([profile, prefs]) => ({ profile, prefs })));
