```ts
import { Effect, Fiber, Data } from "effect";

class TaskError extends Data.TaggedError("TaskError")<{ readonly name: string }> {}

declare const taskA: Effect.Effect<number, TaskError>;
declare const taskB: Effect.Effect<string, TaskError>;
declare const taskC: Effect.Effect<boolean, TaskError>;

export const failFast: Effect.Effect<
  readonly [number, string, boolean],
  TaskError
> = Effect.gen(function* () {
  const fa = yield* Effect.fork(taskA);
  const fb = yield* Effect.fork(taskB);
  const fc = yield* Effect.fork(taskC);
  const a = yield* Fiber.join(fa);
  const b = yield* Fiber.join(fb);
  const c = yield* Fiber.join(fc);
  return [a, b, c] as const;
});
```

All three tasks start immediately via `Effect.fork`; each `Fiber.join` waits for its fiber. If any task fails the parent's error propagates and the runtime interrupts the other forked fibers — structured concurrency ensures no orphaned work.

