import { Effect } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Order {
  totalCents: number;
  country: string;
  itemCount: number;
  expectedRevision: number;
  actualRevision: number;
}

type Rule = (o: Order) => Effect.Effect<string, FieldError>;

const minRule: Rule = (o) =>
  o.totalCents >= 500 ? Effect.succeed("totalCents") : Effect.fail(fe("totalCents", "min $5"));
const countryRule: Rule = (o) =>
  ["US", "CA"].includes(o.country)
    ? Effect.succeed("country")
    : Effect.fail(fe("country", "US|CA only"));
const itemsRule: Rule = (o) =>
  o.itemCount > 0 && o.itemCount <= 50
    ? Effect.succeed("itemCount")
    : Effect.fail(fe("itemCount", "1..50"));
const revisionRule: Rule = (o) =>
  o.expectedRevision === o.actualRevision
    ? Effect.succeed("expectedRevision")
    : Effect.fail(fe("expectedRevision", `stale: want ${o.expectedRevision}, got ${o.actualRevision}`));

const rules: ReadonlyArray<Rule> = [minRule, countryRule, itemsRule, revisionRule];

export const validateOrder = (
  o: Order
): Effect.Effect<Order, readonly [FieldError, ...FieldError[]]> =>
  Effect.gen(function* () {
    yield* Effect.validateAll(rules, (r) => r(o));
    return o;
  });
```

`Effect.validateAll(rules, (r) => r(o))` runs every rule, and any failures accumulate into the error channel as a `NonEmptyArray<FieldError>` — adding the fourth optimistic-concurrency rule is a one-line push onto the rules list.

