import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Webhook { eventType: string; occurredAt: string; signature: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const eventType = (s: string): E.Either<Errs, string> =>
  /^[a-z]+(\.[a-z]+)+$/.test(s) ? E.right(s) : E.left([fe("eventType", "need dotted name")]);
const occurredAt = (s: string): E.Either<Errs, string> =>
  !Number.isNaN(Date.parse(s)) ? E.right(s) : E.left([fe("occurredAt", "bad ISO date")]);
const signature = (s: string): E.Either<Errs, string> =>
  /^[a-f0-9]{64}$/.test(s) ? E.right(s) : E.left([fe("signature", "need hex sha256")]);

export const validateWebhook = (w: Webhook): E.Either<Errs, Webhook> =>
  sequenceS(V)({
    eventType: eventType(w.eventType),
    occurredAt: occurredAt(w.occurredAt),
    signature: signature(w.signature),
  });
```

The `E.chain` tower is replaced by `sequenceS(V)` — every field is evaluated, and every failing field's `Left` is concatenated into the resulting `ReadonlyNonEmptyArray<FieldError>`.

