import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Missing = { _tag: "Missing"; key: string };
type BadBool = { _tag: "BadBool"; raw: string };

const lookup = (flags: Record<string, string>, key: string): E.Either<Missing, string> =>
  key in flags ? E.right(flags[key]) : E.left({ _tag: "Missing", key });

const toBool = (s: string): E.Either<BadBool, boolean> => {
  if (s === "true") return E.right(true);
  if (s === "false") return E.right(false);
  return E.left({ _tag: "BadBool", raw: s });
};

