  pipe(
    lookup(flags, key),
    E.chainW(toBool),
    E.mapLeft((e): boolean => {
      console.warn(`flag[${key}] fell back: ${e._tag}`);
      return false;
    }),
    E.fold((def) => def, (v) => v),
  );
```

