import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Coupon { code: string; expiresAt: number; minOrder: number; pctOff: number }

type Unknown = { _tag: "Unknown"; code: string };
type Expired = { _tag: "Expired"; expiresAt: number };
type UnderMin = { _tag: "UnderMin"; min: number; order: number };

const find = (reg: ReadonlyMap<string, Coupon>, code: string): E.Either<Unknown, Coupon> => {
  const c = reg.get(code);
  return c ? E.right(c) : E.left({ _tag: "Unknown", code });
};

const notExpired = (now: number) => (c: Coupon): E.Either<Expired, Coupon> =>
  c.expiresAt > now ? E.right(c) : E.left({ _tag: "Expired", expiresAt: c.expiresAt });

const meetsMin = (order: number) => (c: Coupon): E.Either<UnderMin, Coupon> =>
  order >= c.minOrder ? E.right(c) : E.left({ _tag: "UnderMin", min: c.minOrder, order });

export const applyCoupon = (
  reg: ReadonlyMap<string, Coupon>,
  code: string,
  order: number,
  now: number,
): number =>
  pipe(
    find(reg, code),
    E.chainW(notExpired(now)),
    E.chainW(meetsMin(order)),
    E.map((c) => order * (1 - c.pctOff / 100)),
    E.mapLeft((_e) => order),
    E.fold((unchanged) => unchanged, (discounted) => discounted),
  );
```

Each widening step narrows the success path; `E.fold` returns the original order on any failure so the caller always gets a `number`.

