```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadLength = { _tag: "BadLength"; got: number };
type BadChars = { _tag: "BadChars" };
type BadChecksum = { _tag: "BadChecksum" };

const strip = (s: string): string => s.replace(/-/g, "");

const length10 = (s: string): E.Either<BadLength, string> =>
  s.length === 10 ? E.right(s) : E.left({ _tag: "BadLength", got: s.length });

const validChars = (s: string): E.Either<BadChars, string> =>
  /^\d{9}[\dX]$/.test(s) ? E.right(s) : E.left({ _tag: "BadChars" });

const checksum = (s: string): E.Either<BadChecksum, string> => {
  const sum = [...s].reduce((acc, ch, i) => acc + (ch === "X" ? 10 : Number(ch)) * (10 - i), 0);
  return sum % 11 === 0 ? E.right(s) : E.left({ _tag: "BadChecksum" });
};

type IsbnResult = { ok: boolean; why: string };

export const validateIsbn10 = (raw: string): IsbnResult =>
  pipe(
    E.right<never, string>(strip(raw)),
    E.chainW(length10),
    E.chainW(validChars),
    E.chainW(checksum),
    E.mapLeft((e): string => e._tag),
    E.match<string, string, IsbnResult>(
      (why) => ({ ok: false, why }),
      (isbn) => ({ ok: true, why: isbn }),
    ),
  );
```

`E.right(strip(raw))` seeds the pipeline; each `chainW` layer adds another tag to the left union until `E.mapLeft` picks just the discriminator.

