```ts
import { Effect, Fiber, Duration, Data } from "effect";

class WatchdogExpired extends Data.TaggedError("WatchdogExpired")<{ readonly ms: number }> {}

declare const heavyCompute: Effect.Effect<number>;

export const guardedCompute = (
  deadlineMs: number
): Effect.Effect<number, WatchdogExpired> =>
  Effect.gen(function* () {
    const fiber = yield* Effect.fork(heavyCompute);
    const winner = yield* Effect.race(
      Fiber.join(fiber),
      Effect.sleep(Duration.millis(deadlineMs)).pipe(
        Effect.flatMap(() => Fiber.interrupt(fiber)),
        Effect.flatMap(() => Effect.fail(new WatchdogExpired({ ms: deadlineMs })))
      )
    );
    return winner;
  });
```

The race is between the joined result and the deadline. If the sleep wins, `Fiber.interrupt` stops the compute fiber before the watchdog error is raised, so no orphaned work is left running.

```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface ProfileUpdate { displayName: string; bio: string; avatarUrl: string }

const display = (s: string): Effect.Effect<string, FieldError> =>
  s.trim().length >= 2 ? Effect.succeed(s) : Effect.fail(fe("displayName", "too short"));
const bio = (s: string): Effect.Effect<string, FieldError> =>
  s.length <= 280 ? Effect.succeed(s) : Effect.fail(fe("bio", "over 280 chars"));
const avatar = (s: string): Effect.Effect<string, FieldError> =>
  s.startsWith("https://") ? Effect.succeed(s) : Effect.fail(fe("avatarUrl", "must be https"));

export const validateProfile = (
  p: ProfileUpdate
): Effect.Effect<ProfileUpdate, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [d, b, a] = yield* Effect.all([
      Effect.either(display(p.displayName)),
      Effect.either(bio(p.bio)),
      Effect.either(avatar(p.avatarUrl)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(d)) errs.push(d.left);
    if (Either.isLeft(b)) errs.push(b.left);
    if (Either.isLeft(a)) errs.push(a.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return p;
  });
```

Wrapping each field check with `Effect.either` reifies the failure into an `Either` value, so `Effect.all` doesn't short-circuit; we then collect every `Left` into the `ReadonlyArray<FieldError>` error channel.

