import { pipe } from "fp-ts/function";
import * as TE from "fp-ts/TaskEither";

interface Config { readonly port: number; readonly host: string }

declare const readFileTE: (path: string) => TE.TaskEither<Error, string>;

const parseJsonTE = (text: string): TE.TaskEither<Error, unknown> =>
  TE.tryCatch(
    async () => JSON.parse(text) as unknown,
    (u) => (u instanceof Error ? u : new Error(String(u))),
  );

const decodeConfig = (j: unknown): TE.TaskEither<Error, Config> => {
  if (typeof j !== "object" || j === null) return TE.left(new Error("config must be object"));
  const { port, host } = j as { port?: unknown; host?: unknown };
  if (typeof port !== "number" || typeof host !== "string")
    return TE.left(new Error("bad config shape"));
  return TE.right({ port, host });
};

const trace =
  (label: string) =>
  <A>(te: TE.TaskEither<Error, A>): TE.TaskEither<Error, A> =>
    pipe(
      te,
      TE.mapLeft((e) => new Error(`[${label}] ${e.message}`)),
    );

export const loadConfig = (path: string): TE.TaskEither<Error, Config> =>
  pipe(
    readFileTE(path),
    TE.chain(parseJsonTE),
    TE.chain(decodeConfig),
    trace("loadConfig"),
  );
```

Four stages of async work — each `TE.chain` short-circuits on the first left, so downstream decoders only ever see a parsed value, and `trace` decorates the final error without touching the success path.

