import { Effect, Layer, Context } from "effect";

interface Env { readonly get: (k: string) => string | undefined }
const Env = Context.GenericTag<Env>("cli/Env");

interface ArgParser { readonly parse: (argv: ReadonlyArray<string>) => Effect.Effect<Record<string, string>> }
const ArgParser = Context.GenericTag<ArgParser>("cli/ArgParser");

interface LoadedConfig { readonly verbose: boolean; readonly target: string }
interface ConfigLoader { readonly load: (argv: ReadonlyArray<string>) => Effect.Effect<LoadedConfig> }
const ConfigLoader = Context.GenericTag<ConfigLoader>("cli/ConfigLoader");

interface Runner { readonly run: (argv: ReadonlyArray<string>) => Effect.Effect<string> }
const Runner = Context.GenericTag<Runner>("cli/Runner");

const EnvLive = Layer.succeed(Env, { get: (k) => ({ VERBOSE: "1" } as Record<string, string>)[k] });
const ArgParserLive = Layer.succeed(ArgParser, {
  parse: (argv) => Effect.succeed(Object.fromEntries(argv.map((a, i) => [`arg${i}`, a])))
});

// ConfigLoader depends on Env + ArgParser
const ConfigLoaderLive = Layer.effect(
  ConfigLoader,
  Effect.gen(function* () {
    const env = yield* Env;
    const parser = yield* ArgParser;
    return ConfigLoader.of({
      load: (argv) => Effect.gen(function* () {
        const args = yield* parser.parse(argv);
        return { verbose: env.get("VERBOSE") === "1", target: args.arg0 ?? "default" };
      })
    });
  })
);

// Runner depends on ConfigLoader
const RunnerLive = Layer.effect(
  Runner,
  Effect.gen(function* () {
    const loader = yield* ConfigLoader;
    return Runner.of({
      run: (argv) => Effect.gen(function* () {
        const cfg = yield* loader.load(argv);
        return `run(target=${cfg.target}, verbose=${cfg.verbose})`;
      })
    });
  })
);

const LiveLayer = Layer.mergeAll(EnvLive, ArgParserLive, ConfigLoaderLive, RunnerLive);

const program = Effect.gen(function* () {
  const r = yield* Runner;
  return yield* r.run(["build"]);
});

export const runnable = Effect.provide(program, LiveLayer);
```

A clean four-layer graph: `Env` and `ArgParser` are leaf services; `ConfigLoader` fans them in; `Runner` consumes the result; `Layer.mergeAll` closes it all under `Effect.provide`.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export interface FetchError {
  readonly _tag: 'FetchError';
  readonly message: string;
  readonly cause: unknown;
}

const toFetchError = (u: unknown): FetchError => ({
  _tag: 'FetchError',
  message: u instanceof Error ? u.message : String(u),
  cause: u,
});

export const fetchJson = <A>(url: string): TE.TaskEither<FetchError, A> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(url);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return (await res.json()) as A;
    },
    toFetchError
  );

export const count = (url: string): TE.TaskEither<FetchError, number> =>
  pipe(
    fetchJson<ReadonlyArray<unknown>>(url),
    TE.map((xs) => xs.length)
  );
```

The `onRejected` callback narrows `unknown` into the declared `FetchError` — never cast, always inspect with `instanceof Error` first. Downstream `pipe` + `TE.map` keeps the error channel stable.

