```ts
import { Effect, Fiber, Ref, Data } from "effect";

class WorkerError extends Data.TaggedError("WorkerError")<{ readonly idx: number }> {}

const worker = (
  idx: number,
  acc: Ref.Ref<ReadonlyArray<number>>
): Effect.Effect<void, WorkerError> =>
  Effect.gen(function* () {
    const v = idx * 2;
    yield* Ref.update(acc, (xs) => [...xs, v]);
  });

export const collect = (
  n: number
): Effect.Effect<ReadonlyArray<number>, WorkerError> =>
  Effect.gen(function* () {
    const acc = yield* Ref.make<ReadonlyArray<number>>([]);
    const fibers: Fiber.Fiber<void, WorkerError>[] = [];
    for (let i = 0; i < n; i++) {
      fibers.push(yield* Effect.fork(worker(i, acc)));
    }
    for (const f of fibers) {
      yield* Fiber.join(f);
    }
    return yield* Ref.get(acc);
  });
```

`Ref.update` is atomic, so concurrent pushes don't lose entries. The order in the final array depends on fiber scheduling — use a `Queue` if you need FIFO ordering.

