```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Account {
  age: number;
  country: string;
  kycStatus: "pending" | "approved" | "rejected";
  termsAccepted: boolean;
}

const age = (n: number): Effect.Effect<number, FieldError> =>
  n >= 18 ? Effect.succeed(n) : Effect.fail(fe("age", "must be >= 18"));
const country = (s: string): Effect.Effect<string, FieldError> =>
  s.length === 2 ? Effect.succeed(s) : Effect.fail(fe("country", "ISO-2 only"));
const kyc = (s: Account["kycStatus"]): Effect.Effect<Account["kycStatus"], FieldError> =>
  s === "approved" ? Effect.succeed(s) : Effect.fail(fe("kycStatus", "must be approved"));
const terms = (b: boolean): Effect.Effect<boolean, FieldError> =>
  b ? Effect.succeed(b) : Effect.fail(fe("termsAccepted", "required"));

export const validateAccount = (
  a: Account
): Effect.Effect<Account, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [ag, co, kc, tm] = yield* Effect.all([
      Effect.either(age(a.age)),
      Effect.either(country(a.country)),
      Effect.either(kyc(a.kycStatus)),
      Effect.either(terms(a.termsAccepted)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(ag)) errs.push(ag.left);
    if (Either.isLeft(co)) errs.push(co.left);
    if (Either.isLeft(kc)) errs.push(kc.left);
    if (Either.isLeft(tm)) errs.push(tm.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return a;
  });
```

Adding the fourth `Effect.either`-wrapped check keeps the accumulating pattern intact — every `Left` contributes to the `ReadonlyArray<FieldError>` error channel rather than aborting on the first bad field.

`Effect.fork(effect)` launches `effect` on a new fiber and returns a `Fiber<A, E>` handle; the parent continues immediately. Calling `Fiber.join(fiber)` later suspends the parent until the fiber completes and re-raises any typed error into the parent's error channel. Fibers are structurally concurrent — if the parent is interrupted, its children are interrupted too.

```ts
import { Effect, Fiber, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly url: string }> {}

declare const fetchUsers: Effect.Effect<ReadonlyArray<string>, FetchError>;
declare const fetchOrders: Effect.Effect<ReadonlyArray<string>, FetchError>;

