import { Effect, Option } from "effect";
import { pipe } from "effect";

export interface Order { readonly total: number; readonly itemCount: number; readonly currency: string }

class RuleError { readonly _tag = "RuleError" as const; constructor(readonly rule: string, readonly msg: string) {} }

const CURRENCIES = new Set(["USD", "EUR", "GBP", "JPY"]);

const vTotal = (n: number): Effect.Effect<number, RuleError> =>
  n > 0 ? Effect.succeed(n) : Effect.fail(new RuleError("total", "must be > 0"));
const vCount = (n: number): Effect.Effect<number, RuleError> =>
  Number.isInteger(n) && n > 0 ? Effect.succeed(n) : Effect.fail(new RuleError("itemCount", "must be a positive integer"));
const vCur = (s: string): Effect.Effect<string, RuleError> =>
  CURRENCIES.has(s) ? Effect.succeed(s) : Effect.fail(new RuleError("currency", `unsupported: ${s}`));

export const validateOrder = (o: Order): Effect.Effect<Order, ReadonlyArray<RuleError>> =>
  pipe(
    Effect.all({ total: vTotal(o.total), itemCount: vCount(o.itemCount), currency: vCur(o.currency) }, { mode: "validate" }),
    Effect.mapError((rec) => {
      const entries: ReadonlyArray<Option.Option<RuleError>> = [rec.total, rec.itemCount, rec.currency];
      return entries.flatMap((e) => Option.isSome(e) ? [e.value] : []);
    }),
  );
