```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Item { readonly sku: string; readonly qty: number }

const parseJson = (s: string): E.Either<string, unknown> =>
  E.tryCatch(
    () => JSON.parse(s) as unknown,
    (u) => (u instanceof Error ? u.message : "parse error"),
  );

const extractItems = (j: unknown): E.Either<string, ReadonlyArray<unknown>> => {
  if (typeof j === "object" && j !== null && Array.isArray((j as { items?: unknown }).items)) {
    return E.right((j as { items: ReadonlyArray<unknown> }).items);
  }
  return E.left("missing items array");
};

const checkItems = (items: ReadonlyArray<unknown>): E.Either<string, ReadonlyArray<Item>> => {
  const out: Item[] = [];
  for (const it of items) {
    if (typeof it !== "object" || it === null) return E.left("item not an object");
    const { sku, qty } = it as { sku?: unknown; qty?: unknown };
    if (typeof sku !== "string" || sku.length === 0) return E.left("missing sku");
    out.push({ sku, qty: typeof qty === "number" ? qty : 1 });
  }
  return E.right(out);
};

export const loadInventory = (body: string): E.Either<string, ReadonlyArray<Item>> =>
  pipe(body, parseJson, E.chain(extractItems), E.chain(checkItems));
```

Four stages: parse → flatMap extract → flatMap check. The `Either` short-circuits on the first failure — the downstream stages never see a malformed document.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Config { host: string; port: number }

type ParseError = { _tag: "ParseError"; msg: string };
type NotObject = { _tag: "NotObject" };
type MissingField = { _tag: "MissingField"; field: string };
type BadType = { _tag: "BadType"; field: string; expected: string };

const parse = (s: string): E.Either<ParseError, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "ParseError", msg: String(u) }));

const asObject = (u: unknown): E.Either<NotObject, Record<string, unknown>> =>
  typeof u === "object" && u !== null && !Array.isArray(u)
    ? E.right(u as Record<string, unknown>)
    : E.left({ _tag: "NotObject" });

const toConfig = (o: Record<string, unknown>): E.Either<MissingField | BadType, Config> => {
  if (!("host" in o)) return E.left({ _tag: "MissingField", field: "host" });
  if (!("port" in o)) return E.left({ _tag: "MissingField", field: "port" });
  if (typeof o.host !== "string") return E.left({ _tag: "BadType", field: "host", expected: "string" });
  if (typeof o.port !== "number") return E.left({ _tag: "BadType", field: "port", expected: "number" });
  return E.right({ host: o.host, port: o.port });
};

export const loadConfig = (raw: string): E.Either<string, Config> =>
  pipe(
    parse(raw),
    E.chainW(asObject),
    E.chainW(toConfig),
    E.mapLeft((e) => `config error: ${e._tag}`),
    E.match((msg) => E.left<string, Config>(msg), (c) => E.right<string, Config>(c)),
  );
```

The final `E.match` re-packages into a simpler `Either<string, Config>` for callers that don't want to discriminate on tags.

```ts
