// v3 idiom: Brand.Brand<Name> tag + Brand.nominal smart constructor.
export type Email = string & Brand.Brand<"Email">;
export const Email = Brand.nominal<Email>();

declare const send: (to: Email, body: string) => Effect.Effect<void, Error>;

