import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadFormat = { _tag: "BadFormat"; input: string };
type InvalidDate = { _tag: "InvalidDate"; input: string };
type InFuture = { _tag: "InFuture"; iso: string };

const ISO_DATE = /^\d{4}-\d{2}-\d{2}$/;

const checkFormat = (s: string): E.Either<BadFormat, string> =>
  ISO_DATE.test(s) ? E.right(s) : E.left({ _tag: "BadFormat", input: s });

const toDate = (s: string): E.Either<InvalidDate, Date> => {
  const d = new Date(s);
  return Number.isNaN(d.getTime()) ? E.left({ _tag: "InvalidDate", input: s }) : E.right(d);
};

const notFuture = (d: Date): E.Either<InFuture, Date> =>
  d.getTime() <= Date.now() ? E.right(d) : E.left({ _tag: "InFuture", iso: d.toISOString() });

export const validateDate = (raw: string): string =>
  pipe(
    checkFormat(raw),
    E.chainW(toDate),
    E.chainW(notFuture),
    E.mapLeft((e) => `reject:${e._tag}`),
    E.match((reason) => reason, (d) => `ok:${d.toISOString().slice(0, 10)}`),
  );
```

Each step pushes a new tagged error into the widened union; `E.mapLeft` turns the whole union into one display string before the final `E.match`.

