import { Effect, Data } from "effect";

interface SavedFile { readonly path: string; readonly bytes: number }

class DownloadFailed extends Data.TaggedError("DownloadFailed")<{ readonly url: string }> {}
class WriteFailed extends Data.TaggedError("WriteFailed")<{ readonly path: string }> {}
class VirusDetected extends Data.TaggedError("VirusDetected")<{ readonly signature: string }> {}

