  url: string,
  path: string
): Effect.Effect<SavedFile, VirusDetected> =>
  fetchAndSave(url, path).pipe(
    Effect.catchTags({
      DownloadFailed: () => Effect.succeed<SavedFile>({ path, bytes: 0 }),
