// Client depends on Provider; scoped to release the HTTP keepalive pool
const ClientLive = Layer.scoped(
  Client,
  Effect.gen(function* () {
    const p = yield* Provider;
    yield* Effect.acquireRelease(
      Effect.sync(() => console.log(`open ${p.name} client`)),
      () => Effect.sync(() => console.log(`close ${p.name} client`))
    );
    return Client.of({
      send: (to, body) => Effect.succeed(`${p.name}:${to}:${body.length}`)
    });
  })
);

const LiveLayer = Layer.merge(ProviderLive, ClientLive);

const program: Effect.Effect<string, never, Client> = Effect.gen(function* () {
  const client = yield* Client;
  return yield* client.send("+15555550100", "hi");
});

export const runnable = Effect.provide(program, LiveLayer);
