import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { sequenceT } from "fp-ts/Apply";

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;
const bad = (m: Err): V<never> => E.left([m] as RNEA.ReadonlyNonEmptyArray<Err>);

const vInt = (n: number): V<number> => Number.isInteger(n) ? E.right(n) : bad("not int");
const vPos = (n: number): V<number> => n > 0 ? E.right(n) : bad("not positive");

const appVal = E.getApplicativeValidation(RNEA.getSemigroup<Err>());

export const validatePair = (a: number, b: number): V<readonly [number, number]> =>
  pipe(sequenceT(appVal)(vInt(a), vPos(b)));

// validatePair(1.5, -1) returns Left(["not int", "not positive"]).
