import { Effect, Context, Layer, Data } from "effect";

class CacheError extends Data.TaggedError("CacheError")<{ readonly key: string }> {}

interface Cache {
  readonly warm: (key: string) => Effect.Effect<void, CacheError>;
}
const Cache = Context.GenericTag<Cache>("app/Cache");

