```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Empty = { _tag: "Empty" };
type BadUrl = { _tag: "BadUrl"; input: string };
type NoHost = { _tag: "NoHost" };

const nonEmpty = (s: string): E.Either<Empty, string> =>
  s.length > 0 ? E.right(s) : E.left({ _tag: "Empty" });

const parseUrl = (s: string): E.Either<BadUrl, URL> =>
  E.tryCatch(() => new URL(s), () => ({ _tag: "BadUrl", input: s }));

const getHost = (u: URL): E.Either<NoHost, string> =>
  u.hostname.length > 0 ? E.right(u.hostname) : E.left({ _tag: "NoHost" });

export const hostnameOf = (raw: string): string =>
  pipe(
    nonEmpty(raw),
    E.chainW(parseUrl),
    E.chainW(getHost),
    E.mapLeft((e): string => `url error: ${e._tag}`),
    E.match((msg) => msg, (host) => host.toLowerCase()),
  );
```

`E.chainW` is what makes the error union grow; the non-widening `E.chain` would force a common left type at every step.

```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Signup { username: string; email: string; password: string }

const username = (s: string): Effect.Effect<string, FieldError> =>
  /^[a-z0-9_]{3,20}$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("username", "3..20"));
const email = (s: string): Effect.Effect<string, FieldError> =>
  /.+@.+\..+/.test(s) ? Effect.succeed(s) : Effect.fail(fe("email", "invalid"));
const password = (s: string): Effect.Effect<string, FieldError> =>
  s.length >= 8 ? Effect.succeed(s) : Effect.fail(fe("password", ">= 8"));

export const validateSignup = (
  s: Signup
): Effect.Effect<Signup, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const checks = [username(s.username), email(s.email), password(s.password)] as const;
    const results = yield* Effect.forEach(checks, (e) => Effect.either(e), { discard: false });
    const errs: FieldError[] = [];
    for (const r of results) if (Either.isLeft(r)) errs.push(r.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return s;
  });
```

Running `Effect.either` around each check inside `Effect.forEach(..., { discard: false })` turns every failure into a `Left` value; we then collect the lefts into the error channel as a single `ReadonlyArray<FieldError>`.

Use sequential `Effect.all` (the default) when the remote has strict rate limits or when each call depends on observable side effects of the previous one (cursor pagination, lock acquisition, transactional writes). Parallel `Effect.all` with `concurrency: "unbounded"` or a numeric cap is right when the calls are truly independent and the remote can absorb the load.

```ts
import { Effect, Data } from "effect";

class RateLimited extends Data.TaggedError("RateLimited")<{}> {}

declare const call: (id: string) => Effect.Effect<string, RateLimited>;

// Sequential: safe under a strict 1-request-per-call rate limit.
export const callAllSerial = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.all(ids.map(call));

// Parallel-bounded: safe for quotas that allow 3 in flight.
export const callAllPooled = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.all(ids.map(call), { concurrency: 3 });

// Either mode, wrapped in a generator for easy extension.
export const callAllLogged = (
  ids: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, RateLimited> =>
  Effect.gen(function* () {
    const results = yield* callAllPooled(ids);
    return results;
  });
```

Both keep the tuple/array order and the typed `RateLimited` error channel identical; only the scheduling changes.

```ts
import { Effect } from "effect";
import { pipe } from "effect";

class Err { readonly _tag = "Err" as const; constructor(readonly index: number, readonly msg: string) {} }

const check = (idx: number, s: string): Effect.Effect<string, Err> =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(new Err(idx, "empty"));

export const validateAll = (items: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<string>, ReadonlyArray<Err>> =>
  pipe(
    Effect.partition(items, (s, i) => check(i, s), { concurrency: 4 }),
    Effect.flatMap(([errs, ok]) => errs.length > 0 ? Effect.fail(errs) : Effect.succeed(ok)),
  );
```

`Effect.partition(iter, f, { concurrency })` runs every `f` to completion (collecting all failures on the left) while capping parallelism. Unlike `Effect.forEach`, a failure does not cancel siblings.

```ts
import { Effect, Fiber, Duration, Data } from "effect";

class DeadlineMissed extends Data.TaggedError("DeadlineMissed")<{ readonly ms: number }> {}

export const joinOrInterrupt = <A, E>(
  eff: Effect.Effect<A, E>,
  ms: number
): Effect.Effect<A, E | DeadlineMissed> =>
  Effect.gen(function* () {
    const fiber = yield* Effect.fork(eff);
    return yield* Effect.race(
      Fiber.join(fiber),
      Effect.sleep(Duration.millis(ms)).pipe(
        Effect.flatMap(() => Fiber.interrupt(fiber)),
        Effect.flatMap(() => Effect.fail(new DeadlineMissed({ ms })))
      )
    );
  });
```

The deadline branch performs the interrupt BEFORE failing, so the fiber's resources are released before the caller sees `DeadlineMissed`. The race's other branch — `Fiber.join` — is a cheap wait on an already-running fiber.

```ts
import { Effect, Data } from "effect";

class AuthSvcError extends Data.TaggedError("AuthSvcError")<{}> {}
class BillingSvcError extends Data.TaggedError("BillingSvcError")<{}> {}
class MailSvcError extends Data.TaggedError("MailSvcError")<{}> {}
class ConfirmError extends Data.TaggedError("ConfirmError")<{ readonly system: string }> {}

declare const deleteAuth: (id: string) => Effect.Effect<void, AuthSvcError>;
declare const deleteBilling: (id: string) => Effect.Effect<void, BillingSvcError>;
declare const deleteMail: (id: string) => Effect.Effect<void, MailSvcError>;

