```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Order { addr?: string; items: ReadonlyArray<unknown>; total: number }

type NoAddr = { _tag: "NoAddr" };
type NoItems = { _tag: "NoItems" };
type BadTotal = { _tag: "BadTotal"; total: number };

const hasAddr = (o: Order): E.Either<NoAddr, Order> =>
  o.addr !== undefined && o.addr.length > 0 ? E.right(o) : E.left({ _tag: "NoAddr" });

const hasItems = (o: Order): E.Either<NoItems, Order> =>
  o.items.length > 0 ? E.right(o) : E.left({ _tag: "NoItems" });

const totalPositive = (o: Order): E.Either<BadTotal, Order> =>
  o.total > 0 ? E.right(o) : E.left({ _tag: "BadTotal", total: o.total });

export const ship = (order: Order): string =>
  pipe(
    hasAddr(order),
    E.chainW(hasItems),
    E.chainW(totalPositive),
    E.mapLeft((e) => {
      switch (e._tag) {
        case "NoAddr": return "no addr";
        case "NoItems": return "no items";
        case "BadTotal": return "bad total";
      }
    }),
    E.fold((msg) => msg, (o) => `ok:${o.total}`),
  );
```

The `switch` inside `E.mapLeft` exhaustively matches the widened `NoAddr | NoItems | BadTotal` union — TypeScript will complain if a new tag is ever added.

