import { Effect, Layer, Context } from "effect";

interface Config { readonly dbUrl: string; readonly cacheTtlMs: number }
const Config = Context.GenericTag<Config>("app/Config");

interface Db { readonly query: (sql: string) => Effect.Effect<string> }
const Db = Context.GenericTag<Db>("app/Db");

interface Cache {
  readonly get: (k: string) => Effect.Effect<string | null>;
  readonly set: (k: string, v: string) => Effect.Effect<void>;
}
const Cache = Context.GenericTag<Cache>("app/Cache");

const ConfigLive = Layer.succeed(Config, { dbUrl: "postgres://x", cacheTtlMs: 30_000 });

// Db depends on Config
const DbLive = Layer.effect(
  Db,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return Db.of({ query: (sql) => Effect.succeed(`${cfg.dbUrl}:${sql}`) });
  })
);

// Cache depends on Config (reads TTL at build time)
const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    const cfg = yield* Config;
    const store = new Map<string, { v: string; exp: number }>();
    return Cache.of({
      get: (k) => Effect.sync(() => {
        const e = store.get(k);
        return e && e.exp > Date.now() ? e.v : null;
      }),
      set: (k, v) => Effect.sync(() => { store.set(k, { v, exp: Date.now() + cfg.cacheTtlMs }); })
    });
  })
);

const LiveLayer = Layer.mergeAll(ConfigLive, DbLive, CacheLive);

const program = Effect.gen(function* () {
  const db = yield* Db;
  const cache = yield* Cache;
  const hit = yield* cache.get("k");
  return hit ?? (yield* db.query("select v from t"));
});

export const runnable = Effect.provide(program, LiveLayer);
```

