const openClient = (host: string): Effect.Effect<HttpClient, ConnectError> =>
  host === "" ? Effect.fail(new ConnectError({ host })) : Effect.succeed({
    host,
    get: (p) => p.startsWith("/") ? Effect.succeed(`ok ${host}${p}`) : Effect.fail(new RequestError({ status: 400 })),
  });

const closeClient = (c: HttpClient): Effect.Effect<void> =>
  Console.log(`[http] closing ${c.host}`);

const clientResource = (host: string) =>
  Effect.acquireRelease(openClient(host), (c) => closeClient(c));

const program: Effect.Effect<string, ConnectError | RequestError, never> = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* clientResource("api.example.com");
    return yield* c.get("/users/1");
  })
);

Effect.runPromise(program).then(console.log);
