```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NotStr = { _tag: "NotStr"; got: string };
type TooShort = { _tag: "TooShort"; n: number };
type BadChars = { _tag: "BadChars" };

const asStr = (x: unknown): E.Either<NotStr, string> =>
  typeof x === "string" ? E.right(x) : E.left({ _tag: "NotStr", got: typeof x });

const minLen5 = (s: string): E.Either<TooShort, string> =>
  s.length >= 5 ? E.right(s) : E.left({ _tag: "TooShort", n: s.length });

const wordOnly = (s: string): E.Either<BadChars, string> =>
  /^\w+$/.test(s) ? E.right(s) : E.left({ _tag: "BadChars" });

export const check = (x: unknown): string =>
  pipe(
    asStr(x),
    E.chainW(minLen5),
    E.chainW(wordOnly),
    E.map((s) => s.toUpperCase()),
    E.mapLeft((e) => `invalid:${e._tag}`),
    E.match((msg) => msg, (up) => up),
  );
```

Each throw becomes an `E.left` with a tagged shape; the left union grows from `NotStr` to `NotStr | TooShort` to `NotStr | TooShort | BadChars` as `E.chainW` threads through.

