    : Effect.fail(fe("requestedAt", "out of range"));
const pmId = (s: string): Effect.Effect<string, FieldError> =>
  /^pm_[a-z0-9]+$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("paymentMethodId", "bad format"));

export const validateChange = (
  c: Change
): Effect.Effect<Change, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [p, r, m] = yield* Effect.all([
      Effect.either(plan(c.newPlan)),
      Effect.either(requestedAt(c.requestedAt)),
      Effect.either(pmId(c.paymentMethodId)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(p)) errs.push(p.left);
    if (Either.isLeft(r)) errs.push(r.left);
    if (Either.isLeft(m)) errs.push(m.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return c;
  });
```

`Effect.either` reifies each rule's failure; `Effect.all` runs every check without short-circuiting, and the collected `Left`s become a single `ReadonlyArray<FieldError>` in the error channel.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NaNErr = { _tag: "NaN" };
type Neg = { _tag: "Neg"; n: number };
type TooBig = { _tag: "TooBig"; n: number };

const toNum = (s: string): E.Either<NaNErr, number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NaN" });
};

const nonNeg = (n: number): E.Either<Neg, number> =>
  n >= 0 ? E.right(n) : E.left({ _tag: "Neg", n });

const under100 = (n: number): E.Either<TooBig, number> =>
  n <= 99 ? E.right(n) : E.left({ _tag: "TooBig", n });

export const clamp = (raw: string): number =>
  pipe(
    toNum(raw),
    E.chainW(nonNeg),
    E.chainW(under100),
    E.mapLeft((e): number => e._tag === "NaN" ? -1 : e._tag === "Neg" ? -2 : -3),
    E.fold((fallback) => fallback, (n) => n),
  );
```

The widened union lets `E.mapLeft` exhaustively map each tag to its sentinel without a `default` branch.

```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface Signup { email: string; password: string; displayName: string }

const checkEmail = (s: string): Effect.Effect<string, FieldError> =>
  /.+@.+\..+/.test(s) ? Effect.succeed(s) : Effect.fail(fe("email", "invalid format"));
const checkPassword = (s: string): Effect.Effect<string, FieldError> =>
  s.length >= 8 ? Effect.succeed(s) : Effect.fail(fe("password", "must be >= 8 chars"));
const checkDisplay = (s: string): Effect.Effect<string, FieldError> =>
  s.trim().length >= 2 ? Effect.succeed(s) : Effect.fail(fe("displayName", "too short"));

export const validateSignup = (
  s: Signup
): Effect.Effect<Signup, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [eE, eP, eD] = yield* Effect.all([
      Effect.either(checkEmail(s.email)),
      Effect.either(checkPassword(s.password)),
      Effect.either(checkDisplay(s.displayName)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(eE)) errs.push(eE.left);
    if (Either.isLeft(eP)) errs.push(eP.left);
    if (Either.isLeft(eD)) errs.push(eD.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return s;
  });
```

Wrapping each per-field effect with `Effect.either` converts failures into data, so `Effect.all` no longer short-circuits. We then collect every `Left` into the `ReadonlyArray<FieldError>` error channel — exactly the accumulation fp-ts gets from the validation applicative.

`Effect.tapError` taps the failure channel — if the effect succeeds, it's a no-op; if it fails, the handler runs and the original error propagates.

