import * as TE from 'fp-ts/TaskEither';

export type ClipboardError =
  | { readonly _tag: 'PermissionDenied' }
  | { readonly _tag: 'ClipboardUnavailable'; readonly cause: unknown };

const isPermissionDenied = (u: unknown): boolean =>
  u instanceof DOMException && u.name === 'NotAllowedError';

