  TE.tryCatch(
    () => navigator.clipboard.readText(),
    (u): ClipboardError =>
      isPermissionDenied(u)
        ? { _tag: 'PermissionDenied' }
        : { _tag: 'ClipboardUnavailable', cause: u }
  );

