import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Missing = { _tag: "Missing"; key: string };
type NotInt = { _tag: "NotInt"; key: string };
type OutOfRange = { _tag: "OutOfRange"; key: string; n: number };

interface Paging { page: number; size: number }

const readInt = (qs: URLSearchParams, key: string): E.Either<Missing | NotInt, number> => {
  const raw = qs.get(key);
  if (raw === null) return E.left({ _tag: "Missing", key });
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotInt", key });
};

const between = (key: string, lo: number, hi: number) => (n: number): E.Either<OutOfRange, number> =>
  n >= lo && n <= hi ? E.right(n) : E.left({ _tag: "OutOfRange", key, n });

export const paging = (qs: URLSearchParams): Paging =>
  pipe(
    readInt(qs, "page"),
    E.chainW(between("page", 1, Number.MAX_SAFE_INTEGER)),
    E.chainW((page): E.Either<Missing | NotInt | OutOfRange, Paging> =>
      pipe(readInt(qs, "size"), E.chainW(between("size", 1, 100)), E.map((size) => ({ page, size })))),
    E.mapLeft((_e): Paging => ({ page: 1, size: 20 })),
    E.fold((def) => def, (p) => p),
  );
```

`E.mapLeft` supplies defaults in the error channel; `E.fold` then merges both arms into a single `Paging`.

