import { Effect, Duration, Data } from "effect";

interface User { readonly id: string }
interface Order { readonly id: string }

class FetchError extends Data.TaggedError("FetchError")<{ readonly reason: string }> {}
class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly ms: number }> {}

declare const fetchUser: (id: string) => Effect.Effect<User, FetchError>;
declare const fetchOrders: (userId: string) => Effect.Effect<ReadonlyArray<Order>, FetchError>;

const program = (id: string) => Effect.gen(function* () {
  const u = yield* fetchUser(id);
  const o = yield* fetchOrders(u.id);
  return { u, o } as const;
});

export const bounded = (
  id: string,
  ms: number
): Effect.Effect<{ readonly u: User; readonly o: ReadonlyArray<Order> }, FetchError | TimeoutError> =>
  Effect.race(
    program(id),
    Effect.sleep(Duration.millis(ms)).pipe(
      Effect.flatMap(() => Effect.fail(new TimeoutError({ ms })))
    )
  );
