import { Effect, Layer, Context } from "effect";

interface Config { readonly level: "debug" | "info" }
const Config = Context.GenericTag<Config>("app/Config");

interface Logger { readonly info: (m: string) => Effect.Effect<void> }
// Tag FIRST, then Layer.effect takes the tag -- not a string literal
const Logger = Context.GenericTag<Logger>("app/Logger");

const ConfigLive = Layer.succeed(Config, { level: "info" });

// Logger depends on Config
const LoggerLive = Layer.effect(
  Logger,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return Logger.of({
      info: (m) => Effect.sync(() => console.log(`[${cfg.level}] ${m}`))
    });
  })
);

const LiveLayer = Layer.merge(ConfigLive, LoggerLive);

const program = Effect.gen(function* () {
  const log = yield* Logger;
  yield* log.info("hi");
});

export const runnable = Effect.provide(program, LiveLayer);
```

`Layer.effect` must take a `Context.Tag` (here produced by `Context.GenericTag<Logger>(...)`) as its first arg so the returned layer's output type is tracked; a string literal leaves the compiler with `unknown` and the downstream `yield* Logger` will not type-check.

