```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Row { id: number; name: string; active: boolean }

type BadArity = { _tag: "BadArity"; got: number };
type BadId = { _tag: "BadId"; raw: string };
type BadBool = { _tag: "BadBool"; raw: string };

const splitRow = (line: string): E.Either<BadArity, ReadonlyArray<string>> => {
  const parts = line.split(",").map((p) => p.trim());
  return parts.length === 3 ? E.right(parts) : E.left({ _tag: "BadArity", got: parts.length });
};

const toId = (raw: string): E.Either<BadId, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "BadId", raw });
};

const toBool = (raw: string): E.Either<BadBool, boolean> =>
  raw === "true" ? E.right(true) : raw === "false" ? E.right(false) : E.left({ _tag: "BadBool", raw });

export const parseRow = (line: string): string =>
  pipe(
    splitRow(line),
    E.chainW(([idRaw, name, activeRaw]): E.Either<BadId | BadBool, Row> =>
      pipe(
        toId(idRaw),
        E.chainW((id) => pipe(toBool(activeRaw), E.map((active) => ({ id, name, active })))),
      ),
    ),
    E.mapLeft((e) => `row error: ${e._tag}`),
    E.fold((err) => err, (row) => JSON.stringify(row)),
  );
```

Each outer `E.chainW` joins the next stage; the inner `pipe` sequences the two coercions that depend on destructured parts.

