```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Account {
  age: number;
  country: string;
  kycStatus: "pending" | "approved" | "rejected";
  termsAccepted: boolean;
}

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const age = (n: number): E.Either<Errs, number> =>
  n >= 18 ? E.right(n) : E.left([fe("age", "must be >= 18")]);
const country = (c: string): E.Either<Errs, string> =>
  c.length === 2 ? E.right(c) : E.left([fe("country", "must be ISO-2")]);
const kyc = (s: Account["kycStatus"]): E.Either<Errs, Account["kycStatus"]> =>
  s === "approved" ? E.right(s) : E.left([fe("kycStatus", "must be approved")]);
const terms = (b: boolean): E.Either<Errs, boolean> =>
  b ? E.right(b) : E.left([fe("termsAccepted", "must accept terms")]);

export const validateAccount = (a: Account): E.Either<Errs, Account> =>
  pipe(
    sequenceT(V)(age(a.age), country(a.country), kyc(a.kycStatus), terms(a.termsAccepted)),
    E.map(([ageV, countryV, kycV, termsV]) => ({
      age: ageV, country: countryV, kycStatus: kycV, termsAccepted: termsV,
    }))
  );
```

Adding the fourth validator is a one-line tuple extension — `sequenceT(V)` already accumulates every failure, so the new rule participates in the same `ReadonlyNonEmptyArray<FieldError>` channel.

```ts
import { Effect, Fiber, Duration } from "effect";

declare const emitMetric: Effect.Effect<void>;
declare const mainWork: Effect.Effect<number>;

const reporter: Effect.Effect<never> = Effect.gen(function* () {
  while (true) {
    yield* emitMetric;
    yield* Effect.sleep(Duration.seconds(10));
  }
});

export const run: Effect.Effect<number> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(reporter);
  const result = yield* mainWork;
  yield* Fiber.interrupt(fiber);
  return result;
});
```

`Effect.fork` launches the infinite reporter loop; `Fiber.interrupt` at the end tears it down deterministically once the main work finishes. Because the loop sleeps, each iteration is an interruption point — no need for a manual stop flag.

```ts
import { Effect, Queue, Ref, Data } from "effect";

class FlushError extends Data.TaggedError("FlushError")<{ readonly count: number; readonly cause: string }> {}

interface Record { readonly id: string; readonly data: unknown }

declare const bulkInsert: (rows: ReadonlyArray<Record>) => Effect.Effect<void, FlushError>;

export const runBatcher = (
  inbox: Queue.Dequeue<Record>,
  batchSize: number,
): Effect.Effect<never, FlushError> =>
  Effect.gen(function* () {
    const buf = yield* Ref.make<ReadonlyArray<Record>>([]);
    while (true) {
      const next = yield* Queue.take(inbox);
      const flushed = yield* Ref.modify(buf, (prev) => {
        const upd = [...prev, next];
        return upd.length >= batchSize ? [upd, [] as ReadonlyArray<Record>] : [[] as ReadonlyArray<Record>, upd];
      });
      if (flushed.length > 0) yield* bulkInsert(flushed);
    }
  });
```

`Ref.modify` atomically swaps the buffer so two concurrent takes can't reissue the same batch.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type NotInt = { _tag: "NotInt"; raw: string };
type Negative = { _tag: "Negative"; n: number };
type TooYoung = { _tag: "TooYoung"; n: number };

const toInt = (s: string): E.Either<NotInt, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotInt", raw: s });
};

const nonNegative = (n: number): E.Either<Negative, number> =>
  n >= 0 ? E.right(n) : E.left({ _tag: "Negative", n });

const adult = (n: number): E.Either<TooYoung, number> =>
  n >= 18 ? E.right(n) : E.left({ _tag: "TooYoung", n });

type EligibleResult = { ok: boolean; msg: string };

export const checkEligible = (raw: string): EligibleResult =>
  pipe(
    toInt(raw),
    E.chainW(nonNegative),
    E.chainW(adult),
    E.mapLeft((e) => `reject:${e._tag}`),
    E.match<string, number, EligibleResult>(
      (msg) => ({ ok: false, msg }),
      (age) => ({ ok: true, msg: `eligible@${age}` }),
    ),
  );
```

The final `E.match` takes both arms and produces a uniform `{ ok, msg }` shape — no `if`/`else` ladder needed.

```ts
export function memoize<T extends (...args: any[]) => any>(fn: T): T {
  const cache = new Map<string, ReturnType<T>>();
  const memoized = (...args: Parameters<T>): ReturnType<T> => {
    const key = JSON.stringify(args);
    let hit = cache.get(key);
    if (hit === undefined && !cache.has(key)) {
      hit = fn(...args);
      cache.set(key, hit as ReturnType<T>);
    }
    return hit as ReturnType<T>;
  };
  return memoized as T;
}
```

Notes: uses `Parameters<T>` / `ReturnType<T>` to preserve the exact tuple shape and return type. `JSON.stringify` is a reasonable default key for serializable args; swap in a structural hash if you need to cache on objects-with-cycles or functions. The `has` check distinguishes a cached `undefined` from a miss.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

type Flags = Readonly<Record<string, unknown>>;

const asBool = (u: unknown): O.Option<boolean> =>
  typeof u === 'boolean' ? O.some(u) : O.none;

export const flag = (flags: Flags, name: string): boolean =>
  pipe(
