```ts
import { Effect, Duration, Data } from "effect";

class PrimaryError extends Data.TaggedError("PrimaryError")<{ readonly url: string }> {}
class CacheEmpty extends Data.TaggedError("CacheEmpty")<{ readonly key: string }> {}
class Deadline extends Data.TaggedError("Deadline")<{ readonly ms: number }> {}

interface Doc { readonly id: string; readonly source: "primary" | "cache" }

declare const primary: Effect.Effect<Doc, PrimaryError>;
declare const staleCache: Effect.Effect<Doc, CacheEmpty>;

export const firstGoodEnough = (
  staleAfter: number,
  hardDeadline: number
): Effect.Effect<Doc, PrimaryError | CacheEmpty | Deadline> =>
  Effect.raceAll([
    primary,
    Effect.sleep(Duration.millis(staleAfter)).pipe(
      Effect.flatMap(() => staleCache)
    ),
    Effect.sleep(Duration.millis(hardDeadline)).pipe(
      Effect.flatMap(() => Effect.fail(new Deadline({ ms: hardDeadline })))
    ),
  ]);
```

The primary fires first; after `staleAfter` the cache read is allowed in; the hard deadline is the safety net. `raceAll` returns the first success, interrupting the other two fibers.

