import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type ParseError = { _tag: "ParseError"; msg: string };
type NoToken = { _tag: "NoToken" };
type BadToken = { _tag: "BadToken" };

const parseJson = (s: string): E.Either<ParseError, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "ParseError", msg: String(u) }));

const getToken = (v: unknown): E.Either<NoToken, unknown> =>
  typeof v === "object" && v !== null && "token" in v
    ? E.right((v as { token: unknown }).token)
    : E.left({ _tag: "NoToken" });

const asString = (u: unknown): E.Either<BadToken, string> =>
  typeof u === "string" ? E.right(u) : E.left({ _tag: "BadToken" });

export const tokenLen = (raw: string): number =>
  pipe(
    parseJson(raw),
    E.chainW(getToken),
    E.chainW(asString),
    E.mapLeft((_e) => -1 as const),
    E.fold((n) => n, (tok) => tok.length),
  );
```

The nested catch becomes a single widened left type; `E.fold` merges the fallback and the success path into one `number`.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseInt10 = (s: string): O.Option<number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? O.none : O.some(n);
};

const nonZero = (n: number): O.Option<number> =>
  n === 0 ? O.none : O.some(n);

export const reciprocalOf = (input: string): number =>
  pipe(
    parseInt10(input),
    O.chain(nonZero),
    O.map((n) => 1 / n),
    O.getOrElse<number>(() => -1),
  );
```

Both `parseInt10` and `nonZero` return `Option<number>`, so each composes with `O.chain`. The final `O.map` stays on successful values only.

`Layer.effect(Tag, builderEffect)` produces a service by running `builderEffect` once when the layer is provided. The builder is an `Effect<Service, E, R>` — its `R` channel names which upstream services it needs. Yield those services inside `Effect.gen`, close over them in the service's method closures, and return the final `Service` record. The builder runs lazily on first use and is memoised per layer.

