```ts
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceT } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface RebateInput {
  purchaseCents: number;
  memberTier: "free" | "silver" | "gold";
  daysSinceEnroll: number;
}

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const minPurchase = (i: RebateInput): E.Either<Errs, RebateInput> =>
  i.purchaseCents >= 2500 ? E.right(i) : E.left([fe("purchaseCents", "minimum $25")]);
const tierOK = (i: RebateInput): E.Either<Errs, RebateInput> =>
  i.memberTier !== "free" ? E.right(i) : E.left([fe("memberTier", "rebate requires silver+")]);
const enrolled = (i: RebateInput): E.Either<Errs, RebateInput> =>
  i.daysSinceEnroll >= 30 ? E.right(i) : E.left([fe("daysSinceEnroll", "need >= 30 days")]);

export const validateRebate = (i: RebateInput): E.Either<Errs, RebateInput> =>
  pipe(
    sequenceT(V)(minPurchase(i), tierOK(i), enrolled(i)),
    E.map(() => i)
  );
```

Each rule is an independent `Either<RNEA<FieldError>, RebateInput>`; the validation applicative composes them so three broken rules produce a three-element `ReadonlyNonEmptyArray<FieldError>`.

