```ts
// `Effect.forEach(xs, fn, { discard: false })` runs fn over each x and
// collects the successes into a ReadonlyArray. It still short-circuits on the
// first failure — so for accumulating validation we pair it with
// `Effect.either` so per-item results become Rights/Lefts we can split.

import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface TlsConfig { certPath: string; keyPath: string; minVersion: "1.2" | "1.3" }

const cert = (s: string): Effect.Effect<string, FieldError> =>
  s.endsWith(".pem") ? Effect.succeed(s) : Effect.fail(fe("certPath", "need .pem"));
const key = (s: string): Effect.Effect<string, FieldError> =>
  s.endsWith(".pem") ? Effect.succeed(s) : Effect.fail(fe("keyPath", "need .pem"));
const minv = (s: string): Effect.Effect<"1.2" | "1.3", FieldError> =>
  s === "1.2" || s === "1.3" ? Effect.succeed(s) : Effect.fail(fe("minVersion", "1.2|1.3"));

export const validateTls = (
  t: TlsConfig
): Effect.Effect<TlsConfig, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const results = yield* Effect.forEach(
      [cert(t.certPath), key(t.keyPath), minv(t.minVersion)],
      (eff) => Effect.either(eff),
      { discard: false }
    );
    const errs = results.flatMap((r) => (Either.isLeft(r) ? [r.left] : []));
    if (errs.length > 0) return yield* Effect.fail(errs);
    return t;
  });
```

Wrapping each per-field effect in `Effect.either` turns failure into data; `Effect.forEach(..., { discard: false })` then runs them all and hands back the full list of results, which we partition into a `ReadonlyArray<FieldError>`.

```ts
// Default: `E.Applicative` — short-circuits on the first Left.
// Validation: `E.getApplicativeValidation(S)` — both branches evaluated; when
// both fail, their errors are combined via the semigroup S. Picking
// `RNEA.getSemigroup<FieldError>()` collects errors into a non-empty array.

import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface Address { street: string; city: string; postalCode: string }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const street = (s: string): E.Either<Errs, string> =>
  s.trim().length > 0 ? E.right(s) : E.left([fe("street", "required")]);
const city = (s: string): E.Either<Errs, string> =>
  s.trim().length > 0 ? E.right(s) : E.left([fe("city", "required")]);
const postal = (s: string): E.Either<Errs, string> =>
  /^\d{5}(-\d{4})?$/.test(s) ? E.right(s) : E.left([fe("postalCode", "bad format")]);

export const validateAddress = (a: Address): E.Either<Errs, Address> =>
  sequenceS(V)({ street: street(a.street), city: city(a.city), postalCode: postal(a.postalCode) });
```

Under the validation applicative, `sequenceS` turns a record of `Either<Errs, _>` into one `Either<Errs, Address>` whose `Left` is the merged list of every field that failed.

```ts
import { Effect, Queue, Ref, Data } from "effect";

class JobError extends Data.TaggedError("JobError")<{ readonly jobId: string; readonly cause: string }> {}

interface Job { readonly id: string; readonly payload: unknown }
interface Stats { readonly ok: number; readonly failed: number }

declare const processJob: (j: Job) => Effect.Effect<void, JobError>;

export const runWorker = (
  inbox: Queue.Dequeue<Job>,
  stats: Ref.Ref<Stats>,
): Effect.Effect<never> =>
  Effect.gen(function* () {
    while (true) {
      const job = yield* Queue.take(inbox);
      const res = yield* Effect.either(processJob(job));
      if (res._tag === "Right") {
        yield* Ref.update(stats, (s) => ({ ...s, ok: s.ok + 1 }));
      } else {
        yield* Effect.logError(`job ${res.left.jobId} failed: ${res.left.cause}`);
        yield* Ref.update(stats, (s) => ({ ...s, failed: s.failed + 1 }));
      }
    }
  });
```

`Effect.either` lifts the failure channel into `Either<E, A>` so the loop never aborts on a single bad job.

