const sortByTs = (es: ReadonlyArray<Event>): ReadonlyArray<Event> =>
  [...es].sort((a, b) => a.ts - b.ts);
const dayKey = (ts: number): string => new Date(ts).toISOString().slice(0, 10);
const byDay = (es: ReadonlyArray<Event>): Readonly<Record<string, ReadonlyArray<Event>>> => {
  const out: Record<string, Event[]> = {};
  for (const e of es) (out[dayKey(e.ts)] ??= []).push(e);
  return out;
};
const countEach = (
  rec: Readonly<Record<string, ReadonlyArray<Event>>>,
): Readonly<Record<string, number>> =>
  Object.fromEntries(Object.entries(rec).map(([k, v]) => [k, v.length]));

