```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Missing = { _tag: "Missing"; key: string };
type NotInt = { _tag: "NotInt"; raw: string };
type OutOfRange = { _tag: "OutOfRange"; n: number };

const readKey = (env: Record<string, string>, k: string): E.Either<Missing, string> =>
  k in env ? E.right(env[k]) : E.left({ _tag: "Missing", key: k });

const toInt = (s: string): E.Either<NotInt, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotInt", raw: s });
};

const inPortRange = (n: number): E.Either<OutOfRange, number> =>
  n >= 1 && n <= 65535 ? E.right(n) : E.left({ _tag: "OutOfRange", n });

export const loadPort = (env: Record<string, string>): number =>
  pipe(
    readKey(env, "PORT"),
    E.chainW(toInt),
    E.chainW(inPortRange),
    E.mapLeft((e) => {
      console.warn(`port config: ${e._tag}`);
      return 3000;
    }),
    E.fold((fallback) => fallback, (port) => port),
  );
```

The `E.mapLeft` both logs and produces the default; `E.fold` then merges the right (valid port) and left (fallback) into a plain `number`.

`Fiber.interrupt` sends a structured interrupt signal that the runtime delivers at the fiber's next suspension point (sleep, async boundary, yield*). Unlike cancelling a `Promise` (which is non-standard and cooperative at best), interrupt runs the fiber's finalizers — any scoped resources are released before the fiber exits.

```ts
import { Effect, Fiber, Data } from "effect";

class WorkerError extends Data.TaggedError("WorkerError")<{ readonly worker: string }> {}

declare const workerA: Effect.Effect<number, WorkerError>;
declare const workerB: Effect.Effect<number, WorkerError>;

export const conditionalStop = (
  stopB: boolean
): Effect.Effect<number, WorkerError> =>
  Effect.gen(function* () {
    const fa = yield* Effect.fork(workerA);
    const fb = yield* Effect.fork(workerB);
    if (stopB) {
      yield* Fiber.interrupt(fb);
    }
    const a = yield* Fiber.join(fa);
    if (!stopB) {
      yield* Fiber.interrupt(fb);
    }
    return a;
  });
```

The example shows interrupt as a normal effectful step. After the conditional interrupt, the program continues — interrupted fibers' results are not observed.

