Client is released first (LIFO), then the config file — the natural reverse of acquisition order.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Rollout { enabled: true; rolloutPct: number }

type ParseErr = { _tag: "ParseErr"; msg: string };
type Disabled = { _tag: "Disabled" };
type BadPct = { _tag: "BadPct"; got: unknown };

const parse = (s: string): E.Either<ParseErr, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "ParseErr", msg: String(u) }));

const enabled = (u: unknown): E.Either<Disabled, Record<string, unknown>> => {
  if (typeof u === "object" && u !== null && (u as { enabled?: unknown }).enabled === true) {
    return E.right(u as Record<string, unknown>);
  }
  return E.left({ _tag: "Disabled" });
};

const readPct = (o: Record<string, unknown>): E.Either<BadPct, Rollout> => {
  const p = o.rolloutPct;
  return typeof p === "number" && p >= 0 && p <= 100
    ? E.right({ enabled: true, rolloutPct: p })
    : E.left({ _tag: "BadPct", got: p });
};

export const loadRollout = (raw: string): E.Either<string, Rollout> =>
  pipe(
    parse(raw),
    E.chainW(enabled),
    E.chainW(readPct),
    E.mapLeft((e) => `rollout:${e._tag}`),
    E.match(
      (reason) => E.left<string, Rollout>(reason),
      (r) => E.right<string, Rollout>(r),
    ),
  );
```

The widened `ParseErr | Disabled | BadPct` makes every failure mode explicit in the type of the intermediate; `E.mapLeft` then normalises to a single reason string.

```ts
