import * as E from 'fp-ts/Either';

type Parse = { _tag: 'Parse' };
type OutOfRange = { _tag: 'OutOfRange'; value: number };

const parse = (s: string): E.Either<Parse, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left({ _tag: 'Parse' }) : E.right(n);
};

const inRange = (n: number): E.Either<OutOfRange, number> =>
  n >= 0 && n <= 100 ? E.right(n) : E.left({ _tag: 'OutOfRange', value: n });

