import { Effect, Schedule } from "effect";

class RpcError {
  readonly _tag = "RpcError" as const;
  constructor(readonly code: number) {}
}

interface RpcResult { readonly ok: boolean }

const callOnce = (method: string): Effect.Effect<RpcResult, RpcError> =>
  Effect.tryPromise({
    try: async (): Promise<RpcResult> => ({ ok: method.length > 0 }),
    catch: () => new RpcError(500),
  });

// no jitter, bounded by recurs(2) — initial + 2 retries.
const policy = Schedule.intersect(
  Schedule.exponential("100 millis"),
  Schedule.recurs(2),
);

