```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Parsed { readonly hours: number; readonly minutes: number }

const parse = (raw: string): E.Either<string, Parsed> => {
  const m = /^(\d{1,2}):(\d{2})$/.exec(raw.trim());
  if (!m) return E.left(`bad format: ${raw}`);
  return E.right({ hours: Number(m[1]), minutes: Number(m[2]) });
};

// NEW stage between parse and format — the pipeline grew by one line.
// With nested calls this would mean wrapping parse(raw) in another validate(...) layer.
const validate = (p: Parsed): E.Either<string, Parsed> =>
  p.hours >= 0 && p.hours < 24 && p.minutes >= 0 && p.minutes < 60
    ? E.right(p)
    : E.left(`out of range: ${p.hours}:${p.minutes}`);

const format = (p: Parsed): string => `${p.hours.toString().padStart(2, "0")}:${p.minutes.toString().padStart(2, "0")}`;

const withPrefix =
  (prefix: string) =>
  (e: E.Either<string, string>): E.Either<string, string> =>
    pipe(e, E.map((s) => `${prefix}${s}`));

export const normaliseTime = (raw: string): E.Either<string, string> =>
  pipe(parse(raw), E.chain(validate), E.map(format), withPrefix("T:"));
```

The only code change from the original two-stage form was adding `E.chain(validate)` and the later `withPrefix("T:")` as new lines. The earlier and later stages didn't move; pipe makes that kind of edit trivial, and every extra step just adds one line rather than one parenthesis level.

```ts
// The default Either applicative is *fail-fast*: the first Left wins.
// For config-style validation we want every bad field surfaced at once, so
// we swap in `E.getApplicativeValidation(S)` where S is a semigroup on the
// error type. Running `sequenceS` over that applicative merges all Lefts via
// the semigroup into a ReadonlyNonEmptyArray<FieldError>.

import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { pipe } from "fp-ts/function";
import { sequenceS } from "fp-ts/Apply";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });
type Errs = RNEA.ReadonlyNonEmptyArray<FieldError>;

interface AppConfig { host: string; port: number; timeoutMs: number }

const V = E.getApplicativeValidation(RNEA.getSemigroup<FieldError>());

const host = (s: string): E.Either<Errs, string> =>
  s.length > 0 ? E.right(s) : E.left([fe("host", "empty")]);
const port = (n: number): E.Either<Errs, number> =>
  n >= 1 && n <= 65535 ? E.right(n) : E.left([fe("port", "1..65535")]);
const timeout = (n: number): E.Either<Errs, number> =>
  n > 0 ? E.right(n) : E.left([fe("timeoutMs", "must be > 0")]);

export const validateConfig = (c: AppConfig): E.Either<Errs, AppConfig> =>
  pipe(
    sequenceS(V)({ host: host(c.host), port: port(c.port), timeoutMs: timeout(c.timeoutMs) })
  );
```

`sequenceS` is the record-shaped sibling of `sequenceT`: it takes a `{ key: Either<E,A> }` record and returns `Either<E, { key: A }>`, but under the validation applicative each failing key adds to the shared `ReadonlyNonEmptyArray<FieldError>`.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type NanErr = { readonly _tag: 'NanErr' };
type NegErr = { readonly _tag: 'NegErr' };

const parseNumber = (s: string): E.Either<NanErr, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left({ _tag: 'NanErr' }) : E.right(n);
};

const nonNegative = (n: number): E.Either<NegErr, number> =>
  n >= 0 ? E.right(n) : E.left({ _tag: 'NegErr' });

export const parse = (s: string): E.Either<NanErr | NegErr, number> =>
  pipe(parseNumber(s), E.chainW(nonNegative));
```

Replacing `throw` with tagged `Left` values makes both failure modes show up in the return type, so the caller cannot forget either.

```ts
import { Effect, Fiber, Ref } from "effect";

const bumpN = (count: Ref.Ref<number>, n: number): Effect.Effect<void> =>
  Effect.gen(function* () {
    for (let i = 0; i < n; i++) {
      yield* Ref.update(count, (x) => x + 1);
    }
  });

export const sharedCounter: Effect.Effect<number> = Effect.gen(function* () {
  const count = yield* Ref.make(0);
  const fa = yield* Effect.fork(bumpN(count, 100));
  const fb = yield* Effect.fork(bumpN(count, 150));
  yield* Fiber.join(fa);
  yield* Fiber.join(fb);
  return yield* Ref.get(count);
});
```

Both fibers run concurrently and mutate the same `Ref` atomically via `Ref.update`. Joining both before reading guarantees we see the combined total (250). `Ref.update` is a single atomic read-modify-write — no locks required.

```ts
