class Invalid extends Data.TaggedError("Invalid")<{ readonly field: string }> {}

declare const validateEmail: (s: string) => Effect.Effect<string, Invalid>;
declare const validateAge: (n: number) => Effect.Effect<number, Invalid>;
declare const validateName: (s: string) => Effect.Effect<string, Invalid>;

interface Form { readonly email: string; readonly age: number; readonly name: string }

export const validateForm = (f: Form): Effect.Effect<[string, number, string], Invalid> =>
  Effect.gen(function* () {
