```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type Malformed = { kind: 'malformed'; part: string };

const splitPair = (part: string): E.Either<Malformed, readonly [string, string]> => {
  const i = part.indexOf('=');
  if (i <= 0) return E.left({ kind: 'malformed', part });
  return E.right([part.slice(0, i), part.slice(i + 1)] as const);
};

const reducePairs = (
  parts: ReadonlyArray<string>,
): E.Either<Malformed, Record<string, string>> =>
  parts.reduce<E.Either<Malformed, Record<string, string>>>(
    (acc, part) =>
      pipe(
        acc,
        E.chain((accMap) =>
          pipe(
            splitPair(part),
            E.map(([k, v]) => ({ ...accMap, [k]: v })),
          ),
        ),
      ),
    E.right({}),
  );

export const parseConfig = (raw: string): E.Either<Malformed, Record<string, string>> =>
  pipe(
    raw.split(';').filter((x) => x.length > 0),
    reducePairs,
  );
```

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadShape = { _tag: "BadShape"; parts: number };
type BadBase64 = { _tag: "BadBase64" };
type BadJson = { _tag: "BadJson"; msg: string };
type Expired = { _tag: "Expired"; exp: number };

const splitJwt = (token: string): E.Either<BadShape, string> => {
  const ps = token.split(".");
  return ps.length === 3 ? E.right(ps[1]) : E.left({ _tag: "BadShape", parts: ps.length });
};

const b64 = (s: string): E.Either<BadBase64, string> =>
  E.tryCatch(() => Buffer.from(s, "base64").toString("utf8"), () => ({ _tag: "BadBase64" as const }));

const parseJson = (s: string): E.Either<BadJson, unknown> =>
  E.tryCatch(() => JSON.parse(s), (u) => ({ _tag: "BadJson" as const, msg: String(u) }));

const notExpired = (now: number) => (u: unknown): E.Either<Expired, { exp: number }> => {
  if (typeof u === "object" && u !== null && "exp" in u) {
    const exp = (u as { exp: unknown }).exp;
    if (typeof exp === "number" && exp > now) return E.right({ exp });
    if (typeof exp === "number") return E.left({ _tag: "Expired", exp });
  }
  return E.left({ _tag: "Expired", exp: 0 });
};

export const verify = (token: string, now: number): string =>
  pipe(
    splitJwt(token),
    E.chainW(b64),
    E.chainW(parseJson),
    E.chainW(notExpired(now)),
    E.mapLeft((e) => `reject:${e._tag}`),
    E.fold((err) => err, (ok) => `ok:exp=${ok.exp}`),
  );
```

Each step adds one tag to the left union — reading the `E.mapLeft` argument type tells you exactly which failure modes are modelled.

```ts
import { Effect, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly url: string; readonly status: number }> {}

declare const fetchBody: (url: string) => Effect.Effect<string, HttpError>;

export const fetchAll = (
  urls: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, HttpError> =>
  Effect.all(urls.map(fetchBody), { concurrency: 4 }).pipe(
    Effect.map((bodies) => bodies)
  );

// Same inputs, but one at a time. Useful when the remote has no rate headroom.
export const fetchAllSerial = (
  urls: ReadonlyArray<string>
): Effect.Effect<ReadonlyArray<string>, HttpError> =>
  Effect.all(urls.map(fetchBody));
```

`Effect.all(jobs, { concurrency: 4 })` caps in-flight requests at 4 fibres; default `Effect.all(jobs)` runs strictly one-by-one. Both preserve input order in the resulting `ReadonlyArray`.

Reach for `pipe` when:

- the pipeline has **three or more stages** — two-step compositions are fine nested,
- the stages are **named**, reusable functions rather than ad-hoc lambdas,
- the data flow matters more than any one transformation in isolation.

Nested calls win only for one- or two-step inline transforms where introducing a pipe would be ceremony.

```ts
import { pipe } from "effect";

interface Raw { readonly width: number; readonly height: number; readonly bytes: number }
interface Meta { readonly width: number; readonly height: number; readonly aspect: number; readonly kb: number }

const addAspect = (r: Raw): Raw & { aspect: number } => ({ ...r, aspect: r.width / r.height });
const addKb = <R extends { bytes: number }>(r: R): R & { kb: number } => ({ ...r, kb: Math.round(r.bytes / 1024) });
const projectMeta = (r: Raw & { aspect: number; kb: number }): Meta => ({
  width: r.width,
  height: r.height,
  aspect: r.aspect,
  kb: r.kb,
});

export const toMeta = (raw: Raw): Meta =>
  pipe(raw, addAspect, addKb, projectMeta);
```

Three stages, each enriching then projecting — the pipeline reads top-to-bottom in the order those facts are computed.

