import { pipe } from "effect";

export type Percentage = number & Brand.Brand<"Percentage">;

export const Percentage = Brand.refined<Percentage>(
  (n) => Number.isFinite(n) && n >= 0 && n <= 1,
  (n) => Brand.error(`Percentage must be in [0, 1]: ${n}`),
);

export const blend = (a: Percentage, b: Percentage): Percentage =>
  (Math.min(1, a + b)) as Percentage;

export const parsePct = (raw: number): Effect.Effect<Percentage, Brand.Brand.BrandErrors> =>
  pipe(
    Percentage.either(raw),
    (r) => r._tag === "Right" ? Effect.succeed(r.right) : Effect.fail(r.left),
  );
