import { Effect, Data } from "effect";

class FooErr extends Data.TaggedError("FooErr")<{ readonly msg: string }> {}
class BarErr extends Data.TaggedError("BarErr")<{ readonly code: number }> {}

const op = (x: number): Effect.Effect<number, FooErr | BarErr> =>
  x < 0
    ? Effect.fail(new FooErr({ msg: "negative" }))
    : x > 100
      ? Effect.fail(new BarErr({ code: x }))
      : Effect.succeed(x);

export const handled: Effect.Effect<number, BarErr> = op(-1).pipe(
  Effect.catchTag("FooErr", () => Effect.succeed(0))
);
```

`Data.TaggedError` gives you structural equality, a stable `_tag`, and auto-generated constructors — same shape as the hand-rolled class, one import instead of boilerplate.

```ts
import { Effect, Data, Duration } from "effect";

class Boom extends Data.TaggedError("Boom")<{ readonly which: string }> {}

const ok = (ms: number): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return "ok";
  });

const bad = (ms: number, tag: string): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Boom({ which: tag }));
  });

// Effect.all with unbounded concurrency short-circuits on first failure
// and interrupts the other fibres.
const program: Effect.Effect<readonly string[], Boom> = Effect.all(
  [ok(80), bad(40, "x"), ok(60)],
  { concurrency: "unbounded" }
);

Effect.runPromise(Effect.either(program)).then(console.log);
```

For first-error short-circuit across many effects prefer `Effect.all(..., { concurrency })`; use `raceAll` when you want the *first success* instead.

`Effect.all(jobs)` defaults to sequential — one at a time, in order. `{ concurrency: "unbounded" }` fans every job out at once. A numeric value like `{ concurrency: 8 }` is a bounded worker pool: at most N fibres in flight, with the remainder queued. `{ concurrency: "inherit" }` uses whatever concurrency was set by an outer `Effect.withConcurrency` scope.

```ts
import { Effect, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly url: string }> {}

declare const fetch: (url: string) => Effect.Effect<string, HttpError>;

const urls: ReadonlyArray<string> = ["/a", "/b", "/c", "/d"];
const jobs = urls.map(fetch);

export const serial: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs);
export const unbounded: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: "unbounded",
});
export const pooled: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: 2,
});
export const inherited: Effect.Effect<ReadonlyArray<string>, HttpError> = Effect.all(jobs, {
  concurrency: "inherit",
});

// Same four, composed inside a generator so downstream code can add steps.
export const pooledThenLog: Effect.Effect<ReadonlyArray<string>, HttpError> =
  Effect.gen(function* () {
    const bodies = yield* pooled;
    return bodies;
  });
```

All four share the same success and error types; only the runtime scheduling changes.

```ts
import { Effect, Layer, Context } from "effect";

interface MetricsBackend { readonly emit: (name: string, value: number) => Effect.Effect<void> }
const MetricsBackend = Context.GenericTag<MetricsBackend>("metrics/Backend");

interface MetricsRecorder { readonly incr: (name: string) => Effect.Effect<void> }
const MetricsRecorder = Context.GenericTag<MetricsRecorder>("metrics/Recorder");

const BackendLive = Layer.succeed(MetricsBackend, {
  emit: (name, value) => Effect.sync(() => console.log(`${name}=${value}`))
});

// Recorder depends on Backend (delegates emission)
const RecorderLive = Layer.effect(
  MetricsRecorder,
  Effect.gen(function* () {
    const backend = yield* MetricsBackend;
    return MetricsRecorder.of({
      incr: (name) => backend.emit(name, 1)
    });
  })
);

const LiveLayer = Layer.merge(BackendLive, RecorderLive);

const program = Effect.gen(function* () {
  const rec = yield* MetricsRecorder;
  yield* rec.incr("requests");
  yield* rec.incr("errors");
});

export const runnable = Effect.provide(program, LiveLayer);
```

The recorder's `Layer.effect` receives the `MetricsRecorder` tag so the returned layer produces exactly that service, while yielding `MetricsBackend` makes the dependency explicit in the R channel before `Layer.merge` eliminates it.

