import { Effect, Option } from "effect";
import { pipe } from "effect";

export interface Query { readonly q: string; readonly page: number; readonly size: number }

class QErr { readonly _tag = "QErr" as const; constructor(readonly field: string, readonly msg: string) {} }

const vQNonEmpty = (s: string): Effect.Effect<string, QErr> =>
  s.trim().length > 0 ? Effect.succeed(s) : Effect.fail(new QErr("q", "required"));
const vQMax = (s: string): Effect.Effect<string, QErr> =>
  s.length <= 256 ? Effect.succeed(s) : Effect.fail(new QErr("q", "too long"));
const vPagePos = (n: number): Effect.Effect<number, QErr> =>
  Number.isInteger(n) && n >= 1 ? Effect.succeed(n) : Effect.fail(new QErr("page", "must be >= 1"));
const vPageMax = (n: number): Effect.Effect<number, QErr> =>
  n <= 10_000 ? Effect.succeed(n) : Effect.fail(new QErr("page", "paging too deep"));
const vSizePos = (n: number): Effect.Effect<number, QErr> =>
  Number.isInteger(n) && n >= 1 ? Effect.succeed(n) : Effect.fail(new QErr("size", "must be >= 1"));
const vSizeMax = (n: number): Effect.Effect<number, QErr> =>
  n <= 100 ? Effect.succeed(n) : Effect.fail(new QErr("size", "too large"));

export const validateQuery = (q: Query): Effect.Effect<Query, ReadonlyArray<QErr>> =>
  pipe(
    Effect.all(
      [vQNonEmpty(q.q), vQMax(q.q), vPagePos(q.page), vPageMax(q.page), vSizePos(q.size), vSizeMax(q.size)],
      { mode: "validate" },
    ),
    Effect.mapError((arr) => arr.flatMap((o) => Option.isSome(o) ? [o.value] : [])),
    Effect.map(() => q),
  );
