```ts
import { Effect } from "effect";
import { pipe } from "effect";

class ItemError { readonly _tag = "ItemError" as const; constructor(readonly index: number, readonly msg: string) {} }

const validateItem = (idx: number, s: string): Effect.Effect<string, ItemError> =>
  s.trim().length > 0 ? Effect.succeed(s.trim()) : Effect.fail(new ItemError(idx, "empty"));

export const validateAll = (raw: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<string>, ReadonlyArray<ItemError>> =>
  pipe(
    Effect.partition(raw, (s, i) => validateItem(i, s)),
    Effect.flatMap(([errors, values]) =>
      errors.length > 0 ? Effect.fail(errors) : Effect.succeed(values),
    ),
  );
```

`Effect.partition` splits the stream into successes and failures without short-circuiting — every item is evaluated, and the left slot collects every error observed.

```ts
import { Effect, Data } from "effect";

class EvalError extends Data.TaggedError("EvalError")<{ readonly model: string }> {}

interface Score { readonly model: string; readonly value: number }

declare const evalFast: (x: string) => Effect.Effect<Score, EvalError>;
declare const evalAccurate: (x: string) => Effect.Effect<Score, EvalError>;
declare const evalCheap: (x: string) => Effect.Effect<Score, EvalError>;

export const firstAnswer = (x: string): Effect.Effect<Score, EvalError> =>
  Effect.gen(function* () {
    return yield* Effect.raceAll([evalFast(x), evalAccurate(x), evalCheap(x)]);
  });
```

`Effect.raceAll` completes with the first successful `Score`; the remaining two evaluators are interrupted by the runtime, freeing their GPU time. A failure in one racer does not end the race — `raceAll` keeps waiting for a success and only surfaces a failure when every racer has failed.

```ts
import { Effect, Fiber, Console } from "effect";

const poller = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("[poll] tick");
    yield* Effect.sleep("30 millis");
  })
);

const condition: Effect.Effect<"stop"> = Effect.gen(function* () {
  yield* Effect.sleep("120 millis");
  return "stop" as const;
});

const program = Effect.gen(function* () {
  const fp = yield* Effect.fork(poller);
  const fc = yield* Effect.fork(condition);
  yield* Fiber.join(fc);
  yield* Fiber.interrupt(fp);
  yield* Console.log("[poller] halted by condition");
});

Effect.runPromise(program);
```

The condition fibre signals completion; the parent responds by interrupting the poller cleanly.

