class QueryFailed { readonly _tag = "QueryFailed" as const; constructor(readonly sql: string) {} }
class NoResults { readonly _tag = "NoResults" as const; constructor(readonly sql: string) {} }

interface Row { readonly id: number; readonly col: string }

