The v3 way is: declare each failure as a tagged class, let it flow through the `E` channel, and recover specifically with `catchTag`. Legacy code typed errors as `unknown` and relied on runtime checks, losing compile-time guarantees.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type BadLength = { _tag: "BadLength"; n: number };
type BadPrefix = { _tag: "BadPrefix"; lead: string };

const digitsOnly = (s: string): string => s.replace(/\D/g, "");

const lengthOk = (s: string): E.Either<BadLength, string> =>
  s.length === 10 || s.length === 11 ? E.right(s) : E.left({ _tag: "BadLength", n: s.length });

const stripCountry = (s: string): E.Either<BadPrefix, string> => {
  if (s.length === 10) return E.right(s);
  return s[0] === "1" ? E.right(s.slice(1)) : E.left({ _tag: "BadPrefix", lead: s[0] });
};

const fmt = (s: string): string => `(${s.slice(0, 3)}) ${s.slice(3, 6)}-${s.slice(6)}`;

export const normalise = (raw: string): string =>
  pipe(
    E.right(digitsOnly(raw)),
    E.chainW(lengthOk),
    E.chainW(stripCountry),
    E.map(fmt),
    E.mapLeft((e) => `invalid:${e._tag}`),
    E.fold((err) => err, (ph) => ph),
  );
```

`digitsOnly` is a pure transform so it's applied inside `E.right(...)` before the validation chain starts.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export interface CryptoError {
  readonly _tag: 'CryptoError';
  readonly message: string;
}

export const sha256 = (data: ArrayBuffer): TE.TaskEither<CryptoError, ArrayBuffer> =>
  TE.tryCatch(
    () => crypto.subtle.digest('SHA-256', data),
    (u): CryptoError => ({
      _tag: 'CryptoError',
      message: u instanceof Error ? u.message : 'digest failed',
    })
  );

export const digestLen = (data: ArrayBuffer): TE.TaskEither<CryptoError, number> =>
  pipe(sha256(data), TE.map((buf) => buf.byteLength));
```

The thunk here is a native promise — no `async` wrapper needed. The narrower still insists on `instanceof Error` before touching `.message`, so the type system never sees unchecked `unknown` casts.

```ts
import { Effect, Either } from "effect";

type FieldError = { readonly _tag: "FieldError"; readonly field: string; readonly message: string };
const fe = (field: string, message: string): FieldError => ({ _tag: "FieldError", field, message });

interface UserPatch { email: string; displayName: string; locale: string }

const email = (s: string): Effect.Effect<string, FieldError> =>
  /^[^@\s]+@[^@\s]+$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("email", "bad format"));
const display = (s: string): Effect.Effect<string, FieldError> =>
  s.length >= 1 && s.length <= 64 ? Effect.succeed(s) : Effect.fail(fe("displayName", "1..64"));
const locale = (s: string): Effect.Effect<string, FieldError> =>
  /^[a-z]{2}(-[A-Z]{2})?$/.test(s) ? Effect.succeed(s) : Effect.fail(fe("locale", "xx or xx-YY"));

export const validateUserPatch = (
  u: UserPatch
): Effect.Effect<UserPatch, ReadonlyArray<FieldError>> =>
  Effect.gen(function* () {
    const [e, d, l] = yield* Effect.all([
      Effect.either(email(u.email)),
      Effect.either(display(u.displayName)),
      Effect.either(locale(u.locale)),
    ]);
    const errs: FieldError[] = [];
    if (Either.isLeft(e)) errs.push(e.left);
    if (Either.isLeft(d)) errs.push(d.left);
    if (Either.isLeft(l)) errs.push(l.left);
    if (errs.length > 0) return yield* Effect.fail(errs);
    return u;
  });
```

`Effect.either` converts each field failure into an `Either`; `Effect.all` runs them without short-circuiting, and any `Left` lands in the `ReadonlyArray<FieldError>` error channel — if none fail, the original (validated) input is returned.

