import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type DdbError =
  | { readonly _tag: 'ConditionalCheckFailed'; readonly key: string }
  | { readonly _tag: 'DdbFailure'; readonly cause: unknown };

interface RawAwsError { readonly name?: string }

const isConditionalCheckFailed = (u: unknown): u is RawAwsError =>
  typeof u === 'object' &&
  u !== null &&
  (u as RawAwsError).name === 'ConditionalCheckFailedException';

declare const ddbGet: (key: string) => Promise<Record<string, unknown>>;

export const getItem = (key: string): TE.TaskEither<DdbError, Record<string, unknown>> =>
  TE.tryCatch(
    () => ddbGet(key),
    (u): DdbError =>
      isConditionalCheckFailed(u)
        ? { _tag: 'ConditionalCheckFailed', key }
        : { _tag: 'DdbFailure', cause: u }
  );

export const readAttr = (key: string, attr: string): TE.TaskEither<DdbError, unknown> =>
  pipe(getItem(key), TE.map((row) => row[attr]));
```

