Narrow errors into a discriminated union (`NetworkError | HttpError`). Compose with `pipe`.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type FetchFailure =
  | { readonly _tag: 'NetworkError'; readonly cause: unknown }
  | { readonly _tag: 'HttpError'; readonly status: number };

export const fetchRaw = (url: string): TE.TaskEither<FetchFailure, Response> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(url);
      if (!res.ok) {
        const err: FetchFailure = { _tag: 'HttpError', status: res.status };
        throw err;
      }
      return res;
    },
    (u): FetchFailure =>
      typeof u === 'object' && u !== null && (u as { _tag?: string })._tag === 'HttpError'
        ? (u as FetchFailure)
        : { _tag: 'NetworkError', cause: u }
  );

export const status = (url: string): TE.TaskEither<FetchFailure, number> =>
  pipe(fetchRaw(url), TE.map((r) => r.status));
```

Throwing a pre-shaped domain error inside the thunk lets the narrower re-recognise it by tag, while any other throwable collapses into `NetworkError`.

