```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

type Role = "admin" | "user" | "guest";

type BadRole = { _tag: "BadRole"; got: string };
type NoPerm = { _tag: "NoPerm"; role: Role; action: string };

const PERMS: Record<Role, ReadonlyArray<string>> = {
  admin: ["read", "write", "delete"],
  user: ["read", "write"],
  guest: ["read"],
};

const parseRole = (s: string): E.Either<BadRole, Role> =>
  s === "admin" || s === "user" || s === "guest"
    ? E.right(s)
    : E.left({ _tag: "BadRole", got: s });

const canDo = (action: string) => (role: Role): E.Either<NoPerm, Role> =>
  PERMS[role].includes(action) ? E.right(role) : E.left({ _tag: "NoPerm", role, action });

export const authorized = (roleStr: string, action: string): boolean =>
  pipe(
    parseRole(roleStr),
    E.chainW(canDo(action)),
    E.mapLeft((_e) => false as const),
    E.match((v) => v, (_role) => true),
  );
```

`canDo` widens the left from `BadRole` to `BadRole | NoPerm`, and the `_e` discard in `E.mapLeft` collapses any failure to `false`.

