import { Effect, Data, Exit } from "effect";

class BeginError extends Data.TaggedError("BeginError")<{}> {}
class CommitError extends Data.TaggedError("CommitError")<{}> {}
class RollbackError extends Data.TaggedError("RollbackError")<{}> {}

interface Tx { readonly id: string }

declare const beginTx: () => Effect.Effect<Tx, BeginError>;
declare const commitTx: (t: Tx) => Effect.Effect<void, CommitError>;
declare const rollbackTx: (t: Tx) => Effect.Effect<void, RollbackError>;

export const withTransaction =
  <A, E>(body: (tx: Tx) => Effect.Effect<A, E>): Effect.Effect<A, E | BeginError | CommitError> =>
    Effect.gen(function* () {
      const tx = yield* beginTx();
      const result = yield* Effect.exit(body(tx));
      if (Exit.isSuccess(result)) {
        yield* commitTx(tx);
        return result.value;
      }
      yield* Effect.orDie(rollbackTx(tx));
      return yield* Effect.failCause(result.cause);
    });
```

The `Exit` inspection lets us branch on success vs failure while preserving the original error in the E channel.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;
const bad = (m: Err): V<never> => E.left([m] as RNEA.ReadonlyNonEmptyArray<Err>);

declare const vA: (s: string) => V<string>;
declare const vB: (s: string) => V<string>;
declare const vC: (s: string) => V<string>;

// Manual accumulation: collect every Left's errors into one NonEmptyArray.
const combine = <A>(xs: ReadonlyArray<V<A>>): V<ReadonlyArray<A>> => {
  const errs: Array<Err> = [];
  const oks: Array<A> = [];
  for (const x of xs) {
    if (E.isLeft(x)) errs.push(...x.left);
    else oks.push(x.right);
  }
  if (errs.length > 0) return E.left(errs as unknown as RNEA.ReadonlyNonEmptyArray<Err>);
  return E.right(oks);
};

// Old (fail-fast): pipe(vA(s), E.chain(vB), E.chain(vC)) — stops at first Left.
// New (accumulating): every validator runs; their Lefts concatenate.
export const validateAll = (s: string): V<string> =>
  pipe(combine<string>([vA(s), vB(s), vC(s)]), E.map(() => s));

export const example: V<string> = validateAll("hello");

// Seed a trivial no-op example so the file exercises E.left and E.chain.
const _unused: V<never> = bad("unused");
const _seedChain: V<string> = pipe(E.right<RNEA.ReadonlyNonEmptyArray<Err>, string>("seed"), E.chain((s) => E.right(s)));
void _unused; void _seedChain;
```

Because `E.chain` is monadic it short-circuits on the first `Left`. The applicative-validation shape — here unfolded by hand — keeps running every validator so every `Left` survives.

