import * as E from "fp-ts/Either";

interface User { id: number; email: string | null }

type NotInt = { _tag: "NotInt"; raw: string };
type NotFound = { _tag: "NotFound"; id: number };
type NoEmail = { _tag: "NoEmail"; id: number };

const toInt = (s: string): E.Either<NotInt, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isFinite(n) ? E.right(n) : E.left({ _tag: "NotInt", raw: s });
};

const fetchUser = (db: ReadonlyMap<number, User>) => (id: number): E.Either<NotFound, User> => {
  const u = db.get(id);
  return u ? E.right(u) : E.left({ _tag: "NotFound", id });
};

const requireEmail = (u: User): E.Either<NoEmail, string> =>
  u.email !== null ? E.right(u.email) : E.left({ _tag: "NoEmail", id: u.id });

export const emailOf = (db: ReadonlyMap<number, User>, raw: string): string =>
  pipe(
    toInt(raw),
    E.chainW(fetchUser(db)),
    E.chainW(requireEmail),
    E.mapLeft((e) => `err:${e._tag}`),
    E.match((err) => err, (email) => email.toLowerCase()),
  );
```

The widened left `NotInt | NotFound | NoEmail` is exactly the set of reasons the caller might care about — and `E.mapLeft` makes that surface navigable.

