        return { id, displayName: rich ? `User ${id} (rich)` : `User ${id}` };
      })
    });
  })
);

const LiveLayer = Layer.merge(FlagsServiceLive, ProfileServiceLive);

const program: Effect.Effect<Profile, never, ProfileService> = Effect.gen(function* () {
  const svc = yield* ProfileService;
  return yield* svc.load("42");
});

export const runnable = Effect.provide(program, LiveLayer);
```

The tag-keyed layers let the compiler check that every yield inside the program is eventually satisfied by the bundled `LiveLayer`.

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';
import { promises as fs } from 'node:fs';

export type FileError =
  | { readonly _tag: 'NotFound'; readonly path: string }
  | { readonly _tag: 'ReadFailed'; readonly path: string; readonly cause: unknown };

const isEnoent = (u: unknown): boolean =>
  typeof u === 'object' && u !== null && (u as { code?: string }).code === 'ENOENT';

export const readFileSafe = (path: string): TE.TaskEither<FileError, string> =>
  TE.tryCatch(
    () => fs.readFile(path, 'utf8'),
    (u): FileError =>
      isEnoent(u) ? { _tag: 'NotFound', path } : { _tag: 'ReadFailed', path, cause: u }
  );

export const charCount = (path: string): TE.TaskEither<FileError, number> =>
  pipe(readFileSafe(path), TE.map((s) => s.length));
```

The narrower inspects the runtime error code before producing the domain error — discrimination happens at the boundary, not inside callers.

