import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Item { sku: string; qty: number; price: number }
interface Line { sku: string; total: number }

type BadQty = { _tag: "BadQty"; qty: number };
type BadPrice = { _tag: "BadPrice"; price: number };
type BadSku = { _tag: "BadSku" };

const qtyPositive = (i: Item): E.Either<BadQty, Item> =>
  i.qty > 0 ? E.right(i) : E.left({ _tag: "BadQty", qty: i.qty });

const pricePositive = (i: Item): E.Either<BadPrice, Item> =>
  i.price > 0 ? E.right(i) : E.left({ _tag: "BadPrice", price: i.price });

const skuPresent = (i: Item): E.Either<BadSku, Item> =>
  i.sku.trim().length > 0 ? E.right(i) : E.left({ _tag: "BadSku" });

export const toLine = (item: Item): E.Either<string, Line> =>
  pipe(
    qtyPositive(item),
    E.chainW(pricePositive),
    E.chainW(skuPresent),
    E.map((i) => ({ sku: i.sku, total: i.qty * i.price })),
    E.mapLeft((e) => `cart:${e._tag}`),
    E.match(
      (msg) => E.left<string, Line>(msg),
      (line) => E.right<string, Line>(line),
    ),
  );
```

Each widening step adds a `_tag`; `E.match` is used here to rewrap into a simpler `Either<string, Line>` for downstream code.

```ts
import { Effect, Option } from "effect";
import { pipe } from "effect";

class Err { readonly _tag = "Err" as const; constructor(readonly field: string, readonly msg: string) {} }

const nonEmpty = (field: string, s: string): Effect.Effect<string, Err> =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(new Err(field, "empty"));

export interface Profile { readonly name: string; readonly bio: string }

export const validate = (name: string, bio: string): Effect.Effect<Profile, ReadonlyArray<Err>> =>
  pipe(
    Effect.all(
      { name: nonEmpty("name", name), bio: nonEmpty("bio", bio) },
      { mode: "validate" },
    ),
    Effect.mapError((rec) => [rec.name, rec.bio].flatMap((o) => Option.isSome(o) ? [o.value] : [])),
  );
```

`Effect.all(record, { mode: "validate" })` is the Effect-native analogue: all validators run; on failure the error channel is a record whose values are `Option<Err>`, and `Option.isSome` filters the `None` slots.

