```ts
import { Effect, Fiber, Duration, Data } from "effect";

class QueueError extends Data.TaggedError("QueueError")<{ readonly queue: string }> {}

interface WorkItem { readonly id: string }

declare const poll: () => Effect.Effect<ReadonlyArray<WorkItem>, QueueError>;
declare const process: (w: WorkItem) => Effect.Effect<void>;

const workerLoop: Effect.Effect<never, QueueError> = Effect.gen(function* () {
  while (true) {
    const batch = yield* poll();
    for (const w of batch) {
      yield* process(w);
    }
    yield* Effect.sleep(Duration.millis(250));
  }
});

export const startWorker: Effect.Effect<Fiber.Fiber<never, QueueError>> =
  Effect.fork(workerLoop);

export const stopWorker = (f: Fiber.Fiber<never, QueueError>) => Fiber.interrupt(f);
```

Each `Effect.sleep` is an interruption point; a `Fiber.interrupt` call from another fiber will stop the loop cleanly between batches without orphaning an in-flight `process` call.

